(10, 1, 'Botble\\ACL\\Models\\User', 'room', '{\"name\":\"Ferns Grand Mountain Suite\",\"model\":\"Botble\\\\Hotel\\\\Models\\\\Room\",\"slug\":\"ferns-grand-mountain-suite\",\"slug_id\":\"19\",\"is_slug_editable\":\"1\",\"description\":\"C\\u00e1c c\\u0103n Ferns Grand Mountain Suite n\\u1eb1m tr\\u00ean tri\\u1ec1n n\\u00fai, xen l\\u1eabn trong nh\\u1eefng t\\u00e1n c\\u00e2y. \\u0110\\u1ed3 n\\u1ed9i th\\u1ea5t \\u0111\\u01b0\\u1ee3c ch\\u0103m ch\\u00fat, l\\u1ef1a ch\\u1ecdn k\\u1ef9 l\\u01b0\\u1ee1ng, ph\\u1ea3n \\u00e1nh gu th\\u1ea9m m\\u1ef9 tinh t\\u1ebf v\\u00e0 sang tr\\u1ecdng. Thi\\u1ebft k\\u1ebf c\\u1ee7a Ferns \\u0111\\u00f3n nhi\\u1ec1u nh\\u1ea5t c\\u00f3 th\\u1ec3 \\u00e1nh s\\u00e1ng thi\\u00ean nhi\\u00ean qua h\\u1ec7 th\\u1ed1ng c\\u1eeda k\\u00ednh m\\u1edf r\\u1ed9ng v\\u00e0 k\\u00e9o d\\u00e0i t\\u1eeb s\\u00e0n l\\u00ean \\u0111\\u1ebfn tr\\u1ea7n nh\\u00e0. Ban c\\u00f4ng r\\u1ed9ng, tho\\u00e1ng v\\u1edbi gh\\u1ebf sofa \\u0111\\u1ec3 tho\\u1ea3i m\\u00e1i th\\u01b0 gi\\u00e3n,ng\\u1eafm nh\\u00ecn c\\u1ea3nh quan xanh m\\u01b0\\u1edbt c\\u1ee7a n\\u00fai \\u0111\\u1ed3i\",\"is_featured\":\"1\",\"content\":null,\"order\":\"0\",\"price\":\"187\",\"number_of_rooms\":\"1\",\"number_of_beds\":\"4\",\"max_adults\":\"4\",\"max_children\":\"3\",\"size\":\"186\",\"images\":[null,\"rooms\\/168179031903-ferms-grand-mountain-suite-3.jpg\",\"rooms\\/168179031903-ferms-grand-mountain-suite-2.jpg\",\"rooms\\/168170040701-lantana-mountain-bungalow-3-1.jpg\",\"rooms\\/168170037901-lantana-mountain-bungalow-4-1.jpg\"],\"amenities\":[\"1\",\"2\",\"9\",\"10\",\"11\",\"12\",\"14\"],\"room_availability_value\":null,\"room_availability_value_type\":\"fixed\",\"room_availability_number_of_rooms\":\"1\",\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"status\":\"published\",\"room_category_id\":\"1\",\"tax_id\":\"1\",\"submitter\":\"apply\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleW