(57, 1, 'Botble\\ACL\\Models\\User', 'place', '{\"name\":\"B\\u00e3i bi\\u1ec3n \\u0111\\u1eb9p\",\"model\":\"Botble\\\\Hotel\\\\Models\\\\Place\",\"slug\":\"bai-bien-dep\",\"slug_id\":\"33\",\"is_slug_editable\":\"1\",\"distance\":\"1.500 m | 21 ph\\u00fat \\u0111i b\\u1ed9\",\"description\":null,\"content\":\"<h2><strong>Kh\\u00e1m ph\\u00e1 c\\u00e1c \\u0111i\\u1ec3m tham quan g\\u1ea7n \\u0111\\u00f3<\\/strong><\\/h2><p>H\\u00e3y t\\u1eadn h\\u01b0\\u1edfng <strong>v\\u1ebb \\u0111\\u1eb9p v\\u00e0 h\\u01b0\\u01a1ng v\\u1ecb c\\u1ee7a khu v\\u1ef1c \\u0111\\u1ecba ph\\u01b0\\u01a1ng<\\/strong>, n\\u01a1i nh\\u1eefng <strong>c\\u1ea3nh quan tuy\\u1ec7t \\u0111\\u1eb9p<\\/strong> v\\u00e0 <strong>\\u1ea9m th\\u1ef1c h\\u1ea5p d\\u1eabn<\\/strong> \\u0111ang ch\\u1edd \\u0111\\u00f3n b\\u1ea1n. Ch\\u00fang t\\u00f4i xin gi\\u1edbi thi\\u1ec7u t\\u1ed5ng quan v\\u1ec1 nh\\u1eefng <strong>\\u0111\\u1ecba \\u0111i\\u1ec3m th\\u00fa v\\u1ecb<\\/strong> m\\u00e0 b\\u1ea1n c\\u00f3 th\\u1ec3 tr\\u1ea3i nghi\\u1ec7m trong su\\u1ed1t th\\u1eddi gian l\\u01b0u tr\\u00fa.<\\/p><hr><h2><strong>Th\\u01b0 gi\\u00e3n t\\u1ea1i b\\u00e3i bi\\u1ec3n<\\/strong><\\/h2><p>H\\u00e3y th\\u1ea3 l\\u1ecfng v\\u00e0 t\\u1eadn h\\u01b0\\u1edfng <strong>s\\u1ef1 y\\u00ean b\\u00ecnh c\\u1ee7a b\\u00e3i bi\\u1ec3n trong l\\u00e0nh<\\/strong> ch\\u1ec9 c\\u00e1ch kh\\u00e1ch s\\u1ea1n c\\u1ee7a ch\\u00fang t\\u00f4i v\\u00e0i b\\u01b0\\u1edbc ch\\u00e2n. <strong>B\\u00e3i c\\u00e1t m\\u1ec1m m\\u1ea1i, l\\u00e0n s\\u00f3ng d\\u1ecbu nh\\u1eb9 v\\u00e0 \\u0111\\u01b0\\u1eddng ch\\u00e2n tr\\u1eddi tuy\\u1ec7t \\u0111\\u1eb9p<\\/strong> t\\u1ea1o n\\u00ean m\\u1ed9t kh\\u00f4ng gian l\\u00fd t\\u01b0\\u1edfng \\u0111\\u1ec3 b\\u1ea1n <strong>t\\u00e1i t\\u1ea1o n\\u0103ng l\\u01b0\\u1ee3ng v\\u00e0 th\\u01b0 gi\\u00e3n<\\/strong>.<\\/p><p>D\\u00f9 b\\u1ea1n <strong>t\\u1eafm n\\u1eafng tr\\u00ean b\\u00e3i bi\\u1ec3n<\\/strong> hay <strong>t\\u1ea3n b\\u1ed9 nh\\u1eb9 nh\\u00e0ng d\\u1ecdc b\\u1edd c\\u00e1t<\\/strong>, n\\u01a1i \\u0111\\u00e2y lu\\u00f4n mang \\u0111\\u1ebfn <strong>kho\\u1ea3nh kh\\u1eafc b\\u00ecnh y\\u00ean<\\/strong> gi\\u00fap b\\u1ea1n t\\u1ea1m r\\u1eddi xa s\\u1ef1 b\\u1eadn r\\u1ed9n c\\u1ee7a cu\\u1ed9c s\\u1ed1ng h\\u1eb1ng ng\\u00e0y.<\\/p><hr><h2><strong>Th\\u01b0\\u1edfng th\\u1ee9c \\u1ea9m th\\u1ef1c t\\u1ea1i nh\\u00e0 h\\u00e0ng h\\u00e0ng \\u0111\\u1ea7u<\\/strong><\\/h2><p>H\\u00e3y b\\u1eaft \\u0111\\u1ea7u <strong>h\\u00e0nh tr\\u00ecnh \\u1ea9m th\\u1ef1c<\\/strong> t\\u1ea1i m\\u1ed9t trong nh\\u1eefng <strong>nh\\u00e0 h\\u00e0ng n\\u1ed5i b\\u1eadt c\\u1ee7a khu v\\u1ef1c<\\/strong>, m\\u1ed9t vi\\u00ean ng\\u1ecdc qu\\u00fd trong khu ph\\u1ed1 c\\u1ee7a ch\\u00fang t\\u00f4i.<\\/p><p>Th\\u01b0\\u1edfng th\\u1ee9c <strong>nhi\\u1ec1u m\\u00f3n \\u0103n h\\u1ea5p d\\u1eabn<\\/strong> \\u0111\\u01b0\\u1ee3c ch\\u1ebf bi\\u1ebfn c\\u00f4ng phu b\\u1edfi <strong>nh\\u1eefng \\u0111\\u1ea7u b\\u1ebfp t\\u00e0i n\\u0103ng<\\/strong>. T\\u1eeb <strong>m\\u00f3n khai v\\u1ecb tinh t\\u1ebf<\\/strong>, <strong>m\\u00f3n ch\\u00ednh \\u0111\\u1eadm \\u0111\\u00e0<\\/strong> \\u0111\\u1ebfn <strong>m\\u00f3n tr\\u00e1ng mi\\u1ec7ng ng\\u1ecdt ng\\u00e0o<\\/strong>, m\\u1ed7i m\\u00f3n \\u0103n \\u0111\\u1ec1u l\\u00e0 <strong>s\\u1ef1 k\\u1ebft h\\u1ee3p ho\\u00e0n h\\u1ea3o gi\\u1eefa h\\u01b0\\u01a1ng v\\u1ecb v\\u00e0 s\\u1ef1 s\\u00e1ng t\\u1ea1o<\\/strong>.<\\/p><p>Kh\\u00f4ng gian <strong>\\u1ea5m c\\u00fang<\\/strong> c\\u00f9ng <strong>d\\u1ecbch v\\u1ee5 chu \\u0111\\u00e1o<\\/strong> s\\u1ebd l\\u00e0m cho tr\\u1ea3i nghi\\u1ec7m \\u1ea9m th\\u1ef1c c\\u1ee7a b\\u1ea1n tr\\u1edf n\\u00ean tr\\u1ecdn v\\u1eb9n h\\u01a1n.<\\/p><hr><p>Cho d\\u00f9 b\\u1ea1n l\\u00e0 <strong>ng\\u01b0\\u1eddi y\\u00eau \\u1ea9m th\\u1ef1c<\\/strong> hay <strong>ng\\u01b0\\u1eddi y\\u00eau thi\\u00ean nhi\\u00ean<\\/strong>, v\\u1ecb tr\\u00ed c\\u1ee7a kh\\u00e1ch s\\u1ea1n ch\\u00fang t\\u00f4i mang \\u0111\\u1ebfn <strong>tr\\u1ea