(82, 1, 'Botble\\ACL\\Models\\User', '', '{\"name\":\"Bauhinia Mountain Suite\",\"model\":\"Botble\\\\Hotel\\\\Models\\\\Room\",\"slug\":\"bauhinia-mountain-suite\",\"slug_id\":\"21\",\"is_slug_editable\":\"1\",\"description\":\"Bauhinia offers a spacious atmosphere with premium and well-equipped interiors, featuring either a large double bed or two single beds, a relaxing sofa, and plenty of natural daylight. The 36m\\u00b2 balcony is ideal for relaxing in dry weather,furnished with a comfortable sofa and a charming small dining table for two. Not only impressive for its elegant interior, the Bauhinia Mountain Suite also place\",\"content\":null,\"form\":\"Botble\\\\Hotel\\\\Forms\\\\RoomForm\",\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"submitter\":\"save\",\"language\":\"en_US\",\"ref_lang\":\"en_US\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 5, 'Bauhinia Mountain Suite', 'primary', '2026-03-12 03:14:48', '2026-03-12 03:14:48'),
(83, 1, 'Botble\\ACL\\Models\\User', '', '{\"name\":\"Lantana Mountain Bungalow 2PN\",\"model\":\"Botble\\\\Hotel\\\\Models\\\\Room\",\"slug\":\"lantana-mountain-bungalow-2pn\",\"slug_id\":\"20\",\"is_slug_editable\":\"1\",\"description\":\"The Lantana Mountain Bungalow with two bedrooms is thoughtfully designed to blend harmoniously with nature, featuring a charming balcony overlooking the peaceful valley ahead. The d\\u00e9cor and furnishings are carefully selected, complementing the overall design of the room. Like other villas at Avana, the bathroom of the Lantana Mountain Bungalow includes a private bathtub with large, transparent gla\",\"content\":null,\"form\":\"Botble\\\\Hotel\\\\Forms\\\\RoomForm\",\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"submitter\":\"save\",\"language\":\"en_US\",\"ref_lang\":\"en_US\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 4, 'Lantana Mountain Bungalow 2PN', 'primary', '2026-03-12 03:15:15', '2026-03-12 03:15:15'),
(84, 1, 'Botble\\ACL\\Models\\User', '', '{\"name\":\"Ferns Grand Mountain Suite\",\"model\":\"Botble\\\\Hotel\\\\Models\\\\Room\",\"slug\":\"ferns-grand-mountain-suite\",\"slug_id\":\"19\",\"is_slug_editable\":\"1\",\"description\":\"The Ferns Grand Mountain Suites are nestled along the mountainside, hidden among lush tree canopies.The furnishings are carefully curated and meticulously selected, reflecting a refined and elegant sense of style. The design of the Ferns maximizes natural light through an expansive glass window system that stretches from floor to ceiling. The spacious and airy balcony, furnished with a comfortable\",\"content\":null,\"form\":\"Botble\\\\Hotel\\\\Forms\\\\RoomForm\",\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"submitter\":\"save\",\"language\":\"en_US\",\"ref_lang\":\"en_US\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 3, 'Ferns Grand Mountain Suite', 'primary', '2026-03-12 03:15:41', '2026-03-12 03:15:41');
