(85, 1, 'Botble\\ACL\\Models\\User', 'room', '{\"name\":\"Senna Hilltop Pool Villa 1PN\",\"model\":\"Botble\\\\Hotel\\\\Models\\\\Room\",\"slug\":\"senna-hilltop-pool-villa-1pn\",\"slug_id\":\"18\",\"is_slug_editable\":\"1\",\"description\":\"The Senna Hilltop Pool Villa (one bedroom) is designed especially for couples seeking privacy and romance. The villa features a spacious bedroom connected to an airy living area, overlooking the terraced rice fields and the valley below. The luxurious bathroom includes both a bathtub and a separate walk-in shower, with large glass windows opening to the surrounding natural scenery.\",\"is_featured\":\"1\",\"content\":null,\"order\":\"0\",\"price\":\"171\",\"number_of_rooms\":\"1\",\"number_of_beds\":\"2\",\"max_adults\":\"2\",\"max_children\":\"2\",\"size\":\"126\",\"images\":[null,\"rooms\\/168439441304-senna-hilltop-pool-villa-1-br-9.jpg\",\"rooms\\/168144758104-senna-hilltop-pool-villa-1-br-7.jpg\",\"rooms\\/168144758104-senna-hilltop-pool-villa-1-br-2.jpg\",\"rooms\\/168144758004-senna-hilltop-pool-villa-1-br-5.jpg\",\"rooms\\/168439441904-senna-hilltop-pool-villa-1-br-1.jpg\",\"rooms\\/168439441704-senna-hilltop-pool-villa-1-br-3.jpg\"],\"amenities\":[\"1\",\"2\",\"3\",\"4\",\"5\",\"6\",\"7\",\"9\",\"10\",\"13\",\"14\"],\"room_availability_value\":null,\"room_availability_value_type\":\"fixed\",\"room_availability_number_of_rooms\":\"1\",\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"language\":\"vi\",\"status\":\"published\",\"room_category_id\":\"1\",\"tax_id\":\"1\",\"submitter\":\"save\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 2, 'Senna Hilltop Pool Villa 1PN', 'primary', '2026-03-12 03:16:18', '2026-03-12 03:16:18'),
(86, 1, 'Botble\\ACL\\Models\\User', '', '{\"name\":\"Senna Hilltop Pool Villa 2PN\",\"model\":\"Botble\\\\Hotel\\\\Models\\\\Room\",\"slug\":\"senna-hilltop-pool-villa-2pn\",\"slug_id\":\"17\",\"is_slug_editable\":\"1\",\"description\":\"The Senna Hilltop Pool Villa (two bedrooms) is the largest and most captivating villa at Avana Retreat. Both bedrooms feature expansive glass doors that open to the outdoors, overlooking the private pool, terraced rice fields, and the valley beyond. The villa is elegantly designed, with a spacious living room and a large sunbathing terrace. The outdoor area is beautifully arranged with a sofa\",\"content\":null,\"form\":\"Botble\\\\Hotel\\\\Forms\\\\RoomForm\",\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"submitter\":\"save\",\"language\":\"en_US\",\"ref_lang\":\"en_US\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 1, 'Senna Hilltop Pool Villa 2PN', 'primary', '2026-03-12 03:16:40', '2026-03-12 03:16:40'),
