(258, 1, 'Botble\\ACL\\Models\\User', 'testimonial', '{\"name\":\"Nguy\\u1ec5n Minh Anh\",\"company\":\"CEO Of Microsoft\",\"content\":\"<p>T\\u00f4i th\\u1ef1c s\\u1ef1 r\\u1ea5t h\\u00e0i l\\u00f2ng v\\u1edbi k\\u1ef3 ngh\\u1ec9 t\\u1ea1i \\u0111\\u00e2y. Kh\\u00e1ch s\\u1ea1n s\\u1ea1ch s\\u1ebd, ph\\u00f2ng \\u1ed1c \\u0111\\u01b0\\u1ee3c chu\\u1ea9n b\\u1ecb r\\u1ea5t chu \\u0111\\u00e1o v\\u00e0 nh\\u00e2n vi\\u00ean lu\\u00f4n nhi\\u1ec7t t\\u00ecnh h\\u1ed7 tr\\u1ee3. V\\u1ecb tr\\u00ed c\\u0169ng r\\u1ea5t thu\\u1eadn ti\\u1ec7n \\u0111\\u1ec3 di chuy\\u1ec3n v\\u00e0 tham quan c\\u00e1c \\u0111\\u1ecba \\u0111i\\u1ec3m xung quanh.<\\/p>\",\"submitter\":\"save\",\"language\":\"vi\",\"status\":\"published\",\"image\":\"testimonials\\/viet-hoangpng.jpg\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 1, 'Nguyễn Minh Anh', 'primary', '2026-03-12 20:21:03', '2026-03-12 20:21:03'),
(259, 1, 'Botble\\ACL\\Models\\User', 'testimonial', '{\"name\":\"Tr\\u1ea7n Qu\\u1ed1c B\\u1ea3o\",\"company\":\"CEO Of Apple\",\"content\":\"<p>Tr\\u1ea3i nghi\\u1ec7m l\\u01b0u tr\\u00fa c\\u1ee7a t\\u00f4i r\\u1ea5t tuy\\u1ec7t v\\u1eddi. Ph\\u00f2ng r\\u1ed9ng r\\u00e3i, ti\\u1ec7n nghi \\u0111\\u1ea7y \\u0111\\u1ee7 v\\u00e0 kh\\u00f4ng gian r\\u1ea5t y\\u00ean t\\u0129nh. Nh\\u00e2n vi\\u00ean ph\\u1ee5c v\\u1ee5 chuy\\u00ean nghi\\u1ec7p v\\u00e0 th\\u00e2n thi\\u1ec7n khi\\u1ebfn t\\u00f4i c\\u1ea3m th\\u1ea5y r\\u1ea5t tho\\u1ea3i m\\u00e1i trong su\\u1ed1t th\\u1eddi gian \\u1edf \\u0111\\u00e2y.<\\/p>\",\"submitter\":\"save\",\"language\":\"vi\",\"status\":\"published\",\"image\":\"testimonials\\/anh-chup-man-hinh-2020-04-15-luc-165401.png\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 2, 'Trần Quốc Bảo', 'primary', '2026-03-12 20:21:50', '2026-03-12 20:21:50'),
(260, 1, 'Botble\\ACL\\Models\\User', 'testimonial', '{\"name\":\"Ph\\u1ea1m Thu Trang\",\"company\":\"Pio Founder\",\"content\":\"<p>M\\u1ed9t n\\u01a1i ngh\\u1ec9 d\\u01b0\\u1ee1ng r\\u1ea5t \\u0111\\u00e1ng tr\\u1ea3i nghi\\u1ec7m. Kh\\u00f4ng gian tho\\u1ea3i m\\u00e1i, d\\u1ecbch v\\u1ee5 t\\u1ed1t v\\u00e0 nh\\u00e2n vi\\u00ean lu\\u00f4n s\\u1eb5n s\\u00e0ng h\\u1ed7 tr\\u1ee3 khi c\\u1ea7n. T\\u00f4i \\u0111\\u00e3 c\\u00f3 m\\u1ed9t k\\u1ef3 ngh\\u1ec9 th\\u1eadt th\\u01b0 gi\\u00e3n v\\u00e0 d\\u1ec5 ch\\u1ecbu t\\u1ea1i \\u0111\\u00e2y.<\\/p>\",\"submitter\":\"save\",\"language\":\"vi\",\"status\":\"published\",\"image\":\"testimonials\\/hinh-anh-nguoi-phu-nu-viet-nam-trong-ta-ao-dai-192.webp\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 3, 'Phạm Thu Trang', 'primary', '2026-03-12 20:22:36', '2026-03-12 20:22:36'),
