(265, 1, 'Botble\\ACL\\Models\\User', 'testimonial', '{\"name\":\"V\\u0169 Kh\\u00e1nh Linh\",\"company\":\"VP Of Google\",\"content\":\"<p>Kh\\u00e1ch s\\u1ea1n mang l\\u1ea1i c\\u1ea3m gi\\u00e1c r\\u1ea5t tho\\u1ea3i m\\u00e1i v\\u00e0 ti\\u1ec7n nghi. Ph\\u00f2ng \\u0111\\u1eb9p, s\\u1ea1ch s\\u1ebd v\\u00e0 \\u0111\\u01b0\\u1ee3c trang b\\u1ecb \\u0111\\u1ea7y \\u0111\\u1ee7. Ngo\\u00e0i ra, v\\u1ecb tr\\u00ed c\\u0169ng r\\u1ea5t thu\\u1eadn ti\\u1ec7n \\u0111\\u1ec3 \\u0111i tham quan v\\u00e0 kh\\u00e1m ph\\u00e1 th\\u00e0nh ph\\u1ed1.<\\/p>\",\"submitter\":\"save\",\"language\":\"vi\",\"status\":\"published\",\"image\":\"testimonials\\/free-photo-of-co-gai-tr-m-c-ao-dai-truy-n-th-ng-vi.jpg\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 4, 'Vũ Khánh Linh', 'primary', '2026-03-12 20:25:53', '2026-03-12 20:25:53'),
