(269, 1, 'Botble\\ACL\\Models\\User', 'testimonial', '{\"name\":\"Ho\\u00e0ng Ng\\u1ecdc Mai\",\"company\":\"Founder Of SpaceX\",\"content\":\"<p>Kh\\u00f4ng gian kh\\u00e1ch s\\u1ea1n r\\u1ea5t sang tr\\u1ecdng nh\\u01b0ng v\\u1eabn t\\u1ea1o c\\u1ea3m gi\\u00e1c \\u1ea5m c\\u00fang. M\\u1ecdi th\\u1ee9 t\\u1eeb ph\\u00f2ng ngh\\u1ec9 \\u0111\\u1ebfn d\\u1ecbch v\\u1ee5 \\u0111\\u1ec1u \\u0111\\u01b0\\u1ee3c chu\\u1ea9n b\\u1ecb r\\u1ea5t t\\u1ed1t. T\\u00f4i th\\u1ef1c s\\u1ef1 c\\u1ea3m th\\u1ea5y h\\u00e0i l\\u00f2ng v\\u1edbi tr\\u1ea3i nghi\\u1ec7m n\\u00e0y.<\\/p>\",\"submitter\":\"save\",\"language\":\"vi\",\"status\":\"published\",\"image\":\"testimonials\\/3656093-3655919-nguoi-dep-va-xe-may-9796.jpg\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 5, 'Hoàng Ngọc Mai', 'primary', '2026-03-12 20:26:35', '2026-03-12 20:26:35'),
