(272, 1, 'Botble\\ACL\\Models\\User', 'testimonial', '{\"name\":\"\\u0110\\u1ed7 \\u0110\\u1ee9c Anh\",\"company\":\"Fashion Designer\",\"content\":\"<p>Ph\\u00f2ng r\\u1ea5t s\\u1ea1ch s\\u1ebd, gi\\u01b0\\u1eddng ng\\u1ee7 tho\\u1ea3i m\\u00e1i v\\u00e0 d\\u1ecbch v\\u1ee5 d\\u1ecdn ph\\u00f2ng lu\\u00f4n \\u0111\\u01b0\\u1ee3c th\\u1ef1c hi\\u1ec7n \\u0111\\u00fang gi\\u1edd. Nh\\u00e2n vi\\u00ean r\\u1ea5t nhi\\u1ec7t t\\u00ecnh v\\u00e0 lu\\u00f4n s\\u1eb5n s\\u00e0ng h\\u1ed7 tr\\u1ee3 khi c\\u1ea7n thi\\u1ebft.<\\/p>\",\"submitter\":\"save\",\"language\":\"vi\",\"status\":\"published\",\"image\":\"testimonials\\/chc3a2n-dung-nam-doanh-nhc3a2n-chc3a2u-c3a.jpg\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 6, 'Đỗ Đức Anh', 'primary', '2026-03-12 20:27:08', '2026-03-12 20:27:08'),
