(302, 1, 'Botble\\ACL\\Models\\User', 'page', '{\"name\":\"Trang ch\\u1ee7\",\"model\":\"Botble\\\\Page\\\\Models\\\\Page\",\"slug\":\"https:\\/\\/retreat.anduongliving.com\",\"description\":null,\"content\":\"<shortcode>[simple-slider key=\\\"home-slider\\\"][\\/simple-slider]<\\/shortcode><shortcode>[check-availability-form][\\/check-availability-form]<\\/shortcode><shortcode>[about-us title=\\\"Kh\\u00e1ch s\\u1ea1n an to\\u00e0n v\\u00e0 \\u0111\\u01b0\\u1ee3c \\u0111\\u00e1nh gi\\u00e1 cao nh\\u1ea5t t\\u1ea1i London\\\" subtitle=\\\"V\\u1ec1 ch\\u00fang t\\u00f4i\\\" description=\\\"Ch\\u00fang t\\u00f4i t\\u1ef1 h\\u00e0o mang \\u0111\\u1ebfn nh\\u1eefng kh\\u00e1ch s\\u1ea1n an to\\u00e0n v\\u00e0 \\u0111\\u01b0\\u1ee3c \\u0111\\u00e1nh gi\\u00e1 cao . S\\u1ef1 an to\\u00e0n v\\u00e0 tho\\u1ea3i m\\u00e1i c\\u1ee7a b\\u1ea1n lu\\u00f4n l\\u00e0 \\u01b0u ti\\u00ean h\\u00e0ng \\u0111\\u1ea7u c\\u1ee7a ch\\u00fang t\\u00f4i.. H\\u00e3y ch\\u1ecdn Anduong Living \\u0111\\u1ec3 c\\u00f3 m\\u1ed9t chuy\\u1ebfn \\u0111i \\u0111\\u00e1ng nh\\u1edb.\\\" highlights=\\\"\\u0110\\u1eafm m\\u00ecnh trong v\\u1ebb quy\\u1ebfn r\\u0169 v\\u00e0 tr\\u1ea3i nghi\\u1ec7m s\\u1ef1 k\\u1ebft h\\u1ee3p ho\\u00e0n h\\u1ea3o gi\\u1eefa sang tr\\u1ecdng v\\u00e0 ti\\u1ec7n nghi.\\\" style=\\\"style-1\\\" button_label=\\\"Xem th\\u00eam\\\" button_url=\\\"\\/about-us\\\" signature_image=\\\"rooms\\/168439421305-senna-hilltop-pool-villa-2-br-9-copy.jpg\\\" signature_author=\\\"Vincent Smith\\\" top_left_image=\\\"rooms\\/168144758004-senna-hilltop-pool-villa-1-br-5.jpg\\\" bottom_right_image=\\\"rooms\\/168144758104-senna-hilltop-pool-villa-1-br-2.jpg\\\" floating_right_image=\\\"backgrounds\\/an-img-02.png\\\"][\\/about-us]<\\/shortcode><shortcode>[featured-amenities title=\\\"Kh\\u00e1ch s\\u1ea1n\\\" subtitle=\\\"Kh\\u00e1m ph\\u00e1\\\" description=\\\"Kh\\u00f4ng gian ngh\\u1ec9 d\\u01b0\\u1ee1ng sang tr\\u1ecdng v\\u00e0 tho\\u1ea3i m\\u00e1i ngay t\\u1ea1i trung t\\u00e2m th\\u00e0nh ph\\u1ed1. V\\u1edbi thi\\u1ebft k\\u1ebf tinh t\\u1ebf c\\u00f9ng c\\u00e1c ti\\u1ec7n nghi hi\\u1ec7n \\u0111\\u1ea1i, m\\u1ed7i ph\\u00f2ng \\u0111\\u1ec1u \\u0111\\u01b0\\u1ee3c ch\\u0103m ch\\u00fat \\u0111\\u1ec3 mang l\\u1ea1i c\\u1ea3m gi\\u00e1c th\\u01b0 gi\\u00e3n t\\u1ed1i \\u0111a cho du kh\\u00e1ch.\\\" background_color=\\\"#F7F5F1\\\" background_image=\\\"\\/backgrounds\\/an-img-01.png\\\" amenity_ids=\\\"1,2,3,4,5,6\\\"][\\/featured-amenities]<\\/shortcode><shortcode>[featured-rooms title=\\\"Ph\\u00f2ng &amp; Ph\\u00f2ng Suite\\\" subtitle=\\\"Ni\\u1ec1m vui c\\u1ee7a s\\u1ef1 sang tr\\u1ecdng\\\" description=\\\"Kh\\u00e1m ph\\u00e1 c\\u00e1c h\\u1ea1ng ph\\u00f2ng v\\u00e0 suite \\u0111\\u01b0\\u1ee3c thi\\u1ebft k\\u1ebf tinh t\\u1ebf, k\\u1ebft h\\u1ee3p gi\\u1eefa s\\u1ef1 sang tr\\u1ecdng, ti\\u1ec7n nghi hi\\u1ec7n \\u0111\\u1ea1i v\\u00e0 kh\\u00f4ng gian tho\\u1ea3i m\\u00e1i, mang \\u0111\\u1ebfn cho b\\u1ea1n tr\\u1ea3i nghi\\u1ec7m ngh\\u1ec9 d\\u01b0\\u1ee1ng tr\\u1ecdn v\\u1eb9n.\\\" room_ids=\\\"2,3,4\\\"][\\/featured-rooms]<\\/shortcode><shortcode>[feature-area title=\\\"N\\u01a1i t\\u00e2m h\\u1ed3n \\u0111\\u01b0\\u1ee3c th\\u01b0 th\\u00e1i\\\" subtitle=\\\"Kh\\u00e1ch s\\u1ea1n &amp; khu ngh\\u1ec9 d\\u01b0\\u1ee1ng sang tr\\u1ecdng\\\" description=\\\"\\u0110\\u1eebng qu\\u00ean \\u0111\\u1eb7t b\\u00e1o th\\u1ee9c, th\\u1ee9c d\\u1eady s\\u1edbm c\\u00f9ng chi\\u1ebfc \\u00e1o \\u1ea5m \\u0111\\u1ec3 c\\u00f3 c\\u01a1 h\\u1ed9i b\\u1eaft g\\u1eb7p m\\u1ed9t bi\\u1ec3n m\\u00e2y ph\\u1ee7 tr\\u1eafng thung l\\u0169ng, g\\u1ea7n \\u0111\\u1ebfn m\\u1ee9c b\\u1ea1n g\\u1ea7n nh\\u01b0 c\\u00f3 th\\u1ec3 ch\\u1ea1m v\\u00e0o ch\\u00fang!\\\" image=\\\"rooms\\/168439420905-senna-hilltop-pool-villa-2-br-5.jpg\\\" background_image=\\\"backgrounds\\/an-img-02.png\\\" button_primary_label=\\\"Xem th\\u00eam\\\" button_primary_url=\\\"\\/contact-us\\\"][\\/feature-area]<\\/shortcode><shortcode>[pricing title=\\\"D\\u1ecbch v\\u1ee5 b\\u1ed5 sung\\\" subtitle=\\\"Gi\\u00e1 t\\u1ed1t nh\\u1ea5t\\\" description=\\\"Ch\\u00fang t\\u00f4i lu\\u00f4n mang \\u0111\\u1ebfn m\\u1ee9c gi\\u00e1 t\\u1ed1t nh\\u1ea5t c\\u00f9ng nhi\\u1ec1u \\u01b0u \\u0111\\u00e3i h\\u1ea5p d\\u1eabn, gi\\u00fap b\\u1ea1n t\\u1eadn h\\u01b0\\u1edfng k\\u1ef3 ngh\\u1ec9 tho\\u1ea3i m\\u00e1i v\\u00e0 ch\\u1ea5t l\\u01b0\\u1ee3ng v\\u1edbi chi ph\\u00ed h\\u1ee3p l\\u00fd. M\\u1ed7i l\\u1ef1a ch\\u1ecdn \\u0111\\u1ec1u \\u0111\\u01b0\\u1ee3c thi\\u1ebft k\\u1ebf \\u0111\\u1ec3 mang l\\u1ea1i gi\\u00e1 tr\\u1ecb cao nh\\u1ea5t cho tr\\u1ea3i nghi\\u1ec7m l\\u01b0u tr\\u00fa c\\u1ee7a b\\u1ea1n.\\\" background_image_1=\\\"backgrounds\\/an-img-01.png\\\" background_image_2=\\\"backgrounds\\/an-img-02.png\\\" quantity=\\\"2\\\" title_1=\\\"D\\u1ecdn ph\\u00f2ng\\\" description_1=\\\"D\\u1ecbch v\\u1ee5 d\\u1ecdn ph\\u00f2ng \\u0111\\u01b0\\u1ee3c th\\u1ef1c hi\\u1ec7n th\\u01b0\\u1eddng xuy\\u00ean b\\u1edfi \\u0111\\u1ed9i ng\\u0169 nh\\u00e2n vi\\u00ean chuy\\u00ean nghi\\u1ec7p, \\u0111\\u1ea3m b\\u1ea3o kh\\u00f4ng gian ph\\u00f2ng lu\\u00f4n s\\u1ea1ch s\\u1ebd, g\\u1ecdn g\\u00e0ng v\\u00e0 mang l\\u1ea1i c\\u1ea3m gi\\u00e1c tho\\u1ea3i m\\u00e1i cho kh\\u00e1ch trong su\\u1ed1t th\\u1eddi gian l\\u01b0u tr\\u00fa.\\\" price_1=\\\"$39.99\\\" duration_1=\\\"H\\u00e0ng th\\u00e1ng\\\" feature_list_1=\\\"D\\u1ecdn ph\\u00f2ng h\\u1eb1ng ng\\u00e0y., Thay ga gi\\u01b0\\u1eddng v\\u00e0 kh\\u0103n t\\u1eafm s\\u1ea1ch s\\u1ebd., V\\u1ec7 sinh ph\\u00f2ng t\\u1eafm v\\u00e0 khu v\\u1ef1c sinh ho\\u1ea1t., B\\u1ed5 sung \\u0111\\u1ed3 d\\u00f9ng c\\u1ea7n thi\\u1ebft trong ph\\u00f2ng., \\u0110\\u1ea3m b\\u1ea3o kh\\u00f4ng gian lu\\u00f4n s\\u1ea1ch s\\u1ebd v\\u00e0 tho\\u1ea3i m\\u00e1i.\\\" button_label_1=\\\"B\\u1eaft \\u0111\\u1ea7u ngay\\\" button_url_1=\\\"\\/contact-us\\\" title_2=\\\"\\u0110\\u00e3 bao g\\u1ed3m \\u0111\\u1ed3 u\\u1ed1ng\\\" description_2=\\\"Kh\\u00e1ch l\\u01b0u tr\\u00fa s\\u1ebd \\u0111\\u01b0\\u1ee3c ph\\u1ee5c v\\u1ee5 c\\u00e1c lo\\u1ea1i \\u0111\\u1ed3 u\\u1ed1ng mi\\u1ec5n ph\\u00ed trong th\\u1eddi gian s\\u1eed d\\u1ee5ng d\\u1ecbch v\\u1ee5. T\\u1eadn h\\u01b0\\u1edfng tr\\u00e0, c\\u00e0 ph\\u00ea ho\\u1eb7c c\\u00e1c lo\\u1ea1i n\\u01b0\\u1edbc gi\\u1ea3i kh\\u00e1t \\u0111\\u01b0\\u1ee3c chu\\u1ea9n b\\u1ecb s\\u1eb5n \\u0111\\u1ec3 mang l\\u1ea1i s\\u1ef1 ti\\u1ec7n nghi v\\u00e0 tho\\u1ea3i m\\u00e1i trong su\\u1ed1t k\\u1ef3 ngh\\u1ec9 c\\u1ee7a b\\u1ea1n.\\\" price_2=\\\"$59.99\\\" duration_2=\\\"H\\u00e0ng th\\u00e1ng\\\" feature_list_2=\\\"\\u0110\\u1ed3 u\\u1ed1ng mi\\u1ec5n ph\\u00ed cho kh\\u00e1ch l\\u01b0u tr\\u00fa., C\\u00f3 s\\u1eb5n tr\\u00e0; c\\u00e0 ph\\u00ea v\\u00e0 n\\u01b0\\u1edbc gi\\u1ea3i kh\\u00e1t., Ph\\u1ee5c v\\u1ee5 t\\u1ea1i ph\\u00f2ng ho\\u1eb7c khu v\\u1ef1c chung., Lu\\u00f4n \\u0111\\u01b0\\u1ee3c b\\u1ed5 sung trong su\\u1ed1t th\\u1eddi gian l\\u01b0u tr\\u00fa., Mang l\\u1ea1i tr\\u1ea3i nghi\\u1ec7m ngh\\u1ec9 d\\u01b0\\u1ee1ng ti\\u1ec7n nghi v\\u00e0 tho\\u1ea3i m\\u00e1i.\\\" button_label_2=\\\"B\\u1eaft \\u0111\\u1ea7u ngay\\\" button_url_2=\\\"\\/contact-us\\\"][\\/pricing]<\\/shortcode><shortcode>[testimonials title=\\\"Kh\\u00e1ch h\\u00e0ng n\\u00f3i g\\u00ec v\\u1ec1 ch\\u00fang t\\u00f4i\\\" subtitle=\\\"C\\u1ea3m nh\\u1eadn c\\u1ee7a kh\\u00e1ch h\\u00e0ng\\\" description=\\\"Kh\\u00e1m ph\\u00e1 nh\\u1eefng chia s\\u1ebb v\\u00e0 \\u0111\\u00e1nh gi\\u00e1 ch\\u00e2n th\\u1ef1c t\\u1eeb kh\\u00e1ch h\\u00e0ng \\u0111\\u00e3 tr\\u1ea3i nghi\\u1ec7m d\\u1ecbch v\\u1ee5 c\\u1ee7a ch\\u00fang t\\u00f4i. S\\u1ef1 h\\u00e0i l\\u00f2ng c\\u1ee7a kh\\u00e1ch h\\u00e0ng lu\\u00f4n l\\u00e0 \\u0111\\u1ed9ng l\\u1ef1c \\u0111\\u1ec3 ch\\u00fang t\\u00f4i kh\\u00f4ng ng\\u1eebng n\\u00e2ng cao ch\\u1ea5t l\\u01b0\\u1ee3ng d\\u1ecbch v\\u1ee5.\\\" background_image=\\\"\\/backgrounds\\/testimonial-bg.png\\\" testimonial_ids=\\\"1,2,3,4,5,6\\\"][\\/testimonials]<\\/shortcode><shortcode>[booking-form title=\\\"\\u0110\\u1eb7t ph\\u00f2ng\\\" subtitle=\\\"\\u0110\\u1eb7t ch\\u1ed7 ngay\\\" description=\\\"Th\\u1ef1c hi\\u1ec7n \\u0111\\u1eb7t ph\\u00f2ng nhanh ch\\u00f3ng v\\u00e0 thu\\u1eadn ti\\u1ec7n ch\\u1ec9 v\\u1edbi v\\u00e0i b\\u01b0\\u1edbc \\u0111\\u01a1n gi\\u1ea3n. Ch\\u1ecdn th\\u1eddi gian l\\u01b0u tr\\u00fa, lo\\u1ea1i ph\\u00f2ng ph\\u00f9 h\\u1ee3p v\\u00e0 t\\u1eadn h\\u01b0\\u1edfng k\\u1ef3 ngh\\u1ec9 tho\\u1ea3i m\\u00e1i v\\u1edbi d\\u1ecbch v\\u1ee5 chuy\\u00ean nghi\\u1ec7p c\\u1ee7a ch\\u00fang t\\u00f4i.\\\" image=\\\"rooms\\/1722936019senna-2br.jpg\\\"][\\/booking-form]<\\/shortcode><shortcode>[news title=\\\"Tin t\\u1ee9c &amp; B\\u00e0i vi\\u1ebft m\\u1edbi nh\\u1ea5t\\\" subtitle=\\\"B\\u00e0i vi\\u1ebft c\\u1ee7a chung t\\u00f4i\\\" description=\\\"C\\u1eadp nh\\u1eadt nh\\u1eefng b\\u00e0i vi\\u1ebft, tin t\\u1ee9c v\\u00e0 th\\u00f4ng tin m\\u1edbi nh\\u1ea5t v\\u1ec1 du l\\u1ecbch, kh\\u00e1ch s\\u1ea1n v\\u00e0 c\\u00e1c tr\\u1ea3i nghi\\u1ec7m th\\u00fa v\\u1ecb gi\\u00fap b\\u1ea1n c\\u00f3 m\\u1ed9t chuy\\u1ebfn \\u0111i tr\\u1ecdn v\\u1eb9n h\\u01a1n.\\\" background_image=\\\"backgrounds\\/an-img-07.png\\\" type=\\\"featured\\\" limit=\\\"3\\\"][\\/news]<\\/shortcode><shortcode>[brands background_color=\\\"#F7F5F1\\\" quantity=\\\"6\\\" name_1=\\\"Ersintat\\\" image_1=\\\"brands\\/logo-1.png\\\" link_1=\\\"https:\\/\\/ersintat.com\\\" name_2=\\\"Techradar\\\" image_2=\\\"brands\\/logo-2.png\\\" link_2=\\\"https:\\/\\/techradar.com\\\" name_3=\\\"Turbologo\\\" image_3=\\\"brands\\/logo-3.png\\\" link_3=\\\"https:\\/\\/turbologo.com\\\" name_4=\\\"Thepeer\\\" image_4=\\\"brands\\/logo-4.png\\\" link_4=\\\"https:\\/\\/thepeer.com\\\" name_5=\\\"Techi\\\" image_5=\\\"brands\\/logo-5.png\\\" link_5=\\\"http:\\/\\/techi.com\\\" name_6=\\\"Grapik\\\" image_6=\\\"brands\\/logo-6.png\\\" link_6=\\\"https:\\/\\/grapk.com\\\"][\\/brands]<\\/shortcode>\",\"gallery\":null,\"submitter\":\"apply\",\"language\":\"vi\",\"status\":\"published\",\"t