ea9n an to\\u00e0n h\\u00e0ng \\u0111\\u1ea7u. T\\u1eeb nh\\u1eefng kh\\u00e1ch s\\u1ea1n boutique \\u1ea5m c\\u00fang \\u0111\\u1ebfn c\\u00e1c kh\\u00e1ch s\\u1ea1n sang tr\\u1ecdng ngay trung t\\u00e2m th\\u00e0nh ph\\u1ed1, ch\\u00fang t\\u00f4i \\u0111\\u00e3 chu\\u1ea9n b\\u1ecb s\\u1eb5n nhi\\u1ec1u l\\u1ef1a ch\\u1ecdn \\u0111a d\\u1ea1ng \\u0111\\u1ec3 \\u0111\\u1ea3m b\\u1ea3o b\\u1ea1n c\\u00f3 m\\u1ed9t k\\u1ef3 ngh\\u1ec9 tho\\u1ea3i m\\u00e1i v\\u00e0 kh\\u00f4ng ph\\u1ea3i lo l\\u1eafng. H\\u00e3y ch\\u1ecdn About Us \\u0111\\u1ec3 c\\u00f3 m\\u1ed9t chuy\\u1ebfn \\u0111i \\u0111\\u00e1ng nh\\u1edb, tr\\u1ecdn v\\u1eb9n v\\u1edbi s\\u1ee9c h\\u1ea5p d\\u1eabn \\u0111\\u1eb7c bi\\u1ec7t c\\u1ee7a London.\\\" highlights=\\\"Kh\\u00e1m ph\\u00e1 n\\u01a1i l\\u01b0u tr\\u00fa an to\\u00e0n tuy\\u1ec7t \\u0111\\u1ed1i t\\u1ea1i nh\\u1eefng kh\\u00e1ch s\\u1ea1n \\u0111\\u01b0\\u1ee3c \\u0111\\u00e1nh gi\\u00e1 cao nh\\u1ea5t \\u1edf London.; \\u0110\\u1eafm m\\u00ecnh trong v\\u1ebb quy\\u1ebfn r\\u0169 ngay gi\\u1eefa tr\\u00e1i tim London.; Tr\\u1ea3i nghi\\u1ec7m s\\u1ef1 k\\u1ebft h\\u1ee3p ho\\u00e0n h\\u1ea3o gi\\u1eefa sang tr\\u1ecdng v\\u00e0 ti\\u1ec7n nghi.\\\" style=\\\"style-1\\\" button_label=\\\"Xem th\\u00eam\\\" button_url=\\\"\\/about-us\\\" signature_image=\\\"rooms\\/168439421305-senna-hilltop-pool-villa-2-br-9-copy.jpg\\\" signature_author=\\\"Vincent Smith\\\" top_left_image=\\\"rooms\\/168144758004-senna-hilltop-pool-villa-1-br-5.jpg\\\" bottom_right_image=\\\"rooms\\/168144758104-senna-hilltop-pool-villa-1-br-2.jpg\\\" floating_right_image=\\\"backgrounds\\/an-img-02.png\\\"][\\/about-us]<\\/shortcode><shortcode>[featured-amenities title=\\\"Kh\\u00e1ch s\\u1ea1n\\\" subtitle=\\\"Kh\\u00e1m ph\\u00e1\\\" description=\\\"Kh\\u00f4ng gian ngh\\u1ec9 d\\u01b0\\u1ee1ng sang tr\\u1ecdng v\\u00e0 tho\\u1ea3i m\\u00e1i ngay t\\u1ea1i trung t\\u00e2m th\\u00e0nh ph\\u1ed1. V\\u1edbi thi\\u1ebft k\\u1ebf tinh t\\u1ebf c\\u00f9ng c\\u00e1c ti\\u1ec7n nghi hi\\u1ec7n \\u0111\\u1ea1i, m\\u1ed7i ph\\u00f2ng \\u0111\\u1ec1u \\u0111\\u01b0\\u1ee3c ch\\u0103m ch\\u00fat \\u0111\\u1ec3 mang l\\u1ea1i c\\u1ea3m gi\\u00e1c th\\u01b0 gi\\u00e3n t\\u1ed1i \\u0111a cho du kh\\u00e1ch.\\\" background_color=\\\"#F7F5F1\\\" background_image=\\\"\\/backgrounds\\/an-img-01.png\\\" amenity_ids=\\\"1,2,3,4,5,6\\\"][\\/featured-amenities]<\\/shortcode><shortcode>[featured-rooms title=\\\"Ph\\u00f2ng &amp; Ph\\u00f2ng Suite\\\" subtitle=\\\"Ni\\u1ec1m vui c\\u1ee7a s\\u1ef1 sang tr\\u1ecdng\\\" description=\\\"Kh\\u00e1m ph\\u00e1 c\\u00e1c h\\u1ea1ng ph\\u00f2ng v\\u00e0 suite \\u0111\\u01b0\\u1ee3c thi\\u1ebft k\\u1ebf tinh t\\u1ebf, k\\u1ebft h\\u1ee3p gi\\u1eefa s\\u1ef1 sang tr\\u1ecdng, ti\\u1ec7n nghi hi\\u1ec7n \\u0111\\u1ea1i v\\u00e0 kh\\u00f4ng gian tho\\u1ea3i m\\u00e1i, mang \\u0111\\u1ebfn cho b\\u1ea1n tr\\u1ea3i nghi\\u1ec7m ngh\\u1ec9 d\\u01b0\\u1ee1ng tr\\u1ecdn v\\u1eb9n.\\\" room_ids=\\\"2,3,4\\\"][\\/featured-rooms]<\\/shortcode><shortcode>[feature-area title=\\\"N\\u01a1i t\\u00e2m h\\u1ed3n \\u0111\\u01b0\\u1ee3c th\\u01b0 th\\u00e1i\\\" subtitle=\\\"Kh\\u00e1ch s\\u1ea1n &amp; khu ngh\\u1ec9 d\\u01b0\\u1ee1ng sang tr\\u1ecdng\\\" description=\\\"\\u0110\\u1eebng qu\\u00ean \\u0111\\u1eb7t b\\u00e1o th\\u1ee9c, th\\u1ee9c d\\u1eady s\\u1edbm c\\u00f9ng chi\\u1ebfc \\u00e1o \\u1ea5m \\u0111\\u1ec3 c\\u00f3 c\\u01a1 h\\u1ed9i b\\u1eaft g\\u1eb7p m\\u1ed9t bi\\u1ec3n m\\u00e2y ph\\u1ee7 tr\\u1eafng thung l\\u0169ng, g\\u1ea7n \\u0111\\u1ebfn m\\u1ee9c b\\u1ea1n g\\u1ea7n nh\\u01b0 c\\u00f3 th\\u1ec3 ch\\u1ea1m v\\u00e0o ch\\u00fang!\\\" image=\\\"places\\/1714962283avana-10-edit.jpg\\\" background_image=\\\"backgrounds\\/an-img-02.png\\\" button_primary_label=\\\"Xem th\\u00eam\\\" button_primary_url=\\\"\\/contact-us\\\"][\\/feature-area]<\\/shortcode><shortcode>[pricing title=\\\"D\\u1ecbch v\\u1ee5 b\\u1ed5 sung\\\" subtitle=\\\"Gi\\u00e1 t\\u1ed1t nh\\u1ea5t\\\" description=\\\"Ch\\u00fang t\\u00f4i 