i v\\u1edbi \\u0111\\u1ea7y \\u0111\\u1ee7 ti\\u1ec7n nghi.; N\\u01a1i l\\u00fd t\\u01b0\\u1edfng \\u0111\\u1ec3 ngh\\u1ec9 ng\\u01a1i, th\\u01b0 gi\\u00e3n v\\u00e0 t\\u00e1i t\\u1ea1o n\\u0103ng l\\u01b0\\u1ee3ng\\\" style=\\\"style-1\\\" button_label=\\\"Xem th\\u00eam\\\" button_url=\\\"\\/about-us\\\" signature_image=\\\"rooms\\/168439421305-senna-hilltop-pool-villa-2-br-9-copy.jpg\\\" signature_author=\\\"Vincent Smith\\\" top_left_image=\\\"rooms\\/168144758004-senna-hilltop-pool-villa-1-br-5.jpg\\\" bottom_right_image=\\\"rooms\\/168144758104-senna-hilltop-pool-villa-1-br-2.jpg\\\" floating_right_image=\\\"backgrounds\\/an-img-02.png\\\"][\\/about-us]<\\/shortcode><shortcode>[why-choose-us title=\\\"Ch\\u00fang t\\u00f4i cung c\\u1ea5p nhi\\u1ec1u l\\u1ef1a ch\\u1ecdn kh\\u00e1ch s\\u1ea1n\\\" subtitle=\\\"Nh\\u1eefng g\\u00ec ch\\u00fang t\\u00f4i cung c\\u1ea5p\\\" description=\\\"Ch\\u00fang t\\u00f4i mang \\u0111\\u1ebfn nhi\\u1ec1u l\\u1ef1a ch\\u1ecdn kh\\u00e1ch s\\u1ea1n v\\u1edbi c\\u00e1c phong c\\u00e1ch v\\u00e0 m\\u1ee9c gi\\u00e1 kh\\u00e1c nhau, gi\\u00fap b\\u1ea1n d\\u1ec5 d\\u00e0ng t\\u00ecm \\u0111\\u01b0\\u1ee3c n\\u01a1i l\\u01b0u tr\\u00fa ph\\u00f9 h\\u1ee3p v\\u1edbi nhu c\\u1ea7u v\\u00e0 ng\\u00e2n s\\u00e1ch c\\u1ee7a m\\u00ecnh.\\\" right_image=\\\"rooms\\/168179031903-ferms-grand-mountain-suite-2.jpg\\\" background_color=\\\"#291D16\\\" background_image=\\\"backgrounds\\/an-img-05.png\\\" quantity=\\\"3\\\" title_1=\\\"Ch\\u1ea5t l\\u01b0\\u1ee3ng cao\\\" percentage_1=\\\"80\\\" title_2=\\\"D\\u1ecbch v\\u1ee5 b\\u1ea3o tr\\u00ec\\\" percentage_2=\\\"90\\\" title_3=\\\"Qu\\u1ea3n l\\u00fd s\\u1ea3n ph\\u1ea9m\\\" percentage_3=\\\"70\\\"][\\/why-choose-us]<\\/shortcode><shortcode>[services title=\\\"Vi\\u00ean ng\\u1ecdc c\\u1ee7a bi\\u1ec3n Adriatic\\\" subtitle=\\\"Kh\\u00e1ch s\\u1ea1n &amp; khu ngh\\u1ec9 d\\u01b0\\u1ee1ng sang tr\\u1ecdng\\\" description=\\\"Hi\\u1ec7n t\\u1ea1i ch\\u01b0a c\\u00f3 s\\u1ef1 trang tr\\u00ed n\\u1ed5i b\\u1eadt. Maecenas \\u0111\\u00e3 t\\u1ea1o ra m\\u1ed9t m\\u1ee9c gi\\u00e1 ph\\u00f9 h\\u1ee3p. Ph\\u1ea7n li\\u00ean k\\u1ebft t\\u1ed5ng th\\u1ec3 kh\\u00e1 v\\u1eefng ch\\u1eafc, mang l\\u1ea1i hi\\u1ec7u qu\\u1ea3 v\\u00e0 s\\u1ef1 h\\u00e0i h\\u00f2a trong k\\u1ebft n\\u1ed1i. Ph\\u01b0\\u01a1ng ti\\u1ec7n v\\u1eadn h\\u00e0nh linh ho\\u1ea1t theo d\\u00f2ng li\\u00ean k\\u1ebft ch\\u00ednh. Ng\\u01b0\\u1eddi d\\u00f9ng c\\u00f3 th\\u1ec3 \\u0111i\\u1ec1u ch\\u1ec9nh m\\u1ed9t c\\u00e1ch linh ho\\u1ea1t. Hi\\u1ec7n nay, l\\u1ed9 tr\\u00ecnh \\u0111\\u00e3 \\u0111\\u01b0\\u1ee3c m\\u1edf ra, gi\\u00fap c\\u1ea3i thi\\u1ec7n hi\\u1ec7u qu\\u1ea3 v\\u1eadn h\\u00e0nh. K\\u1ebft qu\\u1ea3 cu\\u1ed1i c\\u00f9ng mang l\\u1ea1i s\\u1ef1 c\\u00e2n b\\u1eb1ng v\\u00e0 t\\u00ednh th\\u1ea9m m\\u1ef9.\\\" left_image=\\\"rooms\\/168439420905-senna-hilltop-pool-villa-2-br-5.jpg\\\" right_floating_image=\\\"backgrounds\\/an-img-02.png\\\" button_label=\\\"Xem th\\u00eam\\\" button_url=\\\"\\/about-us\\\"][\\/services]<\\/shortcode><shortcode>[news title=\\\"Tin t\\u1ee9c &amp; B\\u00e0i vi\\u1ebft m\\u1edbi nh\\u1ea5t\\\" subtitle=\\\"B\\u00e0i vi\\u1ebft c\\u1ee7a chung t\\u00f4i\\\" description=\\\"C\\u1eadp nh\\u1eadt nh\\u1eefng b\\u00e0i vi\\u1ebft, tin t\\u1ee9c v\\u00e0 th\\u00f4ng tin m\\u1edbi nh\\u1ea5t v\\u1ec1 du l\\u1ecbch, kh\\u00e1ch s\\u1ea1n v\\u00e0 c\\u00e1c tr\\u1ea3i nghi\\u1ec7m th\\u00fa v\\u1ecb gi\\u00fap b\\u1ea1n c\\u00f3 m\\u1ed9t chuy\\u1ebfn \\u0111i tr\\u1ecdn v\\u1eb9n h\\u01a1n.\\\" background_image=\\\"backgrounds\\/an-img-07.png\\\" type=\\\"featured\\\" limit=\\\"3\\\"][\\/news]<\\/shortcode><shortcode>[newsletter title=\\\"Nh\\u1eadn \\u01b0u \\u0111\\u00e3i t\\u1ed1t nh\\u1ea5t cho kh\\u00e1ch s\\u1ea1n\\\" subtitle=\\\"B\\u1ea3n tin\\\" description=\\\"Kh\\u00e1m ph\\u00e1 nh\\u1eefng \\u01b0u \\u0111\\u00e3i h\\u1ea5p d\\u1eabn v\\u00e0 m\\u1ee9c gi\\u00e1 \\u0111\\u1eb7c bi\\u1ec7t khi \\u0111\\u1eb7t ph\\u00f2ng t\\u1ea1i