(352, 1, 'Botble\\ACL\\Models\\User', '', '{\"name\":\"Home Page 01\",\"model\":\"Botble\\\\Page\\\\Models\\\\Page\",\"slug\":\"https:\\/\\/retreat.anduongliving.com\",\"description\":null,\"content\":\"<shortcode>[simple-slider key=\\\"home-slider\\\"][\\/simple-slider]<\\/shortcode><shortcode>[check-availability-form][\\/check-availability-form]<\\/shortcode><shortcode>[about-us title=\\\"A retreat in the heart of nature\\\" subtitle=\\\"About us\\\" description=\\\"Retreat is designed as a peaceful sanctuary where you can step away from the busy pace of everyday life and rediscover relaxation and balance. Surrounded by lush greenery, harmonious architecture that blends with nature, and thoughtfully curated amenities, it offers a truly complete and refreshing getaway experience for every guest.{{NEWLINE}}{{NEWLINE}}Whether you are looking for a relaxing holiday, a rejuvenating escape, or simply a quiet moment to spend with family and friends, Retreat is always ready to provide a comfortable, private, and inspiring space for your stay.\\\" highlights=\\\"A peaceful retreat immersed in nature.; Elegant design that brings a sense of relaxation and privacy.; A comfortable stay with thoughtfully provided amenities.; An ideal place to rest, unwind, and recharge your energy.\\\" style=\\\"style-1\\\" button_label=\\\"Discover more\\\" button_url=\\\"\\/about-us\\\" signature_image=\\\"rooms\\/168439421305-senna-hilltop-pool-villa-2-br-9-copy.jpg\\\" signature_author=\\\"Vincent Smith\\\" top_left_image=\\\"places\\/1683775376-vbk0653-edit.jpg\\\" bottom_right_image=\\\"places\\/1684383802linh-phuong.jpg\\\" floating_right_image=\\\"backgrounds\\/an-img-02.png\\\"][\\/about-us]<\\/shortcode><shortcode>[featured-amenities title=\\\"The Hotel\\\" subtitle=\\\"Explore\\\" description=\\\"A luxurious and comfortable retreat in the heart of the city. With refined design and modern amenities, each room is thoughtfully crafted to provide guests with the ultimate sense of relaxation.\\\" background_color=\\\"#F7F5F1\\\" background_image=\\\"\\/backgrounds\\/an-img-01.png\\\" amenity_ids=\\\"1,2,3,4,5,6\\\"][\\/featured-amenities]<\\/shortcode><shortcode>[featured-rooms title=\\\"Rooms &amp; Suites\\\" subtitle=\\\"The Pleasure Of Luxury\\\" description=\\\"Explore our thoughtfully designed rooms and suites, where elegance, modern amenities, and comfortable spaces come together to create a truly complete and relaxing stay.\\\" room_ids=\\\"2,3,4\\\"][\\/featured-rooms]<\\/shortcode><shortcode>[feature-area title=\\\"Pearl Of The Adriatic.\\\" subtitle=\\\"Luxury Hotel &amp; Resort\\\" description=\\\"Don\\u2019t forget to set your alarm and wake up early with a warm jacket to catch the breathtaking sight of a sea of clouds covering the valley\\u2014so close it feels like you could almost touch them!\\\" image=\\\"places\\/1714962283avana-10-edit.jpg\\\" background_image=\\\"backgrounds\\/an-img-02.png\\\" button_primary_label=\\\"Discover More\\\" button_primary_url=\\\"\\/contact-us\\\"][\\/feature-area]<\\/shortcode><shortcode>[pricing title=\\\"Extra Services\\\" subtitle=\\\"Best Prices\\\" description=\\\"We always offer the best rates along with attractive promotions, allowing you to enjoy a comfortable and high-quality stay at a reasonable cost. Each option is designed to deliver the greatest value for your stay experience.\\\" background_image_1=\\\"backgrounds\\/an-img-01.png\\\" background_image_2=\\\"backgrounds\\/an-img-02.png\\\" quantity=\\\"2\\\" title_1=\\\"Room cleaning\\\" description_1=\\\"Housekeeping services are carried out regularly by our professional staff, ensuring that every room remains clean, tidy, and comfortable throughout your stay\\\" price_1=\\\"200,000\\u20ab\\\" duration_1=\\\"Monthly\\\" feature_list_1=\\\"Daily housekeeping service., Fresh bed linens and clean towels provided., Cleaning of the bathroom and living areas., Replenishment of essential in-room amenities., Ensuring a clean and comfortable space at all times.\\\" button_label_1=\\\"Get Started\\\" button_url_1=\\\"\\/contact-us\\\" title_2=\\\"Drinks included\\\" description_2=\\\"Guests will be served complimentary beverages during their stay. Enjoy tea, coffee, or a selection of refreshing drinks prepared for your convenience, adding comfort and relaxation throughout your stay.\\\" price_2=\\\"400,000\\u20ab\\\" duration_2=\\\"Monthly\\\" feature_list_2=\\\"Complimentary beverages for staying guests., Tea; coffee; and soft drinks available., Served in-room or in common areas., Regularly replenished throughout your stay., A convenient and comfortable stay experience.\\\" button_label_2=\\\"Get Started \\\" button_url_2=\\\"\\/contact-us\\\"][\\/pricing]<\\/shortcode><shortcode>[testimonials title=\\\"What Our Clients Says\\\" subtitle=\\\"Testimonial\\\" description=\\\"Discover genuine stories and reviews from guests who have experienced our services. Customer satisfaction is always our motivation to continuously improve and enhance the quality of our service.\\\" background_image=\\\"\\/backgrounds\\/testimonial-bg.png\\\" testimonial_ids=\\\"1,2,3,4,5,6\\\"][\\/testimonials]<\\/shortcode><shortcode>[booking-form title=\\\"Book A Room\\\" subtitle=\\\"Make Reservation\\\" description=\\\"Make your reservation quickly and conveniently in just a few simple steps. Choose your stay dates, select the room type that suits you, and enjoy a comfortable getaway with our professional service.\\\" image=\\\"places\\/1685507832restaurant-2.jpg\\\"][\\/booking-form]<\\/shortcode><shortcode>[news title=\\\"Latest Blog &amp; News\\\" subtitle=\\\"Our Blog\\\" description=\\\"Stay updated with the latest articles, news, and information about travel, hotels, and exciting experiences to help you enjoy a more complete and memorable trip.\\\" background_image=\\\"backgrounds\\/an-img-07.png\\\" type=\\\"featured\\\" limit=\\\"3\\\"][\\/news]<\\/shortcode>\",\"form\":\"Botble\\\\Page\\\\Forms\\\\PageForm\",\"gallery\":null,\"submitter\":\"apply\",\"language\":\"en_US\",\"ref_lang\":\"en_US\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 1, 'Home Page 01', 'primary', '2026-03-13 03:40:25', '2026-03-13 03:40:25'),
