(423, 1, 'Botble\\ACL\\Models\\User', 'post', '{\"name\":\"cloud-pool\",\"model\":\"Botble\\\\Blog\\\\Models\\\\Post\",\"slug\":\"cloud-pool\",\"slug_id\":\"79\",\"is_slug_editable\":\"1\",\"description\":\"Cloud Pool l\\u00e0 h\\u1ed3 b\\u01a1i v\\u00f4 c\\u1ef1c n\\u1eb1m gi\\u1eefa khung c\\u1ea3nh n\\u00fai r\\u1eebng h\\u00f9ng v\\u0129, n\\u01a1i du kh\\u00e1ch c\\u00f3 th\\u1ec3 th\\u01b0 gi\\u00e3n trong l\\u00e0n n\\u01b0\\u1edbc m\\u00e1t v\\u00e0 chi\\u00eam ng\\u01b0\\u1ee1ng v\\u1ebb \\u0111\\u1eb9p thi\\u00ean nhi\\u00ean t\\u1eeb tr\\u00ean cao.\",\"is_featured\":\"0\",\"content\":\"<p data-start=\\\"378\\\" data-end=\\\"699\\\">Cloud Pool l\\u00e0 m\\u1ed9t trong nh\\u1eefng \\u0111i\\u1ec3m nh\\u1ea5n n\\u1ed5i b\\u1eadt c\\u1ee7a khu ngh\\u1ec9 d\\u01b0\\u1ee1ng, mang \\u0111\\u1ebfn tr\\u1ea3i nghi\\u1ec7m th\\u01b0 gi\\u00e3n gi\\u1eefa thi\\u00ean nhi\\u00ean v\\u1edbi t\\u1ea7m nh\\u00ecn m\\u1edf r\\u1ed9ng ra to\\u00e0n b\\u1ed9 thung l\\u0169ng v\\u00e0 nh\\u1eefng d\\u00e3y n\\u00fai tr\\u00f9ng \\u0111i\\u1ec7p. H\\u1ed3 b\\u01a1i \\u0111\\u01b0\\u1ee3c thi\\u1ebft k\\u1ebf theo phong c\\u00e1ch v\\u00f4 c\\u1ef1c hi\\u1ec7n \\u0111\\u1ea1i, t\\u1ea1o c\\u1ea3m gi\\u00e1c nh\\u01b0 m\\u1eb7t n\\u01b0\\u1edbc h\\u00f2a v\\u00e0o b\\u1ea7u tr\\u1eddi v\\u00e0 khung c\\u1ea3nh thi\\u00ean nhi\\u00ean xung quanh.<\\/p><p data-start=\\\"701\\\" data-end=\\\"988\\\">Kh\\u00f4ng gian xung quanh h\\u1ed3 b\\u01a1i \\u0111\\u01b0\\u1ee3c b\\u1ed1 tr\\u00ed h\\u00e0i h\\u00f2a v\\u1edbi c\\u1ea3nh quan t\\u1ef1 nhi\\u00ean, mang l\\u1ea1i c\\u1ea3m gi\\u00e1c y\\u00ean b\\u00ecnh v\\u00e0 tho\\u1ea3i m\\u00e1i cho du kh\\u00e1ch. Nh\\u1eefng chi\\u1ebfc gh\\u1ebf n\\u1eb1m th\\u01b0 gi\\u00e3n \\u0111\\u01b0\\u1ee3c s\\u1eafp x\\u1ebfp d\\u1ecdc theo h\\u1ed3 b\\u01a1i, gi\\u00fap b\\u1ea1n c\\u00f3 th\\u1ec3 ngh\\u1ec9 ng\\u01a1i, \\u0111\\u1ecdc s\\u00e1ch ho\\u1eb7c \\u0111\\u01a1n gi\\u1ea3n l\\u00e0 t\\u1eadn h\\u01b0\\u1edfng b\\u1ea7u kh\\u00f4ng kh\\u00ed trong l\\u00e0nh c\\u1ee7a n\\u00fai r\\u1eebng.<\\/p><p data-start=\\\"990\\\" data-end=\\\"1291\\\">V\\u00e0o bu\\u1ed5i s\\u00e1ng s\\u1edbm, Cloud Pool l\\u00e0 n\\u01a1i l\\u00fd t\\u01b0\\u1edfng \\u0111\\u1ec3 \\u0111\\u00f3n nh\\u1eefng tia n\\u1eafng \\u0111\\u1ea7u ng\\u00e0y v\\u00e0 ng\\u1eafm nh\\u00ecn l\\u00e0n s\\u01b0\\u01a1ng m\\u1ecfng bao ph\\u1ee7 thung l\\u0169ng. Khi chi\\u1ec1u xu\\u1ed1ng, khung c\\u1ea3nh ho\\u00e0ng h\\u00f4n r\\u1ef1c r\\u1ee1 ph\\u1ea3n chi\\u1ebfu tr\\u00ean m\\u1eb7t n\\u01b0\\u1edbc t\\u1ea1o n\\u00ean m\\u1ed9t b\\u1ee9c tranh thi\\u00ean nhi\\u00ean \\u0111\\u1ea7y \\u1ea5n t\\u01b0\\u1ee3ng, mang l\\u1ea1i nh\\u1eefng kho\\u1ea3nh kh\\u1eafc th\\u01b0 gi\\u00e3n kh\\u00f3 qu\\u00ean cho du kh\\u00e1ch.<\\/p><p data-start=\\\"1293\\\" data-end=\\\"1566\\\">B\\u00ean c\\u1ea1nh khu v\\u1ef1c h\\u1ed3 b\\u01a1i l\\u00e0 kh\\u00f4ng gian ph\\u1ee5c v\\u1ee5 \\u0111\\u1ed3 u\\u1ed1ng nh\\u1eb9 v\\u00e0 c\\u00e1c khu v\\u1ef1c ngh\\u1ec9 ch\\u00e2n, gi\\u00fap du kh\\u00e1ch c\\u00f3 th\\u1ec3 t\\u1eadn h\\u01b0\\u1edfng tr\\u1ecdn v\\u1eb9n th\\u1eddi gian th\\u01b0 gi\\u00e3n t\\u1ea1i \\u0111\\u00e2y. D\\u00f9 b\\u1ea1n mu\\u1ed1n b\\u01a1i l\\u1ed9i, ngh\\u1ec9 ng\\u01a1i hay ch\\u1ee5p \\u1ea3nh l\\u01b0u ni\\u1ec7m, Cloud Pool \\u0111\\u1ec1u mang \\u0111\\u1ebfn m\\u1ed9t tr\\u1ea3i nghi\\u1ec7m tuy\\u1ec7t v\\u1eddi gi\\u1eefa thi\\u00ean nhi\\u00ean.<\\/p><p data-start=\\\"1568\\\" data-end=\\\"1721\\\">Cloud Pool m\\u1edf c\\u1eeda h\\u1eb1ng ng\\u00e0y t\\u1eeb 07:00 \\u2013 18:30, s\\u1eb5n s\\u00e0ng ch\\u00e0o \\u0111\\u00f3n du kh\\u00e1ch \\u0111\\u1ebfn t\\u1eadn h\\u01b0\\u1edfng kh\\u00f4ng gian th\\u01b0 gi\\u00e3n v\\u00e0 ng\\u1eafm nh\\u00ecn v\\u1ebb \\u0111\\u1eb9p y\\u00ean b\\u00ecnh c\\u1ee7a n\\u00fai r\\u1eebng.<\\/p>\",\"gallery\":null,\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"language\":\"vi\",\"status\":\"published\",\"categories\":[\"1\"],\"image\":\"places\\/1681380943dji-0082.jpg\",\"tag\":null,\"submitter\":\"apply\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 7, 'cloud-pool', 'primary', '2026-03-15 20:04:37', '2026-03-15 20:04:37');
