(463, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"1\",\"question\":\"\\u0110i\\u1ec1u g\\u00ec khi\\u1ebfn Luxury Hotel kh\\u00e1c bi\\u1ec7t so v\\u1edbi nh\\u1eefng n\\u01a1i kh\\u00e1c?\",\"answer\":\"<p>Kh\\u00e1ch s\\u1ea1n c\\u1ee7a ch\\u00fang t\\u00f4i n\\u1ed5i b\\u1eadt v\\u1edbi <strong data-start=\\\"62\\\" data-end=\\\"89\\\">v\\u1ecb tr\\u00ed ven bi\\u1ec3n \\u0111\\u1eafc \\u0111\\u1ecba<\\/strong>, thi\\u1ebft k\\u1ebf cu\\u1ed1n h\\u00fat h\\u00e0i h\\u00f2a v\\u1edbi thi\\u00ean nhi\\u00ean, <strong data-start=\\\"134\\\" data-end=\\\"154\\\">d\\u1ecbch v\\u1ee5 ho\\u00e0n h\\u1ea3o<\\/strong> lu\\u00f4n t\\u1eadn t\\u00e2m \\u0111\\u00e1p \\u1ee9ng m\\u1ecdi nhu c\\u1ea7u c\\u1ee7a du kh\\u00e1ch, c\\u00f9ng <strong data-start=\\\"207\\\" data-end=\\\"247\\\">h\\u1ec7 th\\u1ed1ng ti\\u1ec7n nghi \\u0111\\u1eb3ng c\\u1ea5p th\\u1ebf gi\\u1edbi<\\/strong> mang \\u0111\\u1ebfn s\\u1ef1 sang tr\\u1ecdng v\\u00e0 tinh t\\u1ebf v\\u01b0\\u1ee3t tr\\u1ed9i.<\\/p>\",\"submitter\":\"save\",\"language\":\"vi\",\"status\":\"published\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 1, 'ID: 1', 'primary', '2026-03-15 21:04:00', '2026-03-15 21:04:00'),
(464, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"2\",\"question\":\"Kh\\u00e1ch s\\u1ea1n c\\u1ee7a b\\u1ea1n c\\u00f3 cho ph\\u00e9p mang theo th\\u00fa c\\u01b0ng kh\\u00f4ng?\",\"answer\":\"<p>R\\u1ea5t ti\\u1ebfc, \\u0111\\u1ec3 duy tr\\u00ec <strong data-start=\\\"47\\\" data-end=\\\"84\\\">kh\\u00f4ng gian y\\u00ean t\\u0129nh v\\u00e0 sang tr\\u1ecdng<\\/strong> cho t\\u1ea5t c\\u1ea3 kh\\u00e1ch l\\u01b0u tr\\u00fa, ch\\u00fang t\\u00f4i xin th\\u00f4ng b\\u00e1o r\\u1eb1ng <strong data-start=\\\"140\\\" data-end=\\\"187\\\">kh\\u00e1ch s\\u1ea1n kh\\u00f4ng cho ph\\u00e9p mang theo th\\u00fa c\\u01b0ng<\\/strong> trong c\\u00e1c ph\\u00f2ng ngh\\u1ec9 \\u0111\\u01b0\\u1ee3c thi\\u1ebft k\\u1ebf tinh t\\u1ebf c\\u0169ng nh\\u01b0 t\\u1ea1i c\\u00e1c khu v\\u1ef1c chung \\u0111\\u01b0\\u1ee3c b\\u1ed1 tr\\u00ed c\\u1ea9n th\\u1eadn c\\u1ee7a kh\\u00e1ch s\\u1ea1n.<\\/p>\",\"language\":\"vi\",\"status\":\"published\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 2, 'ID: 2', 'primary', '2026-03-15 21:04:28', '2026-03-15 21:04:28'),
(465, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"2\",\"question\":\"Kh\\u00e1ch s\\u1ea1n c\\u1ee7a b\\u1ea1n c\\u00f3 cho ph\\u00e9p mang theo th\\u00fa c\\u01b0ng kh\\u00f4ng?\",\"answer\":\"<p>R\\u1ea5t ti\\u1ebfc, \\u0111\\u1ec3 duy tr\\u00ec <strong>kh\\u00f4ng gian y\\u00ean t\\u0129nh v\\u00e0 sang tr\\u1ecdng<\\/strong> cho t\\u1ea5t c\\u1ea3 kh\\u00e1ch l\\u01b0u tr\\u00fa, ch\\u00fang t\\u00f4i xin th\\u00f4ng b\\u00e1o r\\u1eb1ng <strong>kh\\u00e1ch s\\u1ea1n kh\\u00f4ng cho ph\\u00e9p mang theo th\\u00fa c\\u01b0ng<\\/strong> trong c\\u00e1c ph\\u00f2ng ngh\\u1ec9 \\u0111\\u01b0\\u1ee3c thi\\u1ebft k\\u1ebf tinh t\\u1ebf c\\u0169ng nh\\u01b0 t\\u1ea1i c\\u00e1c khu v\\u1ef1c chung \\u0111\\u01b0\\u1ee3c b\\u1ed1 tr\\u00ed c\\u1ea9n th\\u1eadn c\\u1ee7a kh\\u00e1ch s\\u1ea1n.<\\/p>\",\"language\":\"vi\",\"status\":\"published\",\"submitter\":\"save\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 2, 'ID: 2', 'primary', '2026-03-15 21:04:32', '2026-03-15 21:04:32'),
(466, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"1\",\"question\":\"Kh\\u00e1ch s\\u1ea1n c\\u00f3 d\\u1ecbch v\\u1ee5 \\u0111\\u01b0a \\u0111\\u00f3n s\\u00e2n bay kh\\u00f4ng?\",\"answer\":\"<p>T\\u1ea5t nhi\\u00ean! \\u0110\\u1ec3 mang l\\u1ea1i s\\u1ef1 thu\\u1eadn ti\\u1ec7n cho qu\\u00fd kh\\u00e1ch, ch\\u00fang t\\u00f4i cung c\\u1ea5p <strong data-start=\\\"97\\\" data-end=\\\"130\\\">d\\u1ecbch v\\u1ee5 \\u0111\\u01b0a \\u0111\\u00f3n s\\u00e2n bay ri\\u00eang<\\/strong>, c\\u00f3 th\\u1ec3 \\u0111\\u01b0\\u1ee3c s\\u1eafp x\\u1ebfp tr\\u01b0\\u1edbc. \\u0110\\u1ed9i ng\\u0169 <strong data-start=\\\"167\\\" data-end=\\\"195\\\">l\\u1ec5 t\\u00e2n\\/concierge t\\u1eadn t\\u00e2m<\\/strong> c\\u1ee7a ch\\u00fang t\\u00f4i lu\\u00f4n s\\u1eb5n s\\u00e0ng cung c\\u1ea5p th\\u00f4ng tin chi ti\\u1ebft v\\u00e0 h\\u1ed7 tr\\u1ee3 b\\u1ea1n \\u0111\\u1eb7t d\\u1ecbch v\\u1ee5.<\\/p>\",\"language\":\"vi\",\"status\":\"published\",\"submitter\":\"save\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 3, 'ID: 3', 'primary', '2026-03-15 21:05:07', '2026-03-15 21:05:07'),
(467, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"2\",\"question\":\"Kh\\u00e1ch s\\u1ea1n c\\u00f3 nh\\u1eefng l\\u1ef1a ch\\u1ecdn \\u1ea9m th\\u1ef1c n\\u00e0o?\",\"answer\":\"<p>H\\u00e3y t\\u1eadn h\\u01b0\\u1edfng <strong data-start=\\\"40\\\" data-end=\\\"75\\\">h\\u00e0nh tr\\u00ecnh \\u1ea9m th\\u1ef1c \\u0111\\u1ea7y c\\u1ea3m h\\u1ee9ng<\\/strong> t\\u1ea1i khu ngh\\u1ec9 d\\u01b0\\u1ee1ng c\\u1ee7a ch\\u00fang t\\u00f4i v\\u1edbi nhi\\u1ec1u l\\u1ef1a ch\\u1ecdn \\u0103n u\\u1ed1ng tinh t\\u1ebf. T\\u1eeb nh\\u1eefng m\\u00f3n \\u0103n \\u0111\\u1ecba ph\\u01b0\\u01a1ng v\\u00e0 qu\\u1ed1c t\\u1ebf \\u0111\\u01b0\\u1ee3c ch\\u1ebf bi\\u1ebfn c\\u00f4ng phu, \\u0111\\u1ebfn c\\u00e1c <strong data-start=\\\"215\\\" data-end=\\\"243\\\">nh\\u00e0 h\\u00e0ng \\u0111\\u1eb7c s\\u1ea3n h\\u1ea5p d\\u1eabn<\\/strong> v\\u00e0 <strong data-start=\\\"247\\\" data-end=\\\"267\\\">qu\\u1ea7y bar \\u1ea5m c\\u00fang<\\/strong>, m\\u1ed7i tr\\u1ea3i nghi\\u1ec7m \\u1ea9m th\\u1ef1c \\u0111\\u1ec1u h\\u1ee9a h\\u1eb9n \\u0111\\u00e1nh th\\u1ee9c v\\u1ecb gi\\u00e1c c\\u1ee7a b\\u1ea1n v\\u00e0 n\\u00e2ng t\\u1ea7m k\\u1ef3 ngh\\u1ec9 c\\u1ee7a b\\u1ea1n l\\u00ean m\\u1ed9t \\u0111\\u1eb3ng c\\u1ea5p th\\u01b0\\u1edfng th\\u1ee9c \\u1ea9m th\\u1ef1c m\\u1edbi.<\\/p>\",\"language\":\"vi\",\"status\":\"published\",\"submitter\":\"save\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 4, 'ID: 4', 'primary', '2026-03-15 21:05:38', '2026-03-15 21:05:38'),
(468, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"2\",\"question\":\"T\\u1ea1i kh\\u00e1ch s\\u1ea1n\\/khu ngh\\u1ec9 d\\u01b0\\u1ee1ng c\\u00f3 spa v\\u00e0 trung t\\u00e2m ch\\u0103m s\\u00f3c s\\u1ee9c kh\\u1ecfe kh\\u00f4ng?\",\"answer\":\"<p>H\\u00e3y t\\u1eadn h\\u01b0\\u1edfng <strong data-start=\\\"40\\\" data-end=\\\"83\\\">tr\\u1ea3i nghi\\u1ec7m ch\\u0103m s\\u00f3c s\\u1ee9c kh\\u1ecfe to\\u00e0n di\\u1ec7n<\\/strong> t\\u1ea1i <strong data-start=\\\"88\\\" data-end=\\\"128\\\">spa v\\u00e0 trung t\\u00e2m wellness sang tr\\u1ecdng<\\/strong> ngay trong khu\\u00f4n vi\\u00ean c\\u1ee7a ch\\u00fang t\\u00f4i. \\u0110\\u1eafm m\\u00ecnh trong m\\u1ed9t kh\\u00f4ng gian <strong data-start=\\\"196\\\" data-end=\\\"230\\\">th\\u01b0 th\\u00e1i v\\u00e0 t\\u00e1i t\\u1ea1o n\\u0103ng l\\u01b0\\u1ee3ng<\\/strong> v\\u1edbi \\u0111a d\\u1ea1ng c\\u00e1c li\\u1ec7u tr\\u00ecnh, ph\\u01b0\\u01a1ng ph\\u00e1p tr\\u1ecb li\\u1ec7u v\\u00e0 h\\u1ec7 th\\u1ed1ng ti\\u1ec7n nghi hi\\u1ec7n \\u0111\\u1ea1i, \\u0111\\u01b0\\u1ee3c thi\\u1ebft k\\u1ebf \\u0111\\u1ec3 ch\\u0103m s\\u00f3c <strong data-start=\\\"338\\\" data-end=\\\"370\\\">c\\u01a1 th\\u1ec3, t\\u00e2m tr\\u00ed v\\u00e0 tinh th\\u1ea7n<\\/strong> c\\u1ee7a b\\u1ea1n.<\\/p>\",\"language\":\"vi\",\"status\":\"published\",\"submitter\":\"save\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 5, 'ID: 5', 'primary', '2026-03-15 21:06:09', '2026-03-15 21:06:09'),
(469, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"2\",\"question\":\"B\\u1ea1n c\\u00f3 c\\u00e1c ho\\u1ea1t \\u0111\\u1ed9ng ph\\u00f9 h\\u1ee3p cho gia \\u0111\\u00ecnh kh\\u00f4ng?\",\"answer\":\"<p>C\\u00e1c gia \\u0111\\u00ecnh lu\\u00f4n \\u0111\\u01b0\\u1ee3c <strong data-start=\\\"49\\\" data-end=\\\"72\\\">ch\\u00e0o \\u0111\\u00f3n n\\u1ed3ng nhi\\u1ec7t<\\/strong> t\\u1ea1i khu ngh\\u1ec9 d\\u01b0\\u1ee1ng c\\u1ee7a ch\\u00fang t\\u00f4i, n\\u01a1i ch\\u00fang t\\u00f4i \\u0111\\u00e3 <strong data-start=\\\"124\\\" data-end=\\\"197\\\">t\\u1eadn t\\u00e2m chu\\u1ea9n b\\u1ecb nhi\\u1ec1u ti\\u1ec7n nghi v\\u00e0 ho\\u1ea1t \\u0111\\u1ed9ng th\\u00e2n thi\\u1ec7n v\\u1edbi gia \\u0111\\u00ecnh<\\/strong>. T\\u1eeb <strong data-start=\\\"202\\\" data-end=\\\"232\\\">c\\u00e2u l\\u1ea1c b\\u1ed9 d\\u00e0nh cho tr\\u1ebb em<\\/strong>, <strong data-start=\\\"234\\\" data-end=\\\"253\\\">h\\u1ed3 b\\u01a1i gia \\u0111\\u00ecnh<\\/strong>, \\u0111\\u1ebfn nhi\\u1ec1u ho\\u1ea1t \\u0111\\u1ed9ng gi\\u1ea3i tr\\u00ed h\\u1ea5p d\\u1eabn kh\\u00e1c, ch\\u00fang t\\u00f4i mang \\u0111\\u1ebfn m\\u1ed9t k\\u1ef3 ngh\\u1ec9 <strong data-start=\\\"329\\\" data-end=\\\"378\\\">h\\u00e0i h\\u00f2a v\\u00e0 th\\u00fa v\\u1ecb cho du kh\\u00e1ch \\u1edf m\\u1ecdi l\\u1ee9a tu\\u1ed5i<\\/strong>.<\\/p>\",\"language\":\"vi\",\"status\":\"published\",\"submitter\":\"save\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 6, 'ID: 6', 'primary', '2026-03-15 21:06:44', '2026-03-15 21:06:44'),
(470, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"3\",\"question\":\"T\\u00f4i c\\u00f3 th\\u1ec3 s\\u1eafp x\\u1ebfp c\\u00e1c y\\u00eau c\\u1ea7u \\u0111\\u1eb7c bi\\u1ec7t t\\u1ea1i khu ngh\\u1ec9 d\\u01b0\\u1ee1ng nh\\u01b0 th\\u1ebf n\\u00e0o?\",\"answer\":\"<p data-start=\\\"26\\\" data-end=\\\"332\\\">H\\u00e3y <strong data-start=\\\"30\\\" data-end=\\\"87\\\">t\\u00f4n vinh nh\\u1eefng kho\\u1ea3nh kh\\u1eafc qu\\u00fd gi\\u00e1 nh\\u1ea5t c\\u1ee7a cu\\u1ed9c s\\u1ed1ng<\\/strong> trong kh\\u00f4ng gian <strong data-start=\\\"105\\\" data-end=\\\"139\\\">sang tr\\u1ecdng v\\u00e0 tinh t\\u1ebf b\\u1eadc nh\\u1ea5t<\\/strong>. \\u0110\\u1ed9i ng\\u0169 <strong data-start=\\\"149\\\" data-end=\\\"182\\\">t\\u1ed5 ch\\u1ee9c s\\u1ef1 ki\\u1ec7n chuy\\u00ean nghi\\u1ec7p<\\/strong> c\\u1ee7a ch\\u00fang t\\u00f4i lu\\u00f4n t\\u1eadn t\\u00e2m l\\u00ean k\\u1ebf ho\\u1ea1ch cho nh\\u1eefng bu\\u1ed5i l\\u1ec5 tr\\u1ecdn v\\u1eb9n v\\u00e0 \\u0111\\u00e1ng nh\\u1edb, \\u0111\\u1ea3m b\\u1ea3o m\\u1ecdi chi ti\\u1ebft \\u0111\\u1ec1u \\u0111\\u01b0\\u1ee3c thi\\u1ebft k\\u1ebf theo \\u0111\\u00fang mong mu\\u1ed1n c\\u1ee7a b\\u1ea1n.<\\/p><p data-start=\\\"334\\\" data-end=\\\"459\\\" data-is-last-node=\\\"\\\" data-is-only-node=\\\"\\\">H\\u00e3y <strong data-start=\\\"338\\\" data-end=\\\"369\\\">li\\u00ean h\\u1ec7 v\\u1edbi b\\u1ed9 ph\\u1eadn s\\u1ef1 ki\\u1ec7n<\\/strong> c\\u1ee7a ch\\u00fang t\\u00f4i \\u0111\\u1ec3 b\\u1eaft \\u0111\\u1ea7u h\\u00e0nh tr\\u00ecnh t\\u1ea1o n\\u00ean nh\\u1eefng kho\\u1ea3nh kh\\u1eafc \\u0111\\u1eb7c bi\\u1ec7t v\\u00e0 \\u0111\\u00e1ng nh\\u1edb.<\\/p>\",\"language\":\"vi\",\"status\":\"published\",\"submitter\":\"save\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 7, 'ID: 7', 'primary', '2026-03-15 21:07:18', '2026-03-15 21:07:18'),
(471, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"4\",\"question\":\"B\\u1ea1n c\\u00f3 nh\\u1eefng bi\\u1ec7n ph\\u00e1p an to\\u00e0n n\\u00e0o d\\u00e0nh cho kh\\u00e1ch l\\u01b0u tr\\u00fa?\",\"answer\":\"<p data-start=\\\"26\\\" data-end=\\\"247\\\"><strong data-start=\\\"26\\\" data-end=\\\"100\\\">S\\u1ee9c kh\\u1ecfe v\\u00e0 s\\u1ef1 an to\\u00e0n c\\u1ee7a b\\u1ea1n l\\u00e0 m\\u1ed1i quan t\\u00e2m h\\u00e0ng \\u0111\\u1ea7u c\\u1ee7a ch\\u00fang t\\u00f4i.<\\/strong> Ch\\u00fang t\\u00f4i \\u0111\\u00e3 tri\\u1ec3n khai c\\u00e1c <strong data-start=\\\"129\\\" data-end=\\\"177\\\">quy tr\\u00ecnh nghi\\u00eam ng\\u1eb7t v\\u1ec1 s\\u1ee9c kh\\u1ecfe v\\u00e0 an to\\u00e0n<\\/strong> nh\\u1eb1m \\u0111\\u1ea3m b\\u1ea3o m\\u1ed9t m\\u00f4i tr\\u01b0\\u1eddng an to\\u00e0n v\\u00e0 tho\\u1ea3i m\\u00e1i cho t\\u1ea5t c\\u1ea3 du kh\\u00e1ch.<\\/p><p data-start=\\\"249\\\" data-end=\\\"454\\\" data-is-last-node=\\\"\\\" data-is-only-node=\\\"\\\">C\\u00e1c bi\\u1ec7n ph\\u00e1p n\\u00e0y bao g\\u1ed3m <strong data-start=\\\"275\\\" data-end=\\\"325\\\">quy tr\\u00ecnh v\\u1ec7 sinh v\\u00e0 kh\\u1eed tr\\u00f9ng \\u0111\\u01b0\\u1ee3c t\\u0103ng c\\u01b0\\u1eddng<\\/strong>, <strong data-start=\\\"327\\\" data-end=\\\"362\\\">c\\u00e1c h\\u01b0\\u1edbng d\\u1eabn gi\\u00e3n c\\u00e1ch ph\\u00f9 h\\u1ee3p<\\/strong>, c\\u00f9ng v\\u1edbi <strong data-start=\\\"373\\\" data-end=\\\"449\\\">cam k\\u1ebft duy tr\\u00ec ti\\u00eau chu\\u1ea9n v\\u1ec7 sinh cao nh\\u1ea5t trong to\\u00e0n b\\u1ed9 khu ngh\\u1ec9 d\\u01b0\\u1ee1ng<\\/strong>.<\\/p>\",\"language\":\"vi\",\"status\":\"published\",\"submitter\":\"save\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 8, 'ID: 8', 'primary', '2026-03-15 21:10:45', '2026-03-15 21:10:45'),
(472, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"1\",\"question\":\"T\\u00f4i c\\u00f3 th\\u1ec3 h\\u1ee7y ho\\u1eb7c thay \\u0111\\u1ed5i \\u0111\\u1eb7t ph\\u00f2ng c\\u1ee7a m\\u00ecnh kh\\u00f4ng?\",\"answer\":\"<p data-start=\\\"26\\\" data-end=\\\"349\\\">Ch\\u00ednh s\\u00e1ch \\u0111\\u1eb7t ph\\u00f2ng c\\u1ee7a ch\\u00fang t\\u00f4i <strong data-start=\\\"61\\\" data-end=\\\"133\\\">c\\u00f3 th\\u1ec3 kh\\u00e1c nhau t\\u00f9y theo lo\\u1ea1i gi\\u00e1 v\\u00e0 c\\u00e1c \\u0111i\\u1ec1u ki\\u1ec7n \\u0111\\u1eb7t ph\\u00f2ng c\\u1ee5 th\\u1ec3<\\/strong>. Ch\\u00fang t\\u00f4i khuy\\u1ebfn kh\\u00edch b\\u1ea1n <strong data-start=\\\"162\\\" data-end=\\\"225\\\">xem l\\u1ea1i c\\u00e1c \\u0111i\\u1ec1u kho\\u1ea3n v\\u00e0 chi ti\\u1ebft trong \\u0111\\u1eb7t ph\\u00f2ng c\\u1ee7a m\\u00ecnh<\\/strong>, ho\\u1eb7c <strong data-start=\\\"232\\\" data-end=\\\"279\\\">li\\u00ean h\\u1ec7 v\\u1edbi \\u0111\\u1ed9i ng\\u0169 \\u0111\\u1eb7t ph\\u00f2ng c\\u1ee7a ch\\u00fang t\\u00f4i<\\/strong> \\u0111\\u1ec3 \\u0111\\u01b0\\u1ee3c h\\u1ed7 tr\\u1ee3 c\\u00e1 nh\\u00e2n h\\u00f3a v\\u1ec1 vi\\u1ec7c <strong data-start=\\\"315\\\" data-end=\\\"346\\\">h\\u1ee7y ho\\u1eb7c thay \\u0111\\u1ed5i \\u0111\\u1eb7t ph\\u00f2ng<\\/strong>.<\\/p><p data-start=\\\"351\\\" data-end=\\\"431\\\" data-is-last-node=\\\"\\\" data-is-only-node=\\\"\\\"><strong data-start=\\\"351\\\" data-end=\\\"427\\\">S\\u1ef1 tho\\u1ea3i m\\u00e1i v\\u00e0 h\\u00e0i l\\u00f2ng c\\u1ee7a b\\u1ea1n lu\\u00f4n l\\u00e0 \\u01b0u ti\\u00ean h\\u00e0ng \\u0111\\u1ea7u c\\u1ee7a ch\\u00fang t\\u00f4i.<\\/strong><\\/p>\",\"language\":\"vi\",\"status\":\"published\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 9, 'ID: 9', 'primary', '2026-03-15 21:21:12', '2026-03-15 21:21:12'),
(473, 1, 'Botble\\ACL\\Models\\User', 'faq', '{\"category_id\":\"1\",\"question\":\"T\\u00f4i c\\u00f3 th\\u1ec3 h\\u1ee7y ho\\u1eb7c thay \\u0111\\u1ed5i \\u0111\\u1eb7t ph\\u00f2ng c\\u1ee7a m\\u00ecnh kh\\u00f4ng?\",\"answer\":\"<p>Ch\\u00ednh s\\u00e1ch \\u0111\\u1eb7t ph\\u00f2ng c\\u1ee7a ch\\u00fang t\\u00f4i <strong>c\\u00f3 th\\u1ec3 kh\\u00e1c nhau t\\u00f9y theo lo\\u1ea1i gi\\u00e1 v\\u00e0 c\\u00e1c \\u0111i\\u1ec1u ki\\u1ec7n \\u0111\\u1eb7t ph\\u00f2ng c\\u1ee5 th\\u1ec3<\\/strong>. Ch\\u00fang t\\u00f4i khuy\\u1ebfn kh\\u00edch b\\u1ea1n <strong>xem l\\u1ea1i c\\u00e1c \\u0111i\\u1ec1u kho\\u1ea3n v\\u00e0 chi ti\\u1ebft trong \\u0111\\u1eb7t ph\\u00f2ng c\\u1ee7a m\\u00ecnh<\\/strong>, ho\\u1eb7c <strong>li\\u00ean h\\u1ec7 v\\u1edbi \\u0111\\u1ed9i ng\\u0169 \\u0111\\u1eb7t ph\\u00f2ng c\\u1ee7a ch\\u00fang t\\u00f4i<\\/strong> \\u0111\\u1ec3 \\u0111\\u01b0\\u1ee3c h\\u1ed7 tr\\u1ee3 c\\u00e1 nh\\u00e2n h\\u00f3a v\\u1ec1 vi\\u1ec7c <strong>h\\u1ee7y ho\\u1eb7c thay \\u0111\\u1ed5i \\u0111\\u1eb7t ph\\u00f2ng<\\/strong>.<\\/p><p><strong>S\\u1ef1 tho\\u1ea3i m\\u00e1i v\\u00e0 h\\u00e0i l\\u00f2ng c\\u1ee7a b\\u1ea1n lu\\u00f4n l\\u00e0 \\u01b0u ti\\u00ean h\\u00e0ng \\u0111\\u1ea7u c\\u1ee7a ch\\u00fang t\\u00f4i.<\\/strong><\\/p>\",\"language\":\"vi\",\"status\":\"published\",\"submitter\":\"save\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', '203.210.138.33', 1, 'Botble\\ACL\\Models\\User', 9, 'ID: 9', 'primary', '2026-03-15 21:21:16', '2026-03-15 21:21:16'),
