(483, 1, 'Botble\\ACL\\Models\\User', '', '{\"question\":\"Can I cancel or modify my reservation?\",\"answer\":\"<div class=\\\"text-base my-auto mx-auto pt-12 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm\\/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg\\/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\\\"><div class=\\\"[--thread-content-max-width:40rem] @w-lg\\/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group\\/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col\\\" tabindex=\\\"-1\\\"><div class=\\\"flex max-w-full flex-col gap-4 grow\\\"><div class=\\\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\\\" data-message-author-role=\\\"user\\\" data-message-id=\\\"d83141db-4749-4c5a-ae56-f5ebebc57ead\\\" dir=\\\"auto\\\"><div class=\\\"flex w-full flex-col gap-1 empty:hidden items-end rtl:items-start\\\"><div class=\\\"user-message-bubble-color corner-superellipse\\/0.98 relative rounded-[22px] px-4 py-2.5 leading-6 max-w-(--user-chat-width,70%)\\\"><div class=\\\"whitespace-pre-wrap\\\">Our reservation policies vary based on the rate type and specific booking conditions. We kindly advise reviewing the terms and details of your reservation or reaching out to our dedicated reservations team for personalized assistance regarding cancellations or modifications. Your comfort and satisfaction remain our utmost priority.<\\/div><\\/div><\\/div><\\/div><\\/div><div class=\\\"z-0 flex justify-end\\\">&nbsp;<\\/div><\\/div><\\/div>\",\"model\":\"Botble\\\\Faq\\\\Models\\\\Faq\",\"form\":\"Botble\\\\Faq\\\\Forms\\\\FaqForm\",\"submitter\":\"save\",\"language\":\"en_US\",\"ref_lang\":\"en_US\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537