(548, 1, 'Botble\\ACL\\Models\\User', 'post', '{\"name\":\"Ph\\u00f2ng S ki\\u1ec3u Nh\\u1eadt v\\u1edbi b\\u1ed3n t\\u1eafm ngo\\u00e0i tr\\u1eddi\",\"model\":\"Botble\\\\Blog\\\\Models\\\\Post\",\"slug\":\"phong-s-kieu-nhat-voi-bon-tam-ngoai-troi\",\"slug_id\":\"0\",\"is_slug_editable\":\"1\",\"description\":null,\"is_featured\":\"0\",\"content\":\"<p>Ph\\u00f2ng ki\\u1ec3u Nh\\u1eadt v\\u1edbi b\\u1ed3n t\\u1eafm ngo\\u00e0i tr\\u1eddi (c\\u1ee1 S)<br>\\u0110\\u00e2y l\\u00e0 ph\\u00f2ng b\\u00e1n \\u0111\\u1eb7c bi\\u1ec7t v\\u1edbi ph\\u00f2ng ng\\u1ee7 ki\\u1ec3u Nh\\u1eadt r\\u1ed9ng r\\u00e3i, ph\\u00f2ng li\\u1ec1n k\\u1ec1 v\\u00e0 b\\u1ed3n t\\u1eafm ngo\\u00e0i tr\\u1eddi ri\\u00eang. [B\\u1ed1 c\\u1ee5c]<br>Ph\\u00f2ng ng\\u1ee7 ki\\u1ec3u Nh\\u1eadt 12,5 chi\\u1ebfu tatami + ph\\u00f2ng li\\u1ec1n k\\u1ec1 8 chi\\u1ebfu tatami + hi\\u00ean r\\u1ed9ng +<br>B\\u1ed3n t\\u1eafm ngo\\u00e0i tr\\u1eddi ri\\u00eang v\\u1edbi n\\u01b0\\u1edbc su\\u1ed1i n\\u00f3ng ch\\u1ea3y t\\u1ef1 do<br>C\\u00f3 8 b\\u1eadc thang d\\u1eabn l\\u00ean ph\\u00f2ng.<\\/p><figure class=\\\"image\\\"><img style=\\\"aspect-ratio:1040\\/600;\\\" src=\\\"https:\\/\\/www.senjyuan.jp\\/wp\\/wp-content\\/uploads\\/2017\\/07\\/a314c3997cd0dab285e9dab2d36e70bd-1040x600.jpg\\\" alt=\\\"\\u9732\\u5929\\u98a8\\u5442\\u4ed8\\u3000\\u548c\\u5ba4S\\\" width=\\\"1040\\\" height=\\\"600\\\"><\\/figure><figure class=\\\"image\\\"><img style=\\\"aspect-ratio:1040\\/600;\\\" src=\\\"https:\\/\\/www.senjyuan.jp\\/wp\\/wp-content\\/uploads\\/2017\\/07\\/58ed1a1cdf57d4a7a2943e3334f5c030-1040x600.jpg\\\" alt=\\\"\\u9732\\u5929\\u98a8\\u5442\\u4ed8\\u3000\\u548c\\u5ba4S\\\" width=\\\"1040\\\" height=\\\"600\\\"><\\/figure>\",\"gallery\":null,\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"status\":\"published\",\"categories\":[\"7\"],\"image\":\"room\\/58ed1a1cdf57d4a7a2943e3334f5c030-1040x600.jpg\",\"tag\":null,\"submitter\":\"apply\"}', 'create