(572, 1, 'Botble\\ACL\\Models\\User', 'post', '{\"name\":\"Nh\\u00e0 t\\u1eafm c\\u00f4ng c\\u1ed9ng l\\u1edbn Ichinokura\",\"model\":\"Botble\\\\Blog\\\\Models\\\\Post\",\"slug\":\"nha-tam-cong-cong-lon-ichinokura\",\"slug_id\":\"0\",\"is_slug_editable\":\"1\",\"description\":null,\"is_featured\":\"0\",\"content\":\"<p>Ph\\u00f2ng x\\u00f4ng h\\u01a1i kh\\u00f4 v\\u1edbi t\\u01b0\\u1eddng l\\u00e0m b\\u1eb1ng than Binchotan, mang l\\u1ea1i hi\\u1ec7u qu\\u1ea3 c\\u00e1ch nhi\\u1ec7t v\\u01b0\\u1ee3t tr\\u1ed9i.<\\/p><p>B\\u1ea1n c\\u00f3 th\\u1ec3 l\\u1ef1a ch\\u1ecdn nhi\\u1ec7t \\u0111\\u1ed9 \\u01b0a th\\u00edch, t\\u1eeb 70\\u00b0C \\u1edf t\\u1ea7ng d\\u01b0\\u1edbi \\u0111\\u1ebfn 90\\u00b0C \\u1edf t\\u1ea7ng tr\\u00ean.<\\/p><p>Ngo\\u00e0i ra c\\u00f2n c\\u00f3 khu v\\u1ef1c th\\u01b0 gi\\u00e3n c\\u1ea1nh c\\u1eeda s\\u1ed5, n\\u01a1i b\\u1ea1n c\\u00f3 th\\u1ec3 th\\u01b0 gi\\u00e3n v\\u00e0 ng\\u1eafm nh\\u00ecn khung c\\u1ea3nh xanh t\\u01b0\\u01a1i b\\u00ean ngo\\u00e0i.<\\/p><figure class=\\\"image\\\"><img style=\\\"aspect-ratio:968\\/620;\\\" src=\\\"https:\\/\\/www.senjyuan.jp\\/wp\\/wp-content\\/uploads\\/2017\\/07\\/C03A2159-968x620.jpg\\\" alt=\\\"\\u5927\\u6d74\\u5834 \\u4e00\\u306e\\u8535\\\" width=\\\"968\\\" height=\\\"620\\\"><\\/figure><p><img src=\\\"https:\\/\\/www.senjyuan.jp\\/wp\\/wp-content\\/uploads\\/2017\\/07\\/C03A2144-464x297.jpg\\\" alt=\\\"\\u5927\\u6d74\\u5834 \\u4e00\\u306e\\u8535\\\" width=\\\"464\\\" height=\\\"297\\\"><img src=\\\"https:\\/\\/www.senjyuan.jp\\/wp\\/wp-content\\/uploads\\/2024\\/02\\/00.jpg\\\" alt=\\\"\\u5927\\u6d74\\u5834 \\u4e00\\u306e\\u8535\\\" width=\\\"464\\\" height=\\\"297\\\"><\\/p>\",\"gallery\":null,\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"status\":\"published\",\"categories\":[\"9\"],\"image\":\"suoi-nuoc-nong\\/00.jpg\",\"tag\":null,\"submitter\":\"apply\"}', 'created', 'Mozilla/5.0 (Macintosh; Intel Mac OS X 10_15_7) AppleWebKit