(616, 1, 'Botble\\ACL\\Models\\User', 'post', '{\"name\":\"Ph\\u00f2ng theo phong c\\u00e1ch Nh\\u1eadt B\\u1ea3n - ph\\u01b0\\u01a1ng T\\u00e2y v\\u1edbi b\\u1ed3n t\\u1eafm ngo\\u00e0i tr\\u1eddi.\",\"model\":\"Botble\\\\Blog\\\\Models\\\\Post\",\"slug\":\"phong-theo-phong-cach-nhat-ban-phuong-tay-voi-bon-tam-ngoai-troi\",\"slug_id\":\"93\",\"is_slug_editable\":\"1\",\"description\":null,\"is_featured\":\"0\",\"content\":\"<shortcode>[simple-slider key=\\\"home-silde\\\"][\\/simple-slider]<\\/shortcode><p>Ph\\u00f2ng ki\\u1ec3u Nh\\u1eadt - ph\\u01b0\\u01a1ng T\\u00e2y v\\u1edbi b\\u1ed3n t\\u1eafm ngo\\u00e0i tr\\u1eddi<br>Ph\\u00f2ng n\\u00e0y c\\u00f3 m\\u1ed9t ph\\u00f2ng ki\\u1ec3u Nh\\u1eadt v\\u00e0 m\\u1ed9t ph\\u00f2ng ng\\u1ee7 \\u0111\\u00f4i r\\u1ed9ng r\\u00e3i, c\\u00f9ng v\\u1edbi m\\u1ed9t b\\u1ed3n t\\u1eafm ngo\\u00e0i tr\\u1eddi. T\\u1eadn h\\u01b0\\u1edfng thi\\u00ean nhi\\u00ean trong l\\u00e0nh t\\u1eeb nh\\u1eefng c\\u1eeda s\\u1ed5 l\\u1edbn v\\u00e0 b\\u1ed3n t\\u1eafm ngo\\u00e0i tr\\u1eddi. [B\\u1ed1 c\\u1ee5c]<br>Ph\\u00f2ng ki\\u1ec3u ph\\u01b0\\u01a1ng T\\u00e2y (40 m\\u00b2) + Ph\\u00f2ng ki\\u1ec3u Nh\\u1eadt (8 chi\\u1ebfu tatami) +<br>B\\u1ed3n t\\u1eafm ngo\\u00e0i tr\\u1eddi v\\u1edbi n\\u01b0\\u1edbc su\\u1ed1i n\\u00f3ng ch\\u1ea3y t\\u1ef1 do trong ph\\u00f2ng.<\\/p><figure class=\\\"image\\\"><img style=\\\"aspect-ratio:1040\\/600;\\\" src=\\\"https:\\/\\/www.senjyuan.jp\\/wp\\/wp-content\\/uploads\\/2017\\/07\\/C03A0039-1040x600.jpg\\\" alt=\\\"\\u9732\\u5929\\u98a8\\u5442\\u4ed8\\u3000\\u548c\\u6d0b\\u5ba4\\\" width=\\\"1040\\\" height=\\\"600\\\"><\\/figure><figure class=\\\"image\\\"><img style=\\\"aspect-ratio:1040\\/600;\\\" src=\\\"https:\\/\\/www.senjyuan.jp\\/wp\\/wp-content\\/uploads\\/2017\\/07\\/C03A2315-1040x600.jpg\\\" alt=\\\"\\u9732\\u5929\\u98a8\\u5442\\u4ed8\\u3000\\u548c\\u6d0b\\u5ba4\\\" width=\\\"1040\\\" height=\\\"600\\\"><\\/figure>\",\"gallery\":null,\"seo_meta\":{\"seo_title\":null,\"seo_description