INSERT INTO `faqs` (`id`, `question`, `answer`, `category_id`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Điều gì khiến Luxury Hotel khác biệt so với những nơi khác?', '<p>Khách sạn của chúng tôi nổi bật với <strong>vị trí ven biển đắc địa</strong>, thiết kế cuốn hút hài hòa với thiên nhiên, <strong>dịch vụ hoàn hảo</strong> luôn tận tâm đáp ứng mọi nhu cầu của du khách, cùng <strong>hệ thống tiện nghi đẳng cấp thế giới</strong> mang đến sự sang trọng và tinh tế vượt trội.</p>', 1, 'published', '2025-06-10 10:38:19', '2026-03-15 21:04:00'),
(2, 'Khách sạn của bạn có cho phép mang theo thú cưng không?', '<p>Rất tiếc, để duy trì <strong>không gian yên tĩnh và sang trọng</strong> cho tất cả khách lưu trú, chúng tôi xin thông báo rằng <strong>khách sạn không cho phép mang theo thú cưng</strong> trong các phòng nghỉ được thiết kế tinh tế cũng như tại các khu vực chung được bố trí cẩn thận của khách sạn.</p>', 2, 'published', '2025-06-10 10:38:19', '2026-03-15 21:04:32'),
(3, 'Khách sạn có dịch vụ đưa đón sân bay không?', '<p>Tất nhiên! Để mang lại sự thuận tiện cho quý khách, chúng tôi cung cấp <strong>dịch vụ đưa đón sân bay riêng</strong>, có thể được sắp xếp trước. Đội ngũ <strong>lễ tân/concierge tận tâm</strong> của chúng tôi luôn sẵn sàng cung cấp thông tin chi tiết và hỗ trợ bạn đặt dịch vụ.</p>', 1, 'published', '2025-06-10 10:38:19', '2026-03-15 21:05:07'),
(4, 'Khách sạn có những lựa chọn ẩm thực nào?', '<p>Hãy tận hưởng <strong>hành trình ẩm thực đầy cảm hứng</strong> tại khu nghỉ dưỡng của chúng tôi với nhiều lựa chọn ăn uống tinh tế. Từ những món ăn địa phương và quốc tế được chế biến công phu, đến các <strong>nhà hàng đặc sản hấp dẫn</strong> và <strong>quầy bar ấm cúng</strong>, mỗi trải nghiệm ẩm thực đều hứa hẹn đánh thức vị giác của bạn và nâng tầm kỳ nghỉ của bạn lên một đẳng cấp thưởng thức ẩm thực mới.</p>', 2, 'published', '2025-06-10 10:38:19', '2026-03-15 21:05:38'),
(5, 'Tại khách sạn/khu nghỉ dưỡng có spa và trung tâm chăm sóc sức khỏe không?', '<p>Hãy tận hưởng <strong>trải nghiệm chăm sóc sức khỏe toàn diện</strong> tại <strong>spa và trung tâm wellness sang trọng</strong> ngay trong khuôn viên của chúng tôi. Đắm mình trong một không gian <strong>thư thái và tái tạo năng lượng</strong> với đa dạng các liệu trình, phương pháp trị liệu và hệ thống tiện nghi hiện đại, được thiết kế để chăm sóc <strong>cơ thể, tâm trí và tinh thần</strong> của bạn.</p>', 2, 'published', '2025-06-10 10:38:19', '2026-03-15 21:06:09'),
(6, 'Bạn có các hoạt động phù hợp cho gia đình không?', '<p>Các gia đình luôn được <strong>chào đón nồng nhiệt</strong> tại khu nghỉ dưỡng của chúng tôi, nơi chúng tôi đã <strong>tận tâm chuẩn bị nhiều tiện nghi và hoạt động thân thiện với gia đình</strong>. Từ <strong>câu lạc bộ dành cho trẻ em</strong>, <strong>hồ bơi gia đình</strong>, đến nhiều hoạt động giải trí hấp dẫn khác, chúng tôi mang đến một kỳ nghỉ <strong>hài hòa và thú vị cho du khách ở mọi lứa tuổi</strong>.</p>', 2, 'published', '2025-06-10 10:38:19', '2026-03-15 21:06:44'),
(7, 'Tôi có thể sắp xếp các yêu cầu đặc biệt tại khu nghỉ dưỡng như thế nào?', '<p>Hãy <strong>tôn vinh những khoảnh khắc quý giá nhất của cuộc sống</strong> trong không gian <strong>sang trọng và tinh tế bậc nhất</strong>. Đội ngũ <strong>tổ chức sự kiện chuyên nghiệp</strong> của chúng tôi luôn tận tâm lên kế hoạch cho những buổi lễ trọn vẹn và đáng nhớ, đảm bảo mọi chi tiết đều được thiết kế theo đúng mong muốn của bạn.</p><p>Hãy <strong>liên hệ với bộ phận sự kiện</strong> của chúng tôi để bắt đầu hành trình tạo nên những khoảnh khắc đặc biệt và đáng nhớ.</p>', 3, 'published', '2025-06-10 10:38:19', '2026-03-15 21:07:18'),
(8, 'Bạn có những biện pháp an toàn nào dành cho khách lưu trú?', '<p><strong>Sức khỏe và sự an toàn của bạn là mối quan tâm hàng đầu của chúng tôi.</strong> Chúng tôi đã triển khai các <strong>quy trình nghiêm ngặt về sức khỏe và an toàn</strong> nhằm đảm bảo một môi trường an toàn và thoải mái cho tất cả du khách.</p><p>Các biện pháp này bao gồm <strong>quy trình vệ sinh và khử trùng được tăng cường</strong>, <strong>các hướng dẫn giãn cách phù hợp</strong>, cùng với <strong>cam kết duy trì tiêu chuẩn vệ sinh cao nhất trong toàn bộ khu nghỉ dưỡng</strong>.</p>', 4, 'published', '2025-06-10 10:38:19', '2026-03-15 21:10:45'),
(9, 'Tôi có thể hủy hoặc thay đổi đặt phòng của mình không?', '<p>Chính sách đặt phòng của chúng tôi <strong>có thể khác nhau tùy theo loại giá và các điều kiện đặt phòng cụ thể</strong>. Chúng tôi khuyến khích bạn <strong>xem lại các điều khoản và chi tiết trong đặt phòng của mình</strong>, hoặc <strong>liên hệ với đội ngũ đặt phòng của chúng tôi</strong> để được hỗ trợ cá nhân hóa về việc <strong>hủy hoặc thay đổi đặt phòng</strong>.</p><p><strong>Sự thoải mái và hài lòng của bạn luôn là ưu tiên hàng đầu của chúng tôi.</strong></p>', 1, 'published', '2025-06-10 10:38:19', '2026-03-15 21:21:16'),
(10, 'Có những hoạt động nào gần khách sạn của bạn?', '<p>Vị trí đắc địa của khách sạn chúng tôi giúp du khách <strong>dễ dàng tiếp cận nhiều điểm tham quan hấp dẫn</strong>. Bạn có thể khám phá <strong>bờ biển Adriatic tuyệt đẹp</strong>, đắm mình trong <strong>những di tích lịch sử</strong>, trải nghiệm <strong>nền văn hóa địa phương sôi động</strong>, và tham gia các <strong>chuyến tham quan đáng nhớ</strong>.</p><p>Đội ngũ <strong>concierge của chúng tôi luôn sẵn sàng hỗ trợ</strong> sắp xếp các hoạt động và chuyến đi để mang đến cho bạn trải nghiệm trọn vẹn nhất.</p>', 5, 'published', '2025-06-10 10:38:19', '2026-03-15 21:21:52');
INSERT INTO `faqs_translations` (`lang_code`, `faqs_id`, `question`, `answer`) VALUES
('en_US', 1, 'What sets Luxury Hotel apart from others area?', '<p>Our hotel stands out with its prime coastal location, captivating design that harmonizes with nature, impeccable service dedicated to fulfilling every guest’s desire, and an array of world-class amenities that redefine opulence and sophistication.</p>'),
('en_US', 2, 'Are pets allowed at your hotel?', '<p>Unfortunately, as we strive to maintain an environment of tranquility and luxury for all our guests, we regret to inform you that we do not permit pets in our elegantly appointed rooms and meticulously designed public spaces.</p>'),
('en_US', 3, 'Is there a service from airport to hotel?', '<div class=\"text-base my-auto mx-auto pt-12 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col gap-4 grow\"><div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" data-message-author-role=\"user\" data-message-id=\"305b0298-cfd3-4080-95a7-3fc182c95f14\" dir=\"auto\"><div class=\"flex w-full flex-col gap-1 empty:hidden items-end rtl:items-start\"><div class=\"user-message-bubble-color corner-superellipse/0.98 relative rounded-[22px] px-4 py-2.5 leading-6 max-w-(--user-chat-width,70%)\"><div class=\"whitespace-pre-wrap\">Absolutely! For your convenience, we offer an exclusive airport shuttle service that can be arranged in advance. Our dedicated concierge team will be delighted to provide you with detailed information and assist with reservations.</div></div></div></div></div><div class=\"z-0 flex justify-end\">&nbsp;</div></div></div>'),
('en_US', 4, 'What dining options are available at hotel?', '<div class=\"text-base my-auto mx-auto pt-12 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col gap-4 grow\"><div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" data-message-author-role=\"user\" data-message-id=\"41aee592-e94f-4a35-b8bb-f6a8f3eaf98a\" dir=\"auto\"><div class=\"flex w-full flex-col gap-1 empty:hidden items-end rtl:items-start\"><div class=\"user-message-bubble-color corner-superellipse/0.98 relative rounded-[22px] px-4 py-2.5 leading-6 max-w-(--user-chat-width,70%)\"><div class=\"whitespace-pre-wrap\">Indulge in a culinary journey at our resort with a range of exquisite dining options. From elegantly crafted local and international cuisines to delightful specialty restaurants and inviting bars, every dining experience promises to tantalize your taste buds and elevate your stay to new heights of gastronomic pleasure.</div></div></div></div></div><div class=\"z-0 flex justify-end\">&nbsp;</div></div></div>'),
('en_US', 5, 'Is there a spa and wellness center on-site?', '<div class=\"text-base my-auto mx-auto pt-12 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col gap-4 grow\"><div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" data-message-author-role=\"user\" data-message-id=\"99d55d80-4a23-4b62-9c8a-c0a0341da39a\" dir=\"auto\"><div class=\"flex w-full flex-col gap-1 empty:hidden items-end rtl:items-start\"><div class=\"user-message-bubble-color corner-superellipse/0.98 relative rounded-[22px] px-4 py-2.5 leading-6 max-w-(--user-chat-width,70%)\"><div class=\"whitespace-pre-wrap\">Embrace holistic well-being at our luxurious on-site spa and wellness center. Immerse yourself in a world of serenity and rejuvenation with a diverse selection of treatments, therapies, and state-of-the-art facilities that cater to your body, mind, and soul.</div></div></div></div></div><div class=\"z-0 flex justify-end\">&nbsp;</div></div></div>'),
('en_US', 6, 'Do you have family-friendly activities?', '<div class=\"text-base my-auto mx-auto pt-12 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col gap-4 grow\"><div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" data-message-author-role=\"user\" data-message-id=\"9dd15596-ddd6-4622-88a7-aba1533f05a7\" dir=\"auto\"><div class=\"flex w-full flex-col gap-1 empty:hidden items-end rtl:items-start\"><div class=\"user-message-bubble-color corner-superellipse/0.98 relative rounded-[22px] px-4 py-2.5 leading-6 max-w-(--user-chat-width,70%)\"><div class=\"whitespace-pre-wrap\">Families are warmly welcomed to our resort, where we have thoughtfully curated a range of family-friendly amenities and activities. From a dedicated kids’ club to a family pool and a host of engaging recreational options, we ensure a harmonious and enjoyable stay for guests of all ages.</div></div></div></div></div><div class=\"z-0 flex justify-end\">&nbsp;</div></div></div>'),
('en_US', 7, 'How can I arrange special at resort?', '<div class=\"text-base my-auto mx-auto pt-12 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col gap-4 grow\"><div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" data-message-author-role=\"user\" data-message-id=\"e85be354-63b5-4e20-a297-4db60e9f2298\" dir=\"auto\"><div class=\"flex w-full flex-col gap-1 empty:hidden items-end rtl:items-start\"><div class=\"user-message-bubble-color corner-superellipse/0.98 relative rounded-[22px] px-4 py-2.5 leading-6 max-w-(--user-chat-width,70%)\"><div class=\"whitespace-pre-wrap\">Celebrate life’s most precious moments in the epitome of luxury and elegance. Our skilled event planning team is committed to orchestrating seamless and memorable celebrations, ensuring every detail is tailored to your vision. Contact our dedicated events department to embark on a journey of crafting extraordinary moments.</div></div></div></div></div><div class=\"z-0 flex justify-end\">&nbsp;</div></div></div>'),
('en_US', 8, 'What safety measures do you have for guests?', '<div class=\"text-base my-auto mx-auto pt-12 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col gap-4 grow\"><div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" data-message-author-role=\"user\" data-message-id=\"0e73c61b-7975-4e68-964b-6aa2c1ed1b79\" dir=\"auto\"><div class=\"flex w-full flex-col gap-1 empty:hidden items-end rtl:items-start\"><div class=\"user-message-bubble-color corner-superellipse/0.98 relative rounded-[22px] px-4 py-2.5 leading-6 max-w-(--user-chat-width,70%)\"><div class=\"whitespace-pre-wrap\">Your well-being is our paramount concern. We have implemented stringent health and safety protocols to ensure a secure and comfortable environment for all our guests. These measures encompass enhanced cleaning procedures, social distancing guidelines, and a commitment to maintaining the highest standards of hygiene throughout the resort.</div></div></div></div></div><div class=\"z-0 flex justify-end\">&nbsp;</div></div></div>'),
('en_US', 9, 'Can I cancel or modify my reservation?', '<div class=\"text-base my-auto mx-auto pt-12 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col gap-4 grow\"><div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" data-message-author-role=\"user\" data-message-id=\"d83141db-4749-4c5a-ae56-f5ebebc57ead\" dir=\"auto\"><div class=\"flex w-full flex-col gap-1 empty:hidden items-end rtl:items-start\"><div class=\"user-message-bubble-color corner-superellipse/0.98 relative rounded-[22px] px-4 py-2.5 leading-6 max-w-(--user-chat-width,70%)\"><div class=\"whitespace-pre-wrap\">Our reservation policies vary based on the rate type and specific booking conditions. We kindly advise reviewing the terms and details of your reservation or reaching out to our dedicated reservations team for personalized assistance regarding cancellations or modifications. Your comfort and satisfaction remain our utmost priority.</div></div></div></div></div><div class=\"z-0 flex justify-end\">&nbsp;</div></div></div>'),
('en_US', 10, 'What activities are near your hotel?', '<div class=\"text-base my-auto mx-auto pt-12 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col gap-4 grow\"><div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" data-message-author-role=\"user\" data-message-id=\"0e82b230-6048-433a-9bdc-541d8cc63541\" dir=\"auto\"><div class=\"flex w-full flex-col gap-1 empty:hidden items-end rtl:items-start\"><div class=\"user-message-bubble-color corner-superellipse/0.98 relative rounded-[22px] px-4 py-2.5 leading-6 max-w-(--user-chat-width,70%)\"><div class=\"whitespace-pre-wrap\">Our hotel’s prime location offers easy access to a plethora of attractions. Explore the captivating Adriatic coastline, immerse yourself in historical landmarks, indulge in vibrant local culture, and embark on memorable excursions that our concierge team can readily assist in arranging.</div></div></div></div></div><div class=\"z-0 flex justify-end\">&nbsp;</div></div></div>');
