INSERT INTO `galleries` (`id`, `name`, `description`, `is_featured`, `order`, `image`, `user_id`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Room', 'Immerse yourself in the epitome of comfort and luxury within our meticulously designed rooms. Each space is a sanctuary where sophistication meets functionality. From plush furnishings to panoramic views, every detail is crafted to ensure an unparalleled stay that leaves a lasting impression.', 1, 0, 'galleries/1.png', 1, 'published', '2025-06-10 10:38:16', '2025-06-10 10:38:16'),
(2, 'Hall', 'Our event halls are more than spaces; they’re canvases for your imagination. With timeless design and versatile layouts, they’re perfect for weddings, conferences, and gatherings of all kinds. Equipped with state-of-the-art technology and impeccable service, our halls set the stage for unforgettable moments.', 1, 0, 'galleries/2.png', 1, 'published', '2025-06-10 10:38:16', '2025-06-10 10:38:16'),
(3, 'Guardian', 'Our vigilant team takes your safety and comfort seriously. With unwavering dedication, our guardians ensure every corner of our hotel is secure, clean, and welcoming. From discreet housekeeping to attentive concierge services, their commitment ensures you experience nothing but the finest in hospitality. Your peace of mind is their top priority', 1, 0, 'galleries/3.png', 1, 'published', '2025-06-10 10:38:16', '2025-06-10 10:38:16'),
(4, 'Hotel', 'Experience opulence redefined at Riorelax. Our meticulously designed rooms and suites offer breathtaking views, plush amenities, and a haven of tranquility. Immerse yourself in sumptuous comfort that sets the stage for an unforgettable stay.', 1, 0, 'galleries/4.png', 1, 'published', '2025-06-10 10:38:16', '2025-06-10 10:38:16'),
(5, 'Event Hall', 'Celebrate life’s milestones in style with our exceptional event spaces. From weddings to corporate gatherings, our dedicated team crafts experiences that leave a lasting impression. Impeccable service, state-of-the-art facilities, and a picturesque backdrop ensure your event is nothing short of extraordinary.', 1, 0, 'galleries/5.png', 1, 'published', '2025-06-10 10:38:16', '2025-06-10 10:38:16');
