INSERT INTO `ht_places` (`id`, `name`, `distance`, `description`, `content`, `image`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Nhà hàng Duplex', '1.500 m | 21 phút đi bộ', '', '<h2><strong>Khám phá các điểm tham quan gần đó</strong></h2><p>Hãy tận hưởng <strong>vẻ đẹp và hương vị của khu vực địa phương</strong>, nơi những <strong>cảnh quan tuyệt đẹp</strong> và <strong>ẩm thực hấp dẫn</strong> đang chờ đón bạn. Chúng tôi xin giới thiệu tổng quan về những <strong>địa điểm thú vị</strong> mà bạn có thể trải nghiệm trong suốt thời gian lưu trú.</p><hr><h2><strong>Thư giãn tại bãi biển</strong></h2><p>Hãy thả lỏng và tận hưởng <strong>sự yên bình của bãi biển trong lành</strong> chỉ cách khách sạn của chúng tôi vài bước chân. <strong>Bãi cát mềm mại, làn sóng dịu nhẹ và đường chân trời tuyệt đẹp</strong> tạo nên một không gian lý tưởng để bạn <strong>tái tạo năng lượng và thư giãn</strong>.</p><p>Dù bạn <strong>tắm nắng trên bãi biển</strong> hay <strong>tản bộ nhẹ nhàng dọc bờ cát</strong>, nơi đây luôn mang đến <strong>khoảnh khắc bình yên</strong> giúp bạn tạm rời xa sự bận rộn của cuộc sống hằng ngày.</p><hr><h2><strong>Thưởng thức ẩm thực tại nhà hàng hàng đầu</strong></h2><p>Hãy bắt đầu <strong>hành trình ẩm thực</strong> tại một trong những <strong>nhà hàng nổi bật của khu vực</strong>, một viên ngọc quý trong khu phố của chúng tôi.</p><p>Thưởng thức <strong>nhiều món ăn hấp dẫn</strong> được chế biến công phu bởi <strong>những đầu bếp tài năng</strong>. Từ <strong>món khai vị tinh tế</strong>, <strong>món chính đậm đà</strong> đến <strong>món tráng miệng ngọt ngào</strong>, mỗi món ăn đều là <strong>sự kết hợp hoàn hảo giữa hương vị và sự sáng tạo</strong>.</p><p>Không gian <strong>ấm cúng</strong> cùng <strong>dịch vụ chu đáo</strong> sẽ làm cho trải nghiệm ẩm thực của bạn trở nên trọn vẹn hơn.</p><hr><p>Cho dù bạn là <strong>người yêu ẩm thực</strong> hay <strong>người yêu thiên nhiên</strong>, vị trí của khách sạn chúng tôi mang đến <strong>trải nghiệm tuyệt vời từ cả hai thế giới</strong>. Hãy đắm mình trong <strong>vẻ đẹp cuốn hút của bãi biển</strong> và thưởng thức <strong>những bữa ăn đáng nhớ</strong>.</p><p>Kỳ nghỉ của bạn tại đây chắc chắn sẽ <strong>tràn đầy những kỷ niệm tuyệt vời mà bạn sẽ trân trọng trong nhiều năm tới</strong>.</p><hr><p>Đối với những ai yêu thích <strong>khám phá và phiêu lưu</strong>, một địa điểm ngắm cảnh gần đó sẽ mang đến <strong>khung cảnh ngoạn mục khiến bạn phải kinh ngạc</strong>. Sự kết hợp hài hòa giữa <strong>vẻ đẹp hùng vĩ của thiên nhiên và nét nghệ thuật độc đáo</strong> khiến nơi đây trở thành địa điểm lý tưởng để <strong>chụp những bức ảnh ấn tượng và lưu giữ kỷ niệm đáng nhớ</strong>.</p><p>Hãy <strong>đắm mình trong văn hóa địa phương</strong>, tận hưởng <strong>những điều thú vị của khu vực</strong>, và để <strong>các giác quan dẫn lối bạn khám phá những điều tuyệt vời ngay gần khách sạn</strong>.</p>', 'places/348s.jpg', 'published', '2025-06-10 10:38:11', '2026-03-11 21:13:35'),
(2, 'Quầy bar mở cửa qua đêm', '1.500 m | 21 phút đi bộ', '', '<h2><strong>Khám phá các điểm tham quan gần đó</strong></h2><p>Hãy tận hưởng <strong>vẻ đẹp và hương vị của khu vực địa phương</strong>, nơi những <strong>cảnh quan tuyệt đẹp</strong> và <strong>ẩm thực hấp dẫn</strong> đang chờ đón bạn. Chúng tôi xin giới thiệu tổng quan về những <strong>địa điểm thú vị</strong> mà bạn có thể trải nghiệm trong suốt thời gian lưu trú.</p><hr><h2><strong>Thư giãn tại bãi biển</strong></h2><p>Hãy thả lỏng và tận hưởng <strong>sự yên bình của bãi biển trong lành</strong> chỉ cách khách sạn của chúng tôi vài bước chân. <strong>Bãi cát mềm mại, làn sóng dịu nhẹ và đường chân trời tuyệt đẹp</strong> tạo nên một không gian lý tưởng để bạn <strong>tái tạo năng lượng và thư giãn</strong>.</p><p>Dù bạn <strong>tắm nắng trên bãi biển</strong> hay <strong>tản bộ nhẹ nhàng dọc bờ cát</strong>, nơi đây luôn mang đến <strong>khoảnh khắc bình yên</strong> giúp bạn tạm rời xa sự bận rộn của cuộc sống hằng ngày.</p><hr><h2><strong>Thưởng thức ẩm thực tại nhà hàng hàng đầu</strong></h2><p>Hãy bắt đầu <strong>hành trình ẩm thực</strong> tại một trong những <strong>nhà hàng nổi bật của khu vực</strong>, một viên ngọc quý trong khu phố của chúng tôi.</p><p>Thưởng thức <strong>nhiều món ăn hấp dẫn</strong> được chế biến công phu bởi <strong>những đầu bếp tài năng</strong>. Từ <strong>món khai vị tinh tế</strong>, <strong>món chính đậm đà</strong> đến <strong>món tráng miệng ngọt ngào</strong>, mỗi món ăn đều là <strong>sự kết hợp hoàn hảo giữa hương vị và sự sáng tạo</strong>.</p><p>Không gian <strong>ấm cúng</strong> cùng <strong>dịch vụ chu đáo</strong> sẽ làm cho trải nghiệm ẩm thực của bạn trở nên trọn vẹn hơn.</p><hr><p>Cho dù bạn là <strong>người yêu ẩm thực</strong> hay <strong>người yêu thiên nhiên</strong>, vị trí của khách sạn chúng tôi mang đến <strong>trải nghiệm tuyệt vời từ cả hai thế giới</strong>. Hãy đắm mình trong <strong>vẻ đẹp cuốn hút của bãi biển</strong> và thưởng thức <strong>những bữa ăn đáng nhớ</strong>.</p><p>Kỳ nghỉ của bạn tại đây chắc chắn sẽ <strong>tràn đầy những kỷ niệm tuyệt vời mà bạn sẽ trân trọng trong nhiều năm tới</strong>.</p><hr><p>Đối với những ai yêu thích <strong>khám phá và phiêu lưu</strong>, một địa điểm ngắm cảnh gần đó sẽ mang đến <strong>khung cảnh ngoạn mục khiến bạn phải kinh ngạc</strong>. Sự kết hợp hài hòa giữa <strong>vẻ đẹp hùng vĩ của thiên nhiên và nét nghệ thuật độc đáo</strong> khiến nơi đây trở thành địa điểm lý tưởng để <strong>chụp những bức ảnh ấn tượng và lưu giữ kỷ niệm đáng nhớ</strong>.</p><p>Hãy <strong>đắm mình trong văn hóa địa phương</strong>, tận hưởng <strong>những điều thú vị của khu vực</strong>, và để <strong>các giác quan dẫn lối bạn khám phá những điều tuyệt vời ngay gần khách sạn</strong>.</p>', 'places/image.jpg', 'published', '2025-06-10 10:38:11', '2026-03-11 21:15:41'),
