INSERT INTO `ht_rooms` (`id`, `name`, `description`, `content`, `is_featured`, `images`, `price`, `currency_id`, `number_of_rooms`, `number_of_beds`, `size`, `max_adults`, `max_children`, `room_category_id`, `tax_id`, `status`, `created_at`, `updated_at`, `order`) VALUES
(1, 'Senna Hilltop Pool Villa 2PN', 'Senna Hilltop Pool Villa 2 phòng ngủ là căn villa có diện tích rộng nhất và quyến rũ nhất của Avana Retreat. Cả hai phòng ngủ đều có cửa kính mở rộng ra không gian bên ngoài, nhìn ra bể bơi riêng, ruộng bậc thang và thung lũng. Villa có thiết kế trang nhã, với phòng khách và hiên tắm nắng rộng. Bên ngoài được bài trí ấn tượng với ghế sofa, gối tựa, ghế nằm và bể bơi riêng bốn mùa', NULL, 0, '{\"1\":\"rooms\\/168439421305-senna-hilltop-pool-villa-2-br-9-copy.jpg\",\"2\":\"rooms\\/168439420905-senna-hilltop-pool-villa-2-br-5.jpg\",\"3\":\"rooms\\/168439419905-senna-hilltop-pool-villa-2-br-8.jpg\",\"4\":\"rooms\\/168439419905-senna-hilltop-pool-villa-2-br-4.jpg\",\"5\":\"rooms\\/168439419905-senna-hilltop-pool-villa-2-br-3.jpg\",\"6\":\"rooms\\/168439419905-senna-hilltop-pool-villa-2-b-2.jpg\",\"7\":\"rooms\\/1722936019senna-2br.jpg\"}', 134, NULL, 2, 4, 118, 4, 4, 1, 1, 'published', '2025-06-10 10:38:06', '2026-03-11 19:36:35', 0),
(2, 'Senna Hilltop Pool Villa 1PN', 'The Senna Hilltop Pool Villa (one bedroom) is designed especially for couples seeking privacy and romance. The villa features a spacious bedroom connected to an airy living area, overlooking the terraced rice fields and the valley below. The luxurious bathroom includes both a bathtub and a separate walk-in shower, with large glass windows opening to the surrounding natural scenery.', NULL, 1, '{\"1\":\"rooms\\/168439441304-senna-hilltop-pool-villa-1-br-9.jpg\",\"2\":\"rooms\\/168144758104-senna-hilltop-pool-villa-1-br-7.jpg\",\"3\":\"rooms\\/168144758104-senna-hilltop-pool-villa-1-br-2.jpg\",\"4\":\"rooms\\/168144758004-senna-hilltop-pool-villa-1-br-5.jpg\",\"5\":\"rooms\\/168439441904-senna-hilltop-pool-villa-1-br-1.jpg\",\"6\":\"rooms\\/168439441704-senna-hilltop-pool-villa-1-br-3.jpg\"}', 171, NULL, 1, 2, 126, 2, 2, 1, 1, 'published', '2025-06-10 10:38:06', '2026-03-12 03:16:18', 0),
(3, 'Ferns Grand Mountain Suite', 'Các căn Ferns Grand Mountain Suite nằm trên triền núi, xen lẫn trong những tán cây. Đồ nội thất được chăm chút, lựa chọn kỹ lưỡng, phản ánh gu thẩm mỹ tinh tế và sang trọng. Thiết kế của Ferns đón nhiều nhất có thể ánh sáng thiên nhiên qua hệ thống cửa kính mở rộng và kéo dài từ sàn lên đến trần nhà. Ban công rộng, thoáng với ghế sofa để thoải mái thư giãn,ngắm nhìn cảnh quan xanh mướt của núi đồi', NULL, 1, '{\"1\":\"rooms\\/168179031903-ferms-grand-mountain-suite-3.jpg\",\"2\":\"rooms\\/168179031903-ferms-grand-mountain-suite-2.jpg\",\"3\":\"rooms\\/168170040701-lantana-mountain-bungalow-3-1.jpg\",\"4\":\"rooms\\/168170037901-lantana-mountain-bungalow-4-1.jpg\"}', 187, NULL, 1, 4, 186, 4, 3, 1, 1, 'published', '2025-06-10 10:38:06', '2026-03-11 19:17:50', 0),
(4, 'Lantana Mountain Bungalow 2PN', 'Các căn Lantana Mountain Bungalow 2 phòng ngủ đều có thiết kế hài hòa với thiên nhiên cùng với ban công xinh xắn nhìn ra vùng thung lũng yên tĩnh trước mắt. Đồ trang trí và nội thất được lựa chọn tỉ mỉ, hài hòa với thiết kế chung của phòng. Giống như các căn villa khác của Avana, phòng tắm của Lantana Mountain Bungalow 2 phòng ngủ có bồn tắm riêng với cửa kính rộng, trong suốt, mang lại cảm giác t', NULL, 1, '{\"1\":\"rooms\\/168439456201-lantana-mountain-bungalow-1.jpg\",\"2\":\"rooms\\/168170037901-lantana-mountain-bungalow-4.jpg\",\"3\":\"rooms\\/168170040701-lantana-mountain-bungalow-3.jpg\"}', 114, NULL, 2, 4, 130, 5, 3, 1, 1, 'published', '2025-06-10 10:38:06', '2026-03-11 19:13:16', 0),
(5, 'Bauhinia Mountain Suite', 'Bauhinia có không gian thoáng đãng, nội thất cao cấp và tiện nghi với giường đôi cỡ lớn hoặc 2 giường đơn, sofa nghỉ, và rất nhiều ánh sáng tự nhiên vào ban ngày. Ban công rộng 36m2 thích hợp để thư giãn trong điều kiện thời tiết khô ráo, được bày trí với ghế sofa rộng và bàn ăn nhỏ xinh cho hai người. Không chỉ ấn tượng bởi nội thất tinh tế, Bauhinia Mountain Suite còn chú trọng đến tính riêng tư', NULL, 0, '{\"1\":\"rooms\\/172292947302-bauhinia-moutain-suite-3.jpg\",\"2\":\"rooms\\/172292934602-bauhinia-moutain-suite-6.jpg\",\"3\":\"rooms\\/172292934602-bauhinia-moutain-suite-2.jpg\",\"4\":\"rooms\\/172292903302-bauhinia-moutain-suite-1.jpg\"}', 137, NULL, 5, 1, 127, 2, 1, 1, 1, 'published', '2025-06-10 10:38:06', '2026-03-11 19:05:19', 0);
