INSERT INTO `ht_rooms_translations` (`lang_code`, `ht_rooms_id`, `name`, `description`, `content`) VALUES
('en_US', 1, 'Senna Hilltop Pool Villa 2PN', 'The Senna Hilltop Pool Villa (two bedrooms) is the largest and most captivating villa at Avana Retreat. Both bedrooms feature expansive glass doors that open to the outdoors, overlooking the private pool, terraced rice fields, and the valley beyond. The villa is elegantly designed, with a spacious living room and a large sunbathing terrace. The outdoor area is beautifully arranged with a sofa', NULL),
('en_US', 3, 'Ferns Grand Mountain Suite', 'The Ferns Grand Mountain Suites are nestled along the mountainside, hidden among lush tree canopies.The furnishings are carefully curated and meticulously selected, reflecting a refined and elegant sense of style. The design of the Ferns maximizes natural light through an expansive glass window system that stretches from floor to ceiling. The spacious and airy balcony, furnished with a comfortable', NULL),
('en_US', 4, 'Lantana Mountain Bungalow 2PN', 'The Lantana Mountain Bungalow with two bedrooms is thoughtfully designed to blend harmoniously with nature, featuring a charming balcony overlooking the peaceful valley ahead. The décor and furnishings are carefully selected, complementing the overall design of the room. Like other villas at Avana, the bathroom of the Lantana Mountain Bungalow includes a private bathtub with large, transparent gla', NULL),
('en_US', 5, 'Bauhinia Mountain Suite', 'Bauhinia offers a spacious atmosphere with premium and well-equipped interiors, featuring either a large double bed or two single beds, a relaxing sofa, and plenty of natural daylight. The 36m² balcony is ideal for relaxing in dry weather,furnished with a comfortable sofa and a charming small dining table for two. Not only impressive for its elegant interior, the Bauhinia Mountain Suite also place', NULL);
