INSERT INTO `ht_services` (`id`, `name`, `description`, `content`, `price`, `price_type`, `currency_id`, `image`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Phòng chất lượng cao', 'Hãy tận hưởng đỉnh cao của sự thoải mái và phong cách với Phòng chất lượng cao của chúng tôi. Đắm mình trong không gian nội thất thanh lịch, thư giãn trên chiếc giường êm ái, và tận hưởng các tiện nghi hiện đại. Từ phòng tắm riêng tiện nghi đến Wi-Fi tốc độ cao, mọi chi tiết đều được thiết kế nhằm mang lại sự thư giãn tối đa cho bạn. Bạn có thể lựa chọn tầm nhìn ra thành phố, khu vườn hoặc hồ bơi', '<h3><strong>Chúng tôi cung cấp những dịch vụ tốt nhất</strong></h3><p>Niềm vui và cả nỗi đau đều có nguồn gốc của nó, và chúng tôi sẽ mang đến cho bạn một bản trình bày đầy đủ về hệ thống đó, đồng thời giải thích những học thuyết thực sự của nhà khám phá vĩ đại của chân lý – người kiến tạo nên hạnh phúc của con người.</p><p>Không ai từ chối, không thích hay né tránh niềm vui chỉ vì đó là niềm vui, mà bởi vì những người không biết cách theo đuổi niềm vui một cách hợp lý thường phải đối mặt với những hậu quả không mong muốn. Cũng không ai yêu thích hay tìm kiếm nỗi đau chỉ vì bản thân nỗi đau.</p><hr><h3><strong>Tại sao nên chọn dịch vụ này</strong></h3><p>Chúng tôi mang đến một cách tiếp cận toàn diện về hệ thống dịch vụ và truyền tải những nguyên tắc thực sự từ những tư tưởng khám phá giá trị của hạnh phúc con người. Không ai từ chối niềm vui chỉ vì nó là niềm vui, mà bởi vì những người không biết theo đuổi niềm vui một cách hợp lý thường phải đối mặt với những hậu quả không mong muốn.</p><p>Chúng tôi luôn nỗ lực mang đến những trải nghiệm tốt nhất, giúp khách hàng tận hưởng sự thư giãn, tiện nghi và dịch vụ chất lượng cao.</p><hr><h3><strong>Chúng tôi cam kết mang đến</strong></h3><p>Chúng tôi cam kết cung cấp dịch vụ với chất lượng cao, sự tận tâm và trải nghiệm tuyệt vời cho khách hàng. Với đội ngũ chuyên nghiệp cùng các tiện ích hiện đại, chúng tôi luôn đảm bảo mọi nhu cầu của bạn được đáp ứng một cách tốt nhất, mang đến sự hài lòng và thoải mái trong suốt thời gian trải nghiệm dịch vụ.</p><hr><p>Chúng tôi không ngừng cải thiện chất lượng dịch vụ và nâng cao trải nghiệm khách hàng. Mỗi chi tiết đều được chăm chút cẩn thận nhằm mang lại không gian thư giãn, tiện nghi và những khoảnh khắc đáng nhớ cho mọi du khách.</p>', 100, 'once', NULL, 'amenities/icon-1.png', 'published', '2025-06-10 10:38:07', '2026-03-11 20:59:59'),
(2, 'Bãi biển riêng', 'Hãy khám phá không gian riêng tư đẳng cấp với dịch vụ lối vào bãi biển riêng của chúng tôi. Bước chân lên bãi biển nguyên sơ được dành riêng cho khách lưu trú, nơi ánh nắng, bãi cát và làn sóng biển hòa quyện trong sự yên bình tuyệt đối. Thư giãn trên ghế nghỉ ven biển thoải mái, tận hưởng dịch vụ tận tâm, và đắm mình trong vẻ đẹp của thiên đường biển tách biệt và yên tĩnh.', '<h3><strong>Chúng tôi cung cấp những dịch vụ tốt nhất</strong></h3><p>Niềm vui và cả nỗi đau đều có nguồn gốc của nó, và chúng tôi sẽ mang đến cho bạn một bản trình bày đầy đủ về hệ thống đó, đồng thời giải thích những học thuyết thực sự của nhà khám phá vĩ đại của chân lý – người kiến tạo nên hạnh phúc của con người.</p><p>Không ai từ chối, không thích hay né tránh niềm vui chỉ vì đó là niềm vui, mà bởi vì những người không biết cách theo đuổi niềm vui một cách hợp lý thường phải đối mặt với những hậu quả không mong muốn. Cũng không ai yêu thích hay tìm kiếm nỗi đau chỉ vì bản thân nỗi đau.</p><hr><h3><strong>Tại sao nên chọn dịch vụ này</strong></h3><p>Chúng tôi mang đến một cách tiếp cận toàn diện về hệ thống dịch vụ và truyền tải những nguyên tắc thực sự từ những tư tưởng khám phá giá trị của hạnh phúc con người. Không ai từ chối niềm vui chỉ vì nó là niềm vui, mà bởi vì những người không biết theo đuổi niềm vui một cách hợp lý thường phải đối mặt với những hậu quả không mong muốn.</p><p>Chúng tôi luôn nỗ lực mang đến những trải nghiệm tốt nhất, giúp khách hàng tận hưởng sự thư giãn, tiện nghi và dịch vụ chất lượng cao.</p><hr><h3><strong>Chúng tôi cam kết mang đến</strong></h3><p>Chúng tôi cam kết cung cấp dịch vụ với chất lượng cao, sự tận tâm và trải nghiệm tuyệt vời cho khách hàng. Với đội ngũ chuyên nghiệp cùng các tiện ích hiện đại, chúng tôi luôn đảm bảo mọi nhu cầu của bạn được đáp ứng một cách tốt nhất, mang đến sự hài lòng và thoải mái trong suốt thời gian trải nghiệm dịch vụ.</p><hr><p>Chúng tôi không ngừng cải thiện chất lượng dịch vụ và nâng cao trải nghiệm khách hàng. Mỗi chi tiết đều được chăm chút cẩn thận nhằm mang lại không gian thư giãn, tiện nghi và những khoảnh khắc đáng nhớ cho mọi du khách.</p>', 30, 'once', NULL, 'amenities/icon-2.png', 'published', '2025-06-10 10:38:07', '2026-03-11 20:56:26'),
(3, 'Chỗ ở tốt nhất', 'Hãy trải nghiệm đỉnh cao của sự sang trọng với dịch vụ lưu trú cao cấp của chúng tôi. Đắm mình trong không gian được thiết kế tinh tế, kết hợp hoàn hảo giữa sự xa hoa và cảm giác thoải mái. Từ nội thất thanh lịch đến các tiện nghi hiện đại, mọi chi tiết đều được chăm chút kỹ lưỡng nhằm vượt xa sự mong đợi của bạn.', '<h3><strong>Chúng tôi cung cấp những dịch vụ tốt nhất</strong></h3><p>Niềm vui và cả nỗi đau đều có nguồn gốc của nó, và chúng tôi sẽ mang đến cho bạn một bản trình bày đầy đủ về hệ thống đó, đồng thời giải thích những học thuyết thực sự của nhà khám phá vĩ đại của chân lý – người kiến tạo nên hạnh phúc của con người.</p><p>Không ai từ chối, không thích hay né tránh niềm vui chỉ vì đó là niềm vui, mà bởi vì những người không biết cách theo đuổi niềm vui một cách hợp lý thường phải đối mặt với những hậu quả không mong muốn. Cũng không ai yêu thích hay tìm kiếm nỗi đau chỉ vì bản thân nỗi đau.</p><hr><h3><strong>Tại sao nên chọn dịch vụ này</strong></h3><p>Chúng tôi mang đến một cách tiếp cận toàn diện về hệ thống dịch vụ và truyền tải những nguyên tắc thực sự từ những tư tưởng khám phá giá trị của hạnh phúc con người. Không ai từ chối niềm vui chỉ vì nó là niềm vui, mà bởi vì những người không biết theo đuổi niềm vui một cách hợp lý thường phải đối mặt với những hậu quả không mong muốn.</p><p>Chúng tôi luôn nỗ lực mang đến những trải nghiệm tốt nhất, giúp khách hàng tận hưởng sự thư giãn, tiện nghi và dịch vụ chất lượng cao.</p><hr><h3><strong>Chúng tôi cam kết mang đến</strong></h3><p>Chúng tôi cam kết cung cấp dịch vụ với chất lượng cao, sự tận tâm và trải nghiệm tuyệt vời cho khách hàng. Với đội ngũ chuyên nghiệp cùng các tiện ích hiện đại, chúng tôi luôn đảm bảo mọi nhu cầu của bạn được đáp ứng một cách tốt nhất, mang đến sự hài lòng và thoải mái trong suốt thời gian trải nghiệm dịch vụ.</p><hr><p>Chúng tôi không ngừng cải thiện chất lượng dịch vụ và nâng cao trải nghiệm khách hàng. Mỗi chi tiết đều được chăm chút cẩn thận nhằm mang lại không gian thư giãn, tiện nghi và những khoảnh khắc đáng nhớ cho mọi du khách.</p>', 50, 'once', NULL, 'amenities/icon-3.png', 'published', '2025-06-10 10:38:07', '2026-03-11 20:55:27'),
(4, 'Chăm sóc sức khỏe &amp; Spa', 'Hãy bắt đầu hành trình tái tạo năng lượng và chăm sóc bản thân với dịch vụ Chăm sóc sức khỏe &amp; Spa của chúng tôi. Đắm mình trong không gian thư giãn yên bình, nơi các chuyên viên trị liệu giàu kinh nghiệm sẽ chăm sóc bạn bằng nhiều liệu pháp phục hồi và thư giãn tuyệt vời.', '<h3><strong>Chúng tôi mang đến những dịch vụ tốt nhất</strong></h3><p>Niềm vui và cả nỗi đau đều có nguồn gốc của nó, và chúng tôi sẽ mang đến cho bạn cái nhìn đầy đủ về hệ thống đó, đồng thời giải thích những học thuyết thực sự của nhà khám phá vĩ đại của chân lý – người kiến tạo nên hạnh phúc của con người.</p><p>Không ai từ chối hay tránh né niềm vui chỉ vì đó là niềm vui, mà bởi vì những người không biết cách theo đuổi niềm vui một cách hợp lý thường gặp phải những hậu quả không mong muốn. Cũng không ai yêu thích hay tìm kiếm nỗi đau chỉ vì bản thân nỗi đau.</p><hr><h3><strong>Tại sao nên chọn dịch vụ này</strong></h3><p>Chúng tôi cung cấp cách tiếp cận toàn diện về hệ thống dịch vụ, dựa trên những nguyên tắc và giá trị thực tiễn nhằm mang lại sự hài lòng và hạnh phúc cho khách hàng.</p><p>Không ai từ chối niềm vui chỉ vì đó là niềm vui, mà bởi vì những người không biết theo đuổi niềm vui một cách hợp lý có thể phải đối mặt với những hậu quả không mong muốn. Vì vậy, chúng tôi luôn hướng đến việc mang lại trải nghiệm cân bằng, thư giãn và trọn vẹn nhất.</p><p>Chúng tôi không ngừng cải thiện và hoàn thiện dịch vụ để mang lại trải nghiệm tốt nhất cho mọi khách hàng.</p><hr><h3><strong>Chúng tôi cam kết mang đến</strong></h3><p>Chúng tôi cam kết cung cấp dịch vụ với <strong>chất lượng cao, sự tận tâm và trải nghiệm đáng nhớ</strong>. Với đội ngũ chuyên nghiệp cùng hệ thống tiện nghi hiện đại, chúng tôi luôn đảm bảo mọi nhu cầu của bạn được đáp ứng một cách tốt nhất.</p><p>Mục tiêu của chúng tôi là mang lại <strong>sự thoải mái, hài lòng và những khoảnh khắc đáng nhớ</strong> trong suốt thời gian bạn trải nghiệm dịch vụ.</p><hr><p>Chúng tôi luôn chú trọng đến từng chi tiết để mang đến <strong>không gian thư giãn, dịch vụ chất lượng và trải nghiệm trọn vẹn</strong>. Sự hài lòng của khách hàng chính là động lực để chúng tôi không ngừng phát triển và hoàn thiện mỗi ngày.</p>', 10, 'once', NULL, 'amenities/icon-4.png', 'published', '2025-06-10 10:38:07', '2026-03-11 20:51:05'),
(5, 'Nhà hàng &amp; Quầy bar', 'Hãy thưởng thức thế giới hương vị tại Nhà hàng &amp; Quầy bar của chúng tôi. Thưởng thức những món ăn tinh tế được chế biến bởi các đầu bếp tài năng, mang đến nhiều phong cách ẩm thực đa dạng để đánh thức vị giác của bạn. Từ không gian ẩm thực sang trọng đến những điểm gặp gỡ sôi động, các địa điểm của chúng tôi mang đến hành trình ẩm thực đầy hấp dẫn, kết hợp cùng nhiều loại đồ uống phong phú phù hợp', '<h3><strong>Chúng tôi mang đến những dịch vụ tốt nhất</strong></h3><p>Niềm vui và cả nỗi đau đều có nguồn gốc của nó, và chúng tôi sẽ mang đến cho bạn cái nhìn đầy đủ về hệ thống đó, đồng thời giải thích những học thuyết thực sự của nhà khám phá vĩ đại của chân lý – người kiến tạo nên hạnh phúc của con người.</p><p>Không ai từ chối hay tránh né niềm vui chỉ vì đó là niềm vui, mà bởi vì những người không biết cách theo đuổi niềm vui một cách hợp lý thường gặp phải những hậu quả không mong muốn. Cũng không ai yêu thích hay tìm kiếm nỗi đau chỉ vì bản thân nỗi đau.</p><hr><h3><strong>Tại sao nên chọn dịch vụ này</strong></h3><p>Chúng tôi cung cấp cách tiếp cận toàn diện về hệ thống dịch vụ, dựa trên những nguyên tắc và giá trị thực tiễn nhằm mang lại sự hài lòng và hạnh phúc cho khách hàng.</p><p>Không ai từ chối niềm vui chỉ vì đó là niềm vui, mà bởi vì những người không biết theo đuổi niềm vui một cách hợp lý có thể phải đối mặt với những hậu quả không mong muốn. Vì vậy, chúng tôi luôn hướng đến việc mang lại trải nghiệm cân bằng, thư giãn và trọn vẹn nhất.</p><p>Chúng tôi không ngừng cải thiện và hoàn thiện dịch vụ để mang lại trải nghiệm tốt nhất cho mọi khách hàng.</p><hr><h3><strong>Chúng tôi cam kết mang đến</strong></h3><p>Chúng tôi cam kết cung cấp dịch vụ với <strong>chất lượng cao, sự tận tâm và trải nghiệm đáng nhớ</strong>. Với đội ngũ chuyên nghiệp cùng hệ thống tiện nghi hiện đại, chúng tôi luôn đảm bảo mọi nhu cầu của bạn được đáp ứng một cách tốt nhất.</p><p>Mục tiêu của chúng tôi là mang lại <strong>sự thoải mái, hài lòng và những khoảnh khắc đáng nhớ</strong> trong suốt thời gian bạn trải nghiệm dịch vụ.</p><hr><p>Chúng tôi luôn chú trọng đến từng chi tiết để mang đến <strong>không gian thư giãn, dịch vụ chất lượng và trải nghiệm trọn vẹn</strong>. Sự hài lòng của khách hàng chính là động lực để chúng tôi không ngừng phát triển và hoàn thiện mỗi ngày.</p>', 10, 'once', NULL, 'amenities/icon-5.png', 'published', '2025-06-10 10:38:07', '2026-03-11 20:53:17'),
(6, 'Ưu đãi đặc biệt', 'Mở khóa giá trị tuyệt vời với các Ưu đãi đặc biệt của chúng tôi. Hãy trải nghiệm sự sang trọng của khách sạn với mức giá hấp dẫn, cho dù bạn đang lên kế hoạch cho kỳ nghỉ lãng mạn, kỳ nghỉ gia đình hay chuyến công tác. Các gói ưu đãi độc quyền của chúng tôi đáp ứng nhu cầu của mọi du khách, mang đến kỳ nghỉ đáng nhớ cùng nhiều đặc quyền hấp dẫn đi kèm.', '<h3><strong>Chúng tôi cung cấp những dịch vụ tốt nhất</strong></h3><p>Niềm vui và cả nỗi đau đều có nguồn gốc của nó, và chúng tôi sẽ mang đến cho bạn một bản trình bày đầy đủ về hệ thống đó, đồng thời giải thích những học thuyết thực sự của nhà khám phá vĩ đại của chân lý – người kiến tạo nên hạnh phúc của con người.</p><p>Không ai từ chối, không thích hay né tránh niềm vui chỉ vì đó là niềm vui, mà bởi vì những người không biết cách theo đuổi niềm vui một cách hợp lý thường phải đối mặt với những hậu quả không mong muốn. Cũng không ai yêu thích hay tìm kiếm nỗi đau chỉ vì bản thân nỗi đau.</p><hr><h3><strong>Tại sao nên chọn dịch vụ này</strong></h3><p>Chúng tôi mang đến một cách tiếp cận toàn diện về hệ thống dịch vụ và truyền tải những nguyên tắc thực sự từ những tư tưởng khám phá giá trị của hạnh phúc con người. Không ai từ chối niềm vui chỉ vì nó là niềm vui, mà bởi vì những người không biết theo đuổi niềm vui một cách hợp lý thường phải đối mặt với những hậu quả không mong muốn.</p><p>Chúng tôi luôn nỗ lực mang đến những trải nghiệm tốt nhất, giúp khách hàng tận hưởng sự thư giãn, tiện nghi và dịch vụ chất lượng cao.</p><hr><h3><strong>Chúng tôi cam kết mang đến</strong></h3><p>Chúng tôi cam kết cung cấp dịch vụ với chất lượng cao, sự tận tâm và trải nghiệm tuyệt vời cho khách hàng. Với đội ngũ chuyên nghiệp cùng các tiện ích hiện đại, chúng tôi luôn đảm bảo mọi nhu cầu của bạn được đáp ứng một cách tốt nhất, mang đến sự hài lòng và thoải mái trong suốt thời gian trải nghiệm dịch vụ.</p><hr><p>Chúng tôi không ngừng cải thiện chất lượng dịch vụ và nâng cao trải nghiệm khách hàng. Mỗi chi tiết đều được chăm chút cẩn thận nhằm mang lại không gian thư giãn, tiện nghi và những khoảnh khắc đáng nhớ cho mọi du khách.</p>', 10, 'once', NULL, 'amenities/icon-6.png', 'published', '2025-06-10 10:38:07', '2026-03-11 20:53:58'),
(7, 'Orchild Spa', '', '<h2 class=\"section-title fs-1 ff-tertiary fw-bold text-primary-3 mb-3 text-center letter-spacing-15\" style=\"background-color:rgb(255,255,255);color:rgb(145,92,55);font-family:Corinthia, sans-serif;font-size:1.875rem;font-style:normal;font-weight:700;line-height:1.2;margin-bottom:3rem;margin-top:0px;text-align:center;word-spacing:0px;\">Orchid Spa, tâm hồn của An Dưỡng Living</h2><p class=\"section-lead paragraph text-primary-4 mw-890px mx-auto mb-5 text-center\" style=\"background-color:rgb(255,255,255);color:rgb(95,77,69);font-family:Lora, sans-serif;font-size:1.25rem;font-style:normal;font-weight:400;margin:0px auto 3rem;max-width:55.625rem;text-align:center;word-spacing:0px;\">Nương mình theo dòng suối giữa rừng mưa nhiệt đới, Orchid Spa như một miền tĩnh lặng gắn kết thiên nhiên, thỏa mãn trọn vẹn mọi giác quan qua các liệu trình chuyên sâu chăm sóc cơ thể và tâm trí.</p><div class=\"mx-flush\" style=\"background-color:rgb(255,255,255);color:rgb(23,27,10);font-family:\'Galano Grotesque\', sans-serif;font-size:16px;font-style:normal;font-weight:400;word-spacing:0px;\"><img class=\"image_resized img-fluid w-100\" style=\"height:auto;max-width:100%;width:1280px;\" src=\"https://avanaretreat.com/storage/2023/04/1681438385Rectangle%20460.png\" alt=\"\" width=\"1280\" height=\"572\"></div><h3 class=\"spa-item-title mb-0\" style=\"background-color:rgb(248,244,240);color:rgb(95,77,69);font-family:Lora, sans-serif;font-size:1.75rem;font-style:normal;font-weight:400;line-height:1.5;margin-bottom:0px;margin-top:0px;padding:0px 3rem;text-align:center;word-spacing:0px;\">Ngắm nhìn những tán cổ thụ, dòng suối nhỏ, cảm nhận không khí trong lành trong từng nhịp thở</h3><div class=\"spa-item-img\" style=\"background-color:rgb(248,244,240);color:rgb(23,27,10);font-family:\'Galano Grotesque\', sans-serif;font-size:16px;font-style:normal;font-weight:400;word-spacing:0px;\"><img class=\"image_resized img-fluid w-100\" style=\"height:auto;max-width:100%;width:700px;\" src=\"https://avanaretreat.com/storage/2023/04/1681438702Rectangle%20468.png\" alt=\"\" width=\"700\" height=\"451\"></div>', 3000000, 'once', NULL, 'services/1681438738rectangle-469-1.webp', 'published', '2026-03-12 19:58:28', '2026-03-12 20:00:18'),
(8, 'Cloud pool', '', '<div class=\"row row-content\" style=\"margin:0px -6px 4.875rem;\"><div class=\"col-lg order-lg-first\" style=\"margin-top:0px;max-width:100%;padding-left:6px;width:878.013px;\"><p class=\"section-text text-gray text-lg-end ms-auto\" style=\"color:rgb(81,79,79);font-family:Lora, sans-serif;margin-bottom:0px;margin-left:auto;margin-top:0px;max-width:43.375rem;text-align:right;\">Đúng như tên gọi, Cloud Pool là địa điểm lý tưởng để “săn” mây. Từ cuối tháng 10 đến tháng 3 năm sau, mùa “săn” mây ở Avana Retreat bắt đầu khi tiết trời chuyển se lạnh. Đừng quên đặt báo thức, thức dậy sớm cùng chiếc áo ấm để có cơ hội bắt gặp một biển mây phủ trắng thung lũng, gần đến mức bạn gần như có thể chạm vào chúng!</p></div></div><div class=\"row row-imgs align-items-end gy-3\" style=\"margin-left:-6px;margin-right:-6px;margin-top:-16px;\"><div class=\"col-md\" style=\"background-color:rgb(255,255,255);color:rgb(23,27,10);font-family:\'Galano Grotesque\', sans-serif;font-size:16px;font-style:normal;font-weight:400;margin-top:16px;max-width:100%;padding-left:6px;width:878.013px;word-spacing:0px;\"><div class=\"section-img section-img-1\"><img class=\"image_resized img-fluid w-100\" style=\"height:auto;max-width:100%;width:866.013px;\" src=\"https://avanaretreat.com/storage/2024/08/1722934877A%20sea%20of%20cloud%20from%20our%20terrace.jpg\" alt=\"\" width=\"916\" height=\"539\"></div></div><div class=\"col-md-auto col-img-2\" style=\"background-color:rgb(255,255,255);color:rgb(23,27,10);font-family:\'Galano Grotesque\', sans-serif;font-size:16px;font-style:normal;font-weight:400;margin-top:16px;max-width:100%;padding-left:6px;width:413.987px;word-spacing:0px;\"><br> </div></div>', 2000, 'once', NULL, 'services/1722934877a-sea-of-cloud-from-our-terrace.webp', 'published', '2026-03-12 20:03:44', '2026-03-12 20:03:44');
