INSERT INTO `pages` (`id`, `name`, `content`, `user_id`, `image`, `template`, `description`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Trang chủ', '<p>&nbsp;</p><p>&nbsp;</p><shortcode>[simple-slider key=\"songhoi1\"][/simple-slider]</shortcode><shortcode>[featured-amenities title=\"Khách sạn\" subtitle=\"Khám phá\" description=\"Không gian nghỉ dưỡng sang trọng và thoải mái ngay tại trung tâm thành phố. Với thiết kế tinh tế cùng các tiện nghi hiện đại, mỗi phòng đều được chăm chút để mang lại cảm giác thư giãn tối đa cho du khách.\" background_color=\"#F7F5F1\" background_image=\"/backgrounds/an-img-01.png\" amenity_ids=\"1,2,3,4,5,6\"][/featured-amenities]</shortcode><shortcode>[featured-rooms title=\"Phòng &amp; Phòng Suite\" subtitle=\"Niềm vui của sự sang trọng\" description=\"Khám phá các hạng phòng và suite được thiết kế tinh tế, kết hợp giữa sự sang trọng, tiện nghi hiện đại và không gian thoải mái, mang đến cho bạn trải nghiệm nghỉ dưỡng trọn vẹn.\" room_ids=\"2,3,4\"][/featured-rooms]</shortcode><shortcode>[feature-area title=\"Nơi tâm hồn được thư thái\" subtitle=\"Khách sạn &amp; khu nghỉ dưỡng sang trọng\" description=\"Đừng quên đặt báo thức, thức dậy sớm cùng chiếc áo ấm để có cơ hội bắt gặp một biển mây phủ trắng thung lũng, gần đến mức bạn gần như có thể chạm vào chúng!\" image=\"places/1714962283avana-10-edit.jpg\" background_image=\"backgrounds/an-img-02.png\" button_primary_label=\"Xem thêm\" button_primary_url=\"/contact-us\"][/feature-area]</shortcode><shortcode>[pricing title=\"Dịch vụ bổ sung\" subtitle=\"Giá tốt nhất\" description=\"Chúng tôi luôn mang đến mức giá tốt nhất cùng nhiều ưu đãi hấp dẫn, giúp bạn tận hưởng kỳ nghỉ thoải mái và chất lượng với chi phí hợp lý. Mỗi lựa chọn đều được thiết kế để mang lại giá trị cao nhất cho trải nghiệm lưu trú của bạn.\" background_image_1=\"backgrounds/an-img-01.png\" background_image_2=\"backgrounds/an-img-02.png\" quantity=\"2\" title_1=\"Dọn phòng\" description_1=\"Dịch vụ dọn phòng được thực hiện thường xuyên bởi đội ngũ nhân viên chuyên nghiệp, đảm bảo không gian phòng luôn sạch sẽ, gọn gàng và mang lại cảm giác thoải mái cho khách trong suốt thời gian lưu trú.\" price_1=\"200,000₫\" duration_1=\"Hàng tháng\" feature_list_1=\"Dọn phòng hằng ngày., Thay ga giường và khăn tắm sạch sẽ., Vệ sinh phòng tắm và khu vực sinh hoạt., Bổ sung đồ dùng cần thiết trong phòng., Đảm bảo không gian luôn sạch sẽ và thoải mái.\" button_label_1=\"Bắt đầu ngay\" button_url_1=\"/contact-us\" title_2=\"Đã bao gồm đồ uống\" description_2=\"Khách lưu trú sẽ được phục vụ các loại đồ uống miễn phí trong thời gian sử dụng dịch vụ. Tận hưởng trà, cà phê hoặc các loại nước giải khát được chuẩn bị sẵn để mang lại sự tiện nghi và thoải mái trong suốt kỳ nghỉ của bạn.\" price_2=\"400,000₫\" duration_2=\"Hàng tháng\" feature_list_2=\"Đồ uống miễn phí cho khách lưu trú., Có sẵn trà; cà phê và nước giải khát., Phục vụ tại phòng hoặc khu vực chung., Luôn được bổ sung trong suốt thời gian lưu trú., Mang lại trải nghiệm nghỉ dưỡng tiện nghi và thoải mái.\" button_label_2=\"Bắt đầu ngay\" button_url_2=\"/contact-us\"][/pricing]</shortcode><shortcode>[testimonials title=\"Khách hàng nói gì về chúng tôi\" subtitle=\"Cảm nhận của khách hàng\" description=\"Khám phá những chia sẻ và đánh giá chân thực từ khách hàng đã trải nghiệm dịch vụ của chúng tôi. Sự hài lòng của khách hàng luôn là động lực để chúng tôi không ngừng nâng cao chất lượng dịch vụ.\" background_image=\"/backgrounds/testimonial-bg.png\" testimonial_ids=\"1,2,3,4,5,6\"][/testimonials]</shortcode><shortcode>[booking-form title=\"Đặt phòng\" subtitle=\"Đặt chỗ ngay\" description=\"Thực hiện đặt phòng nhanh chóng và thuận tiện chỉ với vài bước đơn giản. Chọn thời gian lưu trú, loại phòng phù hợp và tận hưởng kỳ nghỉ thoải mái với dịch vụ chuyên nghiệp của chúng tôi.\" image=\"places/1685507832restaurant-2.jpg\"][/booking-form]</shortcode><shortcode>[news title=\"Tin tức &amp; Bài viết mới nhất\" subtitle=\"Bài viết của chung tôi\" description=\"Cập nhật những bài viết, tin tức và thông tin mới nhất về du lịch, khách sạn và các trải nghiệm thú vị giúp bạn có một chuyến đi trọn vẹn hơn.\" background_image=\"backgrounds/an-img-07.png\" type=\"featured\" limit=\"3\"][/news]</shortcode>', 1, NULL, 'full-width', '', 'published', '2025-06-10 10:38:14', '2026-04-07 18:59:12'),
