(5, 'About Us', '<shortcode>[about-us title=\"Không gian nghỉ dưỡng giữa thiên nhiên\" subtitle=\"Về chúng tôi\" description=\"Retreat được tạo nên như một không gian nghỉ dưỡng yên bình, nơi bạn có thể tạm rời xa nhịp sống bận rộn để tận hưởng sự thư thái và cân bằng lại năng lượng. Với không gian xanh, kiến trúc hài hòa cùng thiên nhiên và các tiện nghi được chăm chút, nơi đây mang đến trải nghiệm nghỉ dưỡng trọn vẹn cho mọi du khách.{{NEWLINE}}{{NEWLINE}}Dù bạn đang tìm kiếm một kỳ nghỉ thư giãn, một chuyến đi tái tạo năng lượng hay đơn giản chỉ là khoảng thời gian nghỉ ngơi bên gia đình và bạn bè, Retreat luôn sẵn sàng mang đến không gian thoải mái, riêng tư và đầy cảm hứng.\" highlights=\"Không gian nghỉ dưỡng yên tĩnh hòa mình vào thiên nhiên.; Thiết kế tinh tế mang đến cảm giác thư thái và riêng tư.; Trải nghiệm lưu trú thoải mái với đầy đủ tiện nghi.; Nơi lý tưởng để nghỉ ngơi, thư giãn và tái tạo năng lượng\" style=\"style-1\" button_label=\"Xem thêm\" button_url=\"/about-us\" signature_image=\"rooms/168439421305-senna-hilltop-pool-villa-2-br-9-copy.jpg\" signature_author=\"Vincent Smith\" top_left_image=\"places/1683775376-vbk0653-edit.jpg\" bottom_right_image=\"places/1684383802linh-phuong.jpg\" floating_right_image=\"backgrounds/an-img-02.png\"][/about-us]</shortcode><shortcode>[why-choose-us title=\"Chúng tôi cung cấp nhiều lựa chọn khách sạn\" subtitle=\"Những gì chúng tôi cung cấp\" description=\"Chúng tôi mang đến nhiều lựa chọn khách sạn với các phong cách và mức giá khác nhau, giúp bạn dễ dàng tìm được nơi lưu trú phù hợp với nhu cầu và ngân sách của mình.\" right_image=\"rooms/168179031903-ferms-grand-mountain-suite-2.jpg\" background_color=\"#291D16\" background_image=\"backgrounds/an-img-05.png\" quantity=\"3\" title_1=\"Chất lượng cao\" percentage_1=\"80\" title_2=\"Dịch vụ bảo trì\" percentage_2=\"90\" title_3=\"Quản lý sản phẩm\" percentage_3=\"70\"][/why-choose-us]</shortcode><shortcode>[services title=\"Viên ngọc của biển Adriatic\" subtitle=\"Khách sạn &amp; khu nghỉ dưỡng sang trọng\" description=\"Hiện tại chưa có sự trang trí nổi bật. Maecenas đã tạo ra một mức giá phù hợp. Phần liên kết tổng thể khá vững chắc, mang lại hiệu quả và sự hài hòa trong kết nối. Phương tiện vận hành linh hoạt theo dòng liên kết chính. Người dùng có thể điều chỉnh một cách linh hoạt. Hiện nay, lộ trình đã được mở ra, giúp cải thiện hiệu quả vận hành. Kết quả cuối cùng mang lại sự cân bằng và tính thẩm mỹ.\" left_image=\"rooms/168439420905-senna-hilltop-pool-villa-2-br-5.jpg\" right_floating_image=\"backgrounds/an-img-02.png\" button_label=\"Xem thêm\" button_url=\"/about-us\"][/services]</shortcode><shortcode>[news title=\"Tin tức &amp; Bài viết mới nhất\" subtitle=\"Bài viết của chung tôi\" description=\"Cập nhật những bài viết, tin tức và thông tin mới nhất về du lịch, khách sạn và các trải nghiệm thú vị giúp bạn có một chuyến đi trọn vẹn hơn.\" background_image=\"backgrounds/an-img-07.png\" type=\"featured\" limit=\"3\"][/news]</shortcode><shortcode>[newsletter title=\"Nhận ưu đãi tốt nhất cho khách sạn\" subtitle=\"Bản tin\" description=\"Khám phá những ưu đãi hấp dẫn và mức giá đặc biệt khi đặt phòng tại khách sạn của chúng tôi. Tận hưởng dịch vụ chất lượng cùng nhiều lợi ích tuyệt vời cho kỳ nghỉ của bạn.\" background_color=\"#F7F5F1\" left_floating_image=\"backgrounds/an-img-07.png\"][/newsletter]</shortcode>', 1, NULL, 'full-width', '', 'published', '2025-06-10 10:38:14', '2026-03-13 01:56:04'),
(6, 'Services', '<shortcode>[service-list background_image=\"backgrounds/an-img-01.png\" limit=\"6\"][/service-list]</shortcode><shortcode>[services title=\"Viên ngọc của biển Adriatic\" subtitle=\"Khách sạn &amp; khu nghỉ dưỡng sang trọng\" description=\"Hiện tại chưa có sự trang trí nổi bật. Maecenas đã tạo ra một mức giá phù hợp. Phần liên kết tổng thể khá vững chắc, mang lại hiệu quả và sự hài hòa trong kết nối. Phương tiện vận hành linh hoạt theo dòng liên kết chính. Người dùng có thể điều chỉnh một cách linh hoạt. Hiện nay, lộ trình đã được mở ra, giúp cải thiện hiệu quả vận hành. Kết quả cuối cùng mang lại sự cân bằng và tính thẩm mỹ.\" left_image=\"rooms/168439420905-senna-hilltop-pool-villa-2-br-5.jpg\" right_floating_image=\"backgrounds/an-img-02.png\" button_label=\"Xem thêm\" button_url=\"/about-us\"][/services]</shortcode><shortcode>[booking-form title=\"Đặt phòng\" subtitle=\"Đặt chỗ ngay\" description=\"Thực hiện đặt phòng nhanh chóng và thuận tiện chỉ với vài bước đơn giản. Chọn thời gian lưu trú, loại phòng phù hợp và tận hưởng kỳ nghỉ thoải mái với dịch vụ chuyên nghiệp của chúng tôi.\" image=\"places/1685507832restaurant-2.jpg\"][/booking-form]</shortcode><shortcode>[testimonials title=\"Khách hàng nói gì về chúng tôi\" subtitle=\"Cảm nhận của khách hàng\" description=\"Khám phá những chia sẻ và đánh giá chân thực từ khách hàng đã trải nghiệm dịch vụ của chúng tôi. Sự hài lòng của khách hàng luôn là động lực để chúng tôi không ngừng nâng cao chất lượng dịch vụ.\" background_image=\"/backgrounds/testimonial-bg.png\" testimonial_ids=\"1,2,3,4,5,6\"][/testimonials]</shortcode>', 1, NULL, 'full-width', '', 'published', '2025-06-10 10:38:14', '2026-03-15 20:31:54'),
