(8, 'FAQ', '<shortcode>[faqs category_ids=\"1,2,3,4,5\"][/faqs]</shortcode><shortcode>[newsletter title=\"Nhận ưu đãi tốt nhất cho khách sạn\" subtitle=\"Bản tin\" description=\"Khám phá những ưu đãi hấp dẫn và mức giá đặc biệt khi đặt phòng tại khách sạn của chúng tôi. Tận hưởng dịch vụ chất lượng cùng nhiều lợi ích tuyệt vời cho kỳ nghỉ của bạn.\" background_color=\"#F7F5F1\" left_floating_image=\"backgrounds/an-img-07.png\"][/newsletter]</shortcode><shortcode>[teams title=\"Khách sạn tốt nhất\" subtitle=\"Đội ngũ của chúng tôi\" description=\"Với tinh thần làm việc như một đội ngũ thống nhất, chúng tôi tận tâm tạo nên kỳ nghỉ hoàn hảo cho bạn, đảm bảo mọi chi tiết đều thể hiện cam kết của chúng tôi đối với dịch vụ hiếu khách xuất sắc.\" team_ids=\"1,2,3,4,5,6\" style=\"style-1\"][/teams]</shortcode>', 1, NULL, 'full-width', '', 'published', '2025-06-10 10:38:14', '2026-03-15 21:03:17'),
(9, 'Team', '[teams team_ids=\"1,2,3,4,5,6,7,8\" style=\"style-2\"][/teams][why-choose-us title=\"We Offer Wide Selection of Hotel\" subtitle=\"Rio We Use\" description=\"Explore a variety of handpicked hotels with Rio We Use. Your ideal stay is just a click away. Book now for an unforgettable experience.\" right_image=\"services/skills-img.png\" background_color=\"#291D16\" background_image=\"backgrounds/an-img-05.png\" quantity=\"3\" title_1=\"Quality Production\" percentage_1=\"80\" title_2=\"Maintenance Services\" percentage_2=\"90\" title_3=\"Product Management\" percentage_3=\"70\"][/why-choose-us][newsletter title=\"Get Best Offers On The Hotel\" subtitle=\"Newsletter\" description=\"With the subscription, enjoy your favourite Hotels without having to think about it\" background_color=\"#F7F5F1\" left_floating_image=\"backgrounds/an-img-07.png\"][/newsletter]', 1, NULL, 'full-width', NULL, 'published', '2025-06-10 10:38:14', '2025-06-10 10:38:14'),
