(11, 'Contact Us', '[contact-form title=&quot;Get In Touch&quot; title_button=&quot;SUBMIT NOW&quot; address_icon=&quot;far fa-map&quot; address_label=&quot;Office Address&quot; address_detail=&quot;380 St Kilda Road, Melbourne &lt;br&gt;VIC 3004, Australia&quot; email_icon=&quot;far fa-envelope-open&quot; email_label=&quot;Message Us&quot; email_detail=&quot;support@example.com &lt;br&gt;info@example.com&quot; work_time_icon=&quot;far fa-clock&quot; work_time_label=&quot;Working Hours&quot; work_time_detail=&quot;Monday to Friday 09:00 to 18:30 &lt;br&gt;Saturday 15:30&quot; phone_icon=&quot;fa fa-phone&quot; phone_label=&quot;(+1) 123 456 78&quot; phone_detail=&quot; 24/7 Customer Service And Returns Support.&quot;][/contact-form][newsletter title=\"Get Best Offers On The Hotel\" subtitle=\"Newsletter\" description=\"With the subscription, enjoy your favourite Hotels without having to think about it\" background_color=\"#F7F5F1\" left_floating_image=\"backgrounds/an-img-07.png\"][/newsletter]', 1, NULL, 'full-width', NULL, 'published', '2025-06-10 10:38:14', '2025-06-10 10:38:14'),
(12, 'Privacy', '<div class=\"about-area5 about-p p-relative\"><div class=\"container pt-60 pb-90\"><div class=\"service-detail\"><div class=\"content-box\"><h2>Tuyên bố Quyền riêng tư</h2><p data-start=\"79\" data-end=\"567\">Trước hết – <strong data-start=\"91\" data-end=\"150\">quyền riêng tư của bạn rất quan trọng đối với chúng tôi</strong>. Có thể bạn đã thấy câu nói này trong nhiều thông báo khác, nhưng chúng tôi thực sự nghiêm túc về điều đó. Khi sử dụng dịch vụ của chúng tôi, bạn đã đặt niềm tin vào chúng tôi và chúng tôi rất trân trọng sự tin tưởng ấy. Vì vậy, chúng tôi cam kết <strong data-start=\"398\" data-end=\"451\">bảo vệ và giữ an toàn cho dữ liệu cá nhân của bạn</strong>. Chúng tôi luôn hành động vì lợi ích tốt nhất của khách hàng và minh bạch trong việc xử lý dữ liệu cá nhân của bạn.</p><p data-start=\"569\" data-end=\"1017\">Nếu bạn đã từng sử dụng dịch vụ của chúng tôi trước đây, bạn sẽ biết rằng dịch vụ của chúng tôi cung cấp <strong data-start=\"674\" data-end=\"708\">các dịch vụ du lịch trực tuyến</strong> thông qua các <strong data-start=\"723\" data-end=\"776\">trang web và ứng dụng di động của chính chúng tôi</strong>, cũng như các <strong data-start=\"791\" data-end=\"819\">nền tảng trực tuyến khác</strong> như website của đối tác và mạng xã hội. Chúng tôi muốn lưu ý rằng tất cả những thông tin bạn sắp đọc dưới đây <strong data-start=\"930\" data-end=\"1016\">không chỉ áp dụng cho một hay hai nền tảng, mà áp dụng cho tất cả các nền tảng này</strong>.</p><p data-start=\"1019\" data-end=\"1411\">Nếu bạn đã từng sử dụng dịch vụ của chúng tôi trước đây, bạn sẽ biết rằng dịch vụ của chúng tôi cung cấp các dịch vụ du lịch trực tuyến thông qua các trang web và ứng dụng di động của chính chúng tôi, cũng như các nền tảng trực tuyến khác như website của đối tác và mạng xã hội. Chúng tôi muốn nhấn mạnh rằng mọi thông tin trong tài liệu này nhìn chung <strong data-start=\"1372\" data-end=\"1410\">áp dụng cho tất cả các nền tảng đó</strong>.</p><h2>Các thuật ngữ được sử dụng trong Tuyên bố Quyền riêng tư này</h2><p><strong data-start=\"1488\" data-end=\"1510\">“Trip” (Chuyến đi)</strong>: Là các sản phẩm và dịch vụ du lịch khác nhau mà bạn có thể <strong data-start=\"1573\" data-end=\"1646\">đặt, mua, thanh toán, thuê, cung cấp, đặt trước, kết hợp hoặc sử dụng</strong> từ <strong data-start=\"1650\" data-end=\"1692\">Nhà cung cấp chuyến đi (Trip Provider)</strong>.</p><p><strong data-start=\"1695\" data-end=\"1739\">“Trip Provider” (Nhà cung cấp chuyến đi)</strong>: Là đơn vị cung cấp <strong data-start=\"1762\" data-end=\"1771\">chỗ ở</strong> (ví dụ: khách sạn, motel, căn hộ, nhà nghỉ B&amp;B, chủ nhà cho thuê), <strong data-start=\"1839\" data-end=\"1857\">điểm tham quan</strong> (ví dụ: công viên giải trí, bảo tàng, tour tham quan), <strong data-start=\"1913\" data-end=\"1935\">dịch vụ vận chuyển</strong> (ví dụ: thuê xe, du thuyền, tàu hỏa, xe đưa đón sân bay, tour xe khách, dịch vụ trung chuyển), <strong data-start=\"2031\" data-end=\"2053\">nhà điều hành tour</strong>, <strong data-start=\"2055\" data-end=\"2075\">bảo hiểm du lịch</strong>, và bất kỳ sản phẩm hoặc dịch vụ du lịch liên quan nào khác được cung cấp để <strong data-start=\"2153\" data-end=\"2184\">đặt chuyến đi trên nền tảng</strong> theo từng thời điểm.</p></div></div></div></div>', 1, NULL, 'full-width', '', 'published', '2025-06-10 10:38:14', '2026-03-15 20:54:22'),
(13, 'Điều khoản &amp; Điều kiện', '<div class=\"about-area5 about-p p-relative\"><div class=\"container pt-60 pb-90\"><div class=\"service-detail\"><div class=\"content-box\"><h3>Định nghĩa</h3><p>Một số từ ngữ bạn sẽ thấy trong tài liệu này có ý nghĩa rất cụ thể, vì vậy vui lòng tham khảo <strong data-start=\"136\" data-end=\"158\">“từ điển RioRelax”</strong> ở cuối Điều khoản để hiểu rõ hơn.</p><h3>Về các điều khoản này</h3><p data-start=\"221\" data-end=\"376\">Khi bạn hoàn tất việc <strong data-start=\"243\" data-end=\"254\">Đặt chỗ</strong>, bạn đồng ý với các <strong data-start=\"275\" data-end=\"293\">Điều khoản này</strong> cũng như bất kỳ điều khoản nào khác được cung cấp cho bạn trong quá trình đặt chỗ.</p><p data-start=\"378\" data-end=\"663\">Phiên bản <strong data-start=\"388\" data-end=\"401\">tiếng Anh</strong> của các Điều khoản này là bản gốc. Nếu có bất kỳ tranh chấp nào liên quan đến các Điều khoản, hoặc có sự khác biệt giữa phiên bản tiếng Anh và phiên bản bằng ngôn ngữ khác, thì <strong data-start=\"579\" data-end=\"618\">phiên bản tiếng Anh sẽ được áp dụng</strong>. (Bạn có thể thay đổi ngôn ngữ ở đầu trang.)</p><h3>Nền tảng của chúng tôi</h3><p data-start=\"693\" data-end=\"1122\">Chúng tôi nỗ lực hợp lý để cung cấp và vận hành Nền tảng của mình, tuy nhiên chúng tôi không thể đảm bảo rằng mọi thông tin trên đó đều hoàn toàn chính xác (vì chúng tôi nhận một phần thông tin từ các <strong data-start=\"894\" data-end=\"918\">Nhà cung cấp dịch vụ</strong>). Trong phạm vi pháp luật cho phép, chúng tôi không chịu trách nhiệm đối với bất kỳ lỗi nào, sự gián đoạn nào hoặc thông tin bị thiếu – mặc dù chúng tôi sẽ cố gắng khắc phục và chỉnh sửa sớm nhất có thể.</p><p data-start=\"1124\" data-end=\"1282\">Chúng tôi sẽ hiển thị cho bạn các ưu đãi có sẵn bằng ngôn ngữ mà chúng tôi cho là phù hợp nhất với bạn. Bạn có thể thay đổi sang ngôn ngữ khác bất cứ lúc nào.</p><h3>Giá cả</h3><p data-start=\"1296\" data-end=\"1431\">Khi bạn thực hiện <strong data-start=\"1314\" data-end=\"1325\">Đặt chỗ</strong>, bạn đồng ý thanh toán chi phí của <strong data-start=\"1361\" data-end=\"1384\">Trải nghiệm du lịch</strong>, bao gồm mọi khoản phí và thuế có thể áp dụng.</p><p data-start=\"1433\" data-end=\"1628\" data-is-last-node=\"\" data-is-only-node=\"\">Một số mức giá bạn thấy có thể đã được <strong data-start=\"1472\" data-end=\"1507\">làm tròn đến số nguyên gần nhất</strong>. Mức giá bạn thực sự thanh toán sẽ dựa trên <strong data-start=\"1552\" data-end=\"1579\">giá gốc (chưa làm tròn)</strong>, tuy nhiên sự chênh lệch thực tế thường rất nhỏ.</p></div></div></div></div>', 1, NULL, 'full-width', '', 'published', '2025-06-10 10:38:14', '2026-03-15 20:52:03'),
(14, 'Thời gian sử dụng', '<p>&nbsp;</p><shortcode>[media url=\"https://www.youtube.com/watch?v=8EtTf9MUKro\" width=\"850\" height=\"445\" centered=\"yes\" margin_top=\"0\" margin_bottom=\"20\" margin_start=\"0\" margin_end=\"0\"][/media]</shortcode><shortcode>[about-us title=\"Thoi gian nghỉ \" subtitle=\"Giảm 20% toàn cửa hàng\" description=\"12bca\" style=\"style-2\" signature_image=\"1681438650rectangle-464.png\"][/about-us]</shortcode><shortcode>[about-us title=\"thơi gian nghi duong\" subtitle=\"Giảm 20% toàn cửa hàng\" description=\"123\" highlights=\"abv\" style=\"style-1\" signature_image=\"concept01-pic01-1-1.jpg\"][/about-us]</shortcode>', 1, NULL, 'default', '', 'published', '2026-04-07 18:43:03', '2026-04-07 19:29:23');
INSERT INTO `pages_translations` (`lang_code`, `pages_id`, `name`, `description`, `content`) VALUES
('en_US', 1, 'Home Page 01', NULL, '<shortcode>[simple-slider key=\"home-slider\"][/simple-slider]</shortcode><shortcode>[check-availability-form][/check-availability-form]</shortcode><shortcode>[about-us title=\"A retreat in the heart of nature\" subtitle=\"About us\" description=\"Retreat is designed as a peaceful sanctuary where you can step away from the busy pace of everyday life and rediscover relaxation and balance. Surrounded by lush greenery, harmonious architecture that blends with nature, and thoughtfully curated amenities, it offers a truly complete and refreshing getaway experience for every guest.{{NEWLINE}}{{NEWLINE}}Whether you are looking for a relaxing holiday, a rejuvenating escape, or simply a quiet moment to spend with family and friends, Retreat is always ready to provide a comfortable, private, and inspiring space for your stay.\" highlights=\"A peaceful retreat immersed in nature.; Elegant design that brings a sense of relaxation and privacy.; A comfortable stay with thoughtfully provided amenities.; An ideal place to rest, unwind, and recharge your energy.\" style=\"style-1\" button_label=\"Discover more\" button_url=\"/about-us\" signature_image=\"rooms/168439421305-senna-hilltop-pool-villa-2-br-9-copy.jpg\" signature_author=\"Vincent Smith\" top_left_image=\"places/1683775376-vbk0653-edit.jpg\" bottom_right_image=\"places/1684383802linh-phuong.jpg\" floating_right_image=\"backgrounds/an-img-02.png\"][/about-us]</shortcode><shortcode>[featured-amenities title=\"The Hotel\" subtitle=\"Explore\" description=\"A luxurious and comfortable retreat in the heart of the city. With refined design and modern amenities, each room is thoughtfully crafted to provide guests with the ultimate sense of relaxation.\" background_color=\"#F7F5F1\" background_image=\"/backgrounds/an-img-01.png\" amenity_ids=\"1,2,3,4,5,6\"][/featured-amenities]</shortcode><shortcode>[featured-rooms title=\"Rooms &amp; Suites\" subtitle=\"The Pleasure Of Luxury\" description=\"Explore our thoughtfully designed rooms and suites, where elegance, modern amenities, and comfortable spaces come together to create a truly complete and relaxing stay.\" room_ids=\"2,3,4\"][/featured-rooms]</shortcode><shortcode>[feature-area title=\"Pearl Of The Adriatic.\" subtitle=\"Luxury Hotel &amp; Resort\" description=\"Don’t forget to set your alarm and wake up early with a warm jacket to catch the breathtaking sight of a sea of clouds covering the valley—so close it feels like you could almost touch them!\" image=\"places/1714962283avana-10-edit.jpg\" background_image=\"backgrounds/an-img-02.png\" button_primary_label=\"Discover More\" button_primary_url=\"/contact-us\"][/feature-area]</shortcode><shortcode>[pricing title=\"Extra Services\" subtitle=\"Best Prices\" description=\"We always offer the best rates along with attractive promotions, allowing you to enjoy a comfortable and high-quality stay at a reasonable cost. Each option is designed to deliver the greatest value for your stay experience.\" background_image_1=\"backgrounds/an-img-01.png\" background_image_2=\"backgrounds/an-img-02.png\" quantity=\"2\" title_1=\"Room cleaning\" description_1=\"Housekeeping services are carried out regularly by our professional staff, ensuring that every room remains clean, tidy, and comfortable throughout your stay\" price_1=\"200,000₫\" duration_1=\"Monthly\" feature_list_1=\"Daily housekeeping service., Fresh bed linens and clean towels provided., Cleaning of the bathroom and living areas., Replenishment of essential in-room amenities., Ensuring a clean and comfortable space at all times.\" button_label_1=\"Get Started\" button_url_1=\"/contact-us\" title_2=\"Drinks included\" description_2=\"Guests will be served complimentary beverages during their stay. Enjoy tea, coffee, or a selection of refreshing drinks prepared for your convenience, adding comfort and relaxation throughout your stay.\" price_2=\"400,000₫\" duration_2=\"Monthly\" feature_list_2=\"Complimentary beverages for staying guests., Tea; coffee; and soft drinks available., Served in-room or in common areas., Regularly replenished throughout your stay., A convenient and comfortable stay experience.\" button_label_2=\"Get Started \" button_url_2=\"/contact-us\"][/pricing]</shortcode><shortcode>[testimonials title=\"What Our Clients Says\" subtitle=\"Testimonial\" description=\"Discover genuine stories and reviews from guests who have experienced our services. Customer satisfaction is always our motivation to continuously improve and enhance the quality of our service.\" background_image=\"/backgrounds/testimonial-bg.png\" testimonial_ids=\"1,2,3,4,5,6\"][/testimonials]</shortcode><shortcode>[booking-form title=\"Book A Room\" subtitle=\"Make Reservation\" description=\"Make your reservation quickly and conveniently in just a few simple steps. Choose your stay dates, select the room type that suits you, and enjoy a comfortable getaway with our professional service.\" image=\"places/1685507832restaurant-2.jpg\"][/booking-form]</shortcode><shortcode>[news title=\"Latest Blog &amp; News\" subtitle=\"Our Blog\" description=\"Stay updated with the latest articles, news, and information about travel, hotels, and exciting experiences to help you enjoy a more complete and memorable trip.\" background_image=\"backgrounds/an-img-07.png\" type=\"featured\" limit=\"3\"][/news]</shortcode>'),
('en_US', 3, 'Home Page Side Menu', NULL, '[simple-slider key=\"home-slider\"][/simple-slider][check-availability-form][/check-availability-form][about-us title=\"Most Safe &amp; Rated Hotel In London.\" subtitle=\"About Us\" description=\"At About Us, we take pride in offering the most secure and top-rated hotels in London. Your safety and comfort are our priorities, which is why our meticulous selection process ensures each hotel meets stringent quality standards. Whether you’re visiting for business or leisure, trust us to provide you with a stay that combines the utmost security and exceptional service.&lt;br&gt; &lt;br&gt;Experience London like never before with our curated list of accommodations that boast prime locations and unmatched safety measures. From charming boutique hotels to Luxuryous city-center options, we’ve done the groundwork to present you with a variety of choices that guarantee a worry-free stay. Choose About Us for a memorable trip enriched with both the allure of London.\" highlights=\"Discover the epitome of safe haven in our top-rated London hotels.; Immerse yourself in the heart of London’s charm.; Experience the perfect blend of luxury and comfort.\" style=\"style-1\" button_label=\"DISCOVER MORE\" button_url=\"/about-us\" signature_image=\"general/signature.png\" signature_author=\"Vincent Smith\" top_left_image=\"services/about-img-02.png\" bottom_right_image=\"services/about-img-03.png\" floating_right_image=\"backgrounds/an-img-02.png\"][/about-us][featured-amenities title=\"The Hotel\" subtitle=\"Explore\" description=\"Proin consectetur non dolor vitae pulvinar. Pellentesque sollicitudin dolor eget neque viverra, sed interdum metus interdum. Cras lobortis pulvinar dolor, sit amet ullamcorper dolor iaculis vel\" background_color=\"#F7F5F1\" background_image=\"/backgrounds/an-img-01.png\" amenity_ids=\"1,2,3,4,5,6\"][/featured-amenities][featured-rooms title=\"Rooms &amp; Suites\" subtitle=\"The Pleasure Of Luxury\" description=\"Pr