INSERT INTO `posts` (`id`, `name`, `description`, `content`, `status`, `author_id`, `author_type`, `is_featured`, `image`, `views`, `format_type`, `created_at`, `updated_at`) VALUES
(9, 'Senjuan là gì?', '', '<p>Giới thiệu về Senjuan</p><p>Là một khu nghỉ dưỡng nổi tiếng thế giới của Nhật Bản, nhà nghỉ này cung cấp không gian riêng tư với bồn tắm ngoài trời trong mỗi phòng, mang đến một thế giới chữa lành thông qua hơi thở của thiên nhiên và lòng hiếu khách chân thành.</p><p>Nhà nghỉ của chúng tôi nằm dọc theo sông Tanigawa, với núi Tanigawa làm nền, mang đến một không gian yên tĩnh và riêng tư.</p><p>Mỗi phòng được thiết kế độc đáo đều có bồn tắm ngoài trời, nơi bạn có thể tận hưởng dòng nước suối nóng tự nhiên chảy trực tiếp từ nguồn.</p><p>Chúng tôi chờ đón sự hiện diện của bạn với ẩm thực tinh tế sử dụng nguyên liệu theo mùa,<br>và lòng hiếu khách chân thành.</p><p>Tất cả các phòng đều có bồn tắm ngoài trời riêng với dòng nước suối nóng chảy tự do. Hãy tận hưởng những giây phút thư giãn và yên tĩnh sang trọng trong không gian riêng tư với tầm nhìn toàn cảnh núi Tanigawa từ bồn tắm ngoài trời của bạn.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"y-tuong1\"][/simple-slider]</shortcode><p>Một bữa tiệc thị giác<br>Ẩm thực và rượu sake được chế biến từ nguyên liệu tươi ngon theo mùa của địa phương<br>Bắt đầu với những món khai vị được trình bày đẹp mắt, bữa ăn bao gồm nhiều món ăn được chế biến từ các nguyên liệu theo mùa được lựa chọn kỹ lưỡng, bao gồm các món đặc sản vùng núi, đặc sản vùng sông và thịt bò Joshu.</p><p>Các bữa ăn sẽ được phục vụ trong 18 phòng ăn riêng tư quyến rũ của chúng tôi.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"y-tuong2\"][/simple-slider]</shortcode><p>Thiết kế tỉ mỉ<br>Để thể hiện tinh túy của một khu nghỉ dưỡng Nhật Bản, chúng tôi cam kết cả về thiết kế và dịch vụ. Các kỹ thuật và vật liệu kiến ​​trúc truyền thống Nhật Bản được kết hợp xuyên suốt công trình. Sự kết hợp giữa kiến ​​trúc hiện đại, như hành lang cong cao khoảng 8 mét, với các kỹ thuật truyền thống như vách ngăn shoji kumiko và đèn chiếu sáng được trang trí bằng giấy washi in mica, cho phép bạn tận hưởng một trải nghiệm phi thường.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"y-tuong3\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'y-tuong/concept01-pic01.jpg', 1, NULL, '2026-04-06 02:12:29', '2026-04-06 19:38:23'),
(10, 'Relais &amp; Châteaux là gì?', '', '<p>Relais &amp; Châteaux là một hiệp hội được thành lập năm 1954, bao gồm khoảng 540 khách sạn sang trọng và nhà hàng hàng đầu trên toàn thế giới, tất cả đều thuộc sở hữu tư nhân hoặc do gia đình chủ khách sạn và đầu bếp điều hành.</p><p>Việc gia nhập hiệp hội đòi hỏi một quy trình sàng lọc nghiêm ngặt, và hiệp hội được biết đến như một biểu tượng của lòng hiếu khách cao cấp.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"y-tuong3\"][/simple-slider]</shortcode><p>Từ những vườn nho ở thung lũng Napa đến vùng Provence của Pháp, vô số bãi biển tuyệt đẹp trải dọc Ấn Độ Dương, và những nhà nghỉ suối nước nóng truyền thống của Nhật Bản, các thành viên của Relais &amp; Châteaux chào đón bạn đến với nhiều quốc gia và khu vực trên thế giới, mời bạn trải nghiệm lối sống và điểm tham quan tuyệt vời bắt nguồn từ văn hóa và môi trường địa phương.</p><p>Tại Nhật Bản, có 20 khách sạn và nhà hàng, bao gồm cả khu nghỉ dưỡng Senjuan, được đăng ký.</p><p>Để biết thêm thông tin, vui lòng xem bên dưới.</p><p>Được thành lập vào năm 1954, Relais &amp; Châteaux là một tổ chức phi lợi nhuận bao gồm 580 khách sạn và nhà hàng được lựa chọn kỹ lưỡng trên toàn thế giới.</p><p>Được hỗ trợ bởi các chủ khách sạn và đầu bếp độc lập, những người cùng chia sẻ niềm tin mạnh mẽ vào việc chung sống hài hòa với cộng đồng địa phương, bảo tồn sự phong phú và đa dạng của văn hóa ẩm thực, và vun đắp những mối quan hệ chân thành với khách hàng, Relais &amp; Châteaux có mặt khắp nơi trên thế giới, từ những vườn nho ở thung lũng Napa đến vùng Provence của Pháp, vô số bãi biển tuyệt đẹp trải dọc Ấn Độ Dương, và thậm chí cả những nhà nghỉ suối nước nóng truyền thống của Nhật Bản.</p><p>Chính những trải nghiệm độc đáo cho phép khách hàng cảm nhận được văn hóa và lịch sử đặc sắc của mỗi nơi, và những kỷ niệm chỉ có thể được tạo ra ở đó, đã thu hút mọi người.</p><p>Các thành viên của Relais &amp; Châteaux cam kết bảo tồn và nuôi dưỡng sự phong phú và đa dạng của văn hóa ẩm thực và truyền thống hiếu khách mà thế giới tự hào.</p><p>Năm 2014, UNESCO đã tuyên bố tầm nhìn của 20 Relais &amp; Châteaux là tích cực tham gia vào việc bảo vệ lịch sử địa phương và môi trường.</p><p>Relais &amp; Châteaux, được thành lập năm 1954, là một hiệp hội gồm 580 khách sạn và nhà hàng độc đáo trên toàn thế giới, thuộc sở hữu và điều hành bởi các doanh nhân độc lập – thường là các gia đình – những người đam mê nghề nghiệp của mình và cam kết sâu sắc trong việc xây dựng mối quan hệ ấm áp, bền lâu với khách hàng.<br>Có mặt trên năm châu lục, từ những vườn nho ở Thung lũng Napa đến Provence và những bãi biển của Ấn Độ Dương, Relais &amp; Châteaux mời mọi người trên toàn cầu thưởng thức những hành trình ẩm thực tuyệt vời, khám phá nghệ thuật sống độc đáo được khắc sâu trong mỗi nền văn hóa địa phương và chia sẻ một trải nghiệm vô song, khó quên.</p><p>Các thành viên của Relais &amp; Châteaux bảo vệ và quảng bá sự giàu có và đa dạng của các truyền thống ẩm thực và khách sạn trên thế giới, để đảm bảo chúng tiếp tục phát triển mạnh mẽ. Họ cũng tận tâm bảo tồn di sản địa phương và môi trường, như đã được nêu trong Tầm nhìn của hiệp hội trình bày trước UNESCO vào tháng 11 năm 2014.</p>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'y-tuong/concept04-slider02.jpg', 0, NULL, '2026-04-06 02:20:57', '2026-04-06 19:41:35'),
(11, 'Nhà trọ chị em: Ryokan Tanigawa', '', '<p>Nhà nghỉ chị em: Ryokan Tanigawa</p><p>Một \"Ngôi nhà thứ hai\" cho khách của chúng tôi<br>Lòng hiếu khách tận tâm, một quê hương tinh thần<br>Ryokan Tanigawa mong muốn trở thành \"ngôi nhà thứ hai\" cho khách của chúng tôi. Khi đón tiếp khách, chúng tôi luôn làm điều đó với cùng một tình cảm như đón tiếp một thành viên gia đình mà chúng ta đã lâu không gặp.</p><figure class=\"image\"><img style=\"aspect-ratio:728/483;\" src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/concept/concept05_pic01.jpg\" alt=\"姉妹館 旅館たにがわ\" width=\"728\" height=\"483\"></figure><p>Một nhà nghỉ suối nước nóng thư giãn, nơi bạn có thể tận hưởng phong cảnh theo mùa của Tanigawadake và hòa mình vào thiên nhiên.Ryokan Tanigawa tọa lạc tại một khu nghỉ dưỡng suối nước nóng yên tĩnh dưới chân sườn phía nam của núi Tanigawa.<br>Như khẩu hiệu \"Núi Tanigawa dường như trong tầm tay\" đã gợi ý, núi Tanigawa, nhìn từ khu vực Tanigawa, mang một vẻ đẹp khác biệt trong mỗi mùa: tuyết còn vương vấn và hoa anh đào, cây xanh tươi mát và những cơn gió mát, lá mùa thu rực rỡ và một khung cảnh rộng lớn, bạc lấp lánh. Nằm trong Vườn quốc gia Joshin\'etsu Kogen, tòa nhà hiện đại hòa quyện hoàn hảo vào khu vực Tanigawa Onsen yên bình, một khung cảnh gợi lên cảm xúc của nhiều khách đến đây.</p><p><img src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/concept/concept05_shizen01.jpg\" alt=\"谷川岳の四季折々の景観を満喫できる心安らぐ温泉宿\" width=\"303\" height=\"195\"><img src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/concept/concept05_shizen02.jpg\" alt=\"谷川岳の四季折々の景観を満喫できる心安らぐ温泉宿\" width=\"303\" height=\"195\"></p><p>Hãy thưởng thức hương vị theo mùa của Joshu tại bốn quán trà khác nhau, mỗi nơi đều mang đến một trải nghiệm ẩm thực độc đáo.</p><p>Với phương châm \"sức khỏe và sự ngon miệng\", các đầu bếp và nhân viên của chúng tôi làm việc chăm chỉ mỗi ngày để đảm bảo bạn có thể tận hưởng trọn vẹn hương vị theo mùa mà Tanigawa đã vun trồng.</p><p><img src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/concept/concept05_shoku01.jpg\" alt=\"それぞれ異なる4つの茶屋で、上州の旬の味覚に舌鼓\" width=\"303\" height=\"195\"><img src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/concept/concept05_shoku02.jpg\" alt=\"それぞれ異なる4つの茶屋で、上州の旬の味覚に舌鼓\" width=\"303\" height=\"195\"></p><p>Hãy tận hưởng nguồn nước nóng dồi dào và những lợi ích tuyệt vời mà suối nước nóng mang lại với hơn 20 tác dụng khác nhau cho sức khỏe.</p><p>Suối nước nóng Tanigawa Onsen đã liên tục chảy trong hàng trăm năm kể từ khi nó phun trào lần đầu tiên ở khu vực này vào thời Edo. Nước trong vắt, có lưu lượng lớn, sạch và chất lượng cao vì đến từ nguồn tư nhân. Suối nước nóng này cũng có hơn 20 đặc tính trị liệu và có thể được sử dụng như một liệu pháp tắm trị liệu.</p><p><img src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/concept/concept05_onsen01.jpg\" alt=\"豊富な湯量と20種類以上の効能をもつ滋養溢れる温泉\" width=\"303\" height=\"185\"><img src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/concept/concept05_onsen02.jpg\" alt=\"豊富な湯量と20種類以上の効能をもつ滋養溢れる温泉\" width=\"303\" height=\"185\"></p><p>&nbsp;</p>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'y-tuong/concept05-onsen03.jpg', 0, NULL, '2026-04-06 02:28:09', '2026-04-06 02:28:09'),
(12, 'Phòng đặc biệt với phòng tắm ngoài trời (SP)', '', '<p>Được bao bọc bởi vẻ đẹp thiên nhiên hùng vĩ của Tanigawa quanh năm,<br>Tất cả các phòng đều có bồn tắm ngoài trời riêng với dòng nước suối nóng chảy tự do và tầm nhìn ra núi Tanigawa.</p><p>Tất cả các phòng tại nhà nghỉ của chúng tôi đều có bồn tắm ngoài trời riêng, cho phép bạn tận hưởng suối nước nóng thỏa thích trong không gian riêng tư.</p><p>Đây là một trong những hình mẫu tiêu biểu của một \"khu nghỉ dưỡng Nhật Bản\".</p><p>Tất cả các phòng đều được trang bị bồn tắm ngoài trời riêng với dòng nước suối nóng chảy tự do, và bạn có thể tận hưởng tầm nhìn toàn cảnh núi Tanigawa từ cả phòng và bồn tắm ngoài trời.</p><p>Trong một tòa nhà rộng 1000 tsubo (khoảng 3300 mét vuông), chỉ có 18 phòng, cho phép bạn thư giãn trong không gian riêng tư, nơi bạn có thể dành thời gian yên tĩnh và thanh bình trong bồn tắm ngoài trời riêng của mình, mà bạn có thể sử dụng bất cứ lúc nào và bao nhiêu lần tùy thích,<br>và trong một căn phòng với nội thất rộng rãi và được thiết kế chu đáo.</p><p>Được bao bọc bởi vẻ đẹp thiên nhiên hùng vĩ của Tanigawa, nơi thay đổi diện mạo theo từng mùa, hãy tận hưởng khoảng thời gian thư giãn và phục hồi sức khỏe tuyệt vời.</p><p>Phòng Đặc Biệt SP với Bồn Tắm Ngoài Trời<br>Không gian nội thất rộng rãi, được thiết kế tỉ mỉ đến từng chi tiết, cùng với bồn tắm ngoài trời kích thước lớn tạo nên cảm giác riêng tư sang trọng. [Bố cục]<br>Phòng kiểu Nhật 12,5 chiếu tatami + phòng kiểu Nhật 8 chiếu tatami + phòng trà + hiên rộng +<br>Bồn tắm ngoài trời với dòng nước suối nóng chảy tự do<br>Có 8 bậc thang dẫn lên phòng.</p><p>&nbsp;</p><p>&nbsp;</p><shortcode>[simple-slider key=\"phong1\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'room/c03a2004-1040x600.jpg', 0, NULL, '2026-04-06 02:32:37', '2026-04-06 19:43:40'),
(13, 'Phòng S kiểu Nhật với bồn tắm ngoài trời', '', '<p>Phòng kiểu Nhật với bồn tắm ngoài trời (cỡ S)<br>Đây là phòng bán đặc biệt với phòng ngủ kiểu Nhật rộng rãi, phòng liền kề và bồn tắm ngoài trời riêng. [Bố cục]<br>Phòng ngủ kiểu Nhật 12,5 chiếu tatami + phòng liền kề 8 chiếu tatami + hiên rộng +<br>Bồn tắm ngoài trời riêng với nước suối nóng chảy tự do<br>Có 8 bậc thang dẫn lên phòng.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"phong2\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'room/58ed1a1cdf57d4a7a2943e3334f5c030-1040x600.jpg', 0, NULL, '2026-04-06 02:35:43', '2026-04-06 19:44:37'),
(14, 'Phòng A theo phong cách Nhật Bản với bồn tắm ngoài trời, phòng xông hơi và sân hiên.', '', '<p>Phòng kiểu Nhật A với bồn tắm ngoài trời, phòng xông hơi và sân hiên<br>Phòng kiểu Nhật này rộng rãi, bao gồm cả phòng liền kề, và là một phòng được ưa chuộng với sân hiên lớn, nơi bạn có thể tận hưởng toàn cảnh núi Tanigawa và phòng xông hơi cho một người. Đây là nơi bạn có thể tận hưởng kỳ nghỉ dưỡng tuyệt vời nhất trong khi ngắm nhìn núi Tanigawa và lắng nghe tiếng suối trong vắt của Tanigawa, với bồn tắm ngoài trời và phòng xông hơi riêng tư. [Bố cục]<br>Phòng kiểu Nhật 12,5 chiếu tatami + phòng liền kề 4,5 chiếu tatami + hiên rộng + sân hiên +<br>Phòng xông hơi (cho 1 người) + bồn tắm ngoài trời riêng tư với nước suối nóng chảy tự do<br>Có 8 bậc thang dẫn lên phòng.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"phong3\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'room/58ed1a1cdf57d4a7a2943e3334f5c030-1040x600-1.jpg', 1, NULL, '2026-04-06 02:40:56', '2026-04-06 19:45:37'),
(15, 'Phòng B kiểu Nhật với bồn tắm ngoài trời và sân hiên.', '', '<p>Phòng kiểu Nhật B với bồn tắm ngoài trời và sân hiên<br>Phòng phổ biến này có phòng kiểu Nhật rộng 12,5 chiếu tatami và bồn tắm ngoài trời riêng, cùng với sân hiên nơi bạn có thể tận hưởng dòng suối trong vắt của Tanigawa ngay trước mặt. Bạn có thể thư giãn ở một vị trí tuyệt vời trong khi được ru ngủ bởi tiếng rì rầm nhẹ nhàng của dòng suối. [Bố cục]<br>Phòng kiểu Nhật 12,5 chiếu tatami + hiên rộng + sân hiên +<br>Bồn tắm ngoài trời riêng với nước suối nóng chảy tự do<br>Có 8 bậc thang dẫn lên phòng.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"phong4\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'room/f6f77a1616e27fc34eb1a81aa7dc6262.jpg', 0, NULL, '2026-04-06 02:43:47', '2026-04-06 19:46:45'),
(16, 'Phòng theo phong cách Nhật Bản - phương Tây với bồn tắm ngoài trời.', '', '<p>Phòng kiểu Nhật - phương Tây với bồn tắm ngoài trời<br>Phòng này có một phòng kiểu Nhật và một phòng ngủ đôi rộng rãi, cùng với một bồn tắm ngoài trời. Tận hưởng thiên nhiên trong lành từ những cửa sổ lớn và bồn tắm ngoài trời. [Bố cục]<br>Phòng kiểu phương Tây (40 m²) + Phòng kiểu Nhật (8 chiếu tatami) +<br>Bồn tắm ngoài trời với nước suối nóng chảy tự do trong phòng.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"phong5\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'room/dsc09947-1040x600.jpg', 1, NULL, '2026-04-06 02:46:23', '2026-04-06 19:47:43'),
(17, 'bữa tối', '', '<figure class=\"image\"><img style=\"aspect-ratio:640/427;\" src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/cuisine/cuisine11_1.JPG\" width=\"640\" height=\"427\"></figure><p style=\"text-align:center;\">Ví dụ về món khai vị</p><figure class=\"image\"><img style=\"aspect-ratio:640/427;\" src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/cuisine/cuisine11_2.JPG\" width=\"640\" height=\"427\"></figure><p style=\"text-align:center;\">Ví dụ về sashimi</p><figure class=\"image\"><img style=\"aspect-ratio:640/427;\" src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/cuisine/cuisine11_3.JPG\" width=\"640\" height=\"427\"></figure><p style=\"text-align:center;\">Ví dụ về một cái bát</p><figure class=\"image\"><img style=\"aspect-ratio:640/427;\" src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/cuisine/cuisine11_4.JPG\" width=\"640\" height=\"427\"></figure><p style=\"text-align:center;\">Ví dụ về món hầm</p>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'do-an/cuisine11-4.jpeg', 0, NULL, '2026-04-06 02:53:06', '2026-04-06 02:53:06'),
(18, 'bữa sáng', '', '<shortcode>[simple-slider key=\"bua-sang\"][/simple-slider]</shortcode><p>Bữa sáng cũng có nhiều nguyên liệu theo mùa, có nguồn gốc địa phương, nhấn mạnh hương vị tự nhiên của nguyên liệu. Các món ăn giàu rau tươi rất tốt cho sức khỏe và giúp bạn tràn đầy năng lượng.</p>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'do-an/yosyoku.jpg', 0, NULL, '2026-04-06 02:57:21', '2026-04-06 19:51:54'),
(19, 'Nhà hàng', '', '<p>Đây là một ví dụ về khu vực ăn uống của chúng tôi.</p><p>Thưởng thức những món ăn ngon theo ý thích của bạn trong một không gian riêng tư được thiết kế tinh tế. Trần nhà cao và cảm giác rộng rãi</p><p>Một phòng riêng với trần nhà cao và cảm giác rộng rãi, có bàn ăn âm sàn và ghế sofa thoải mái.</p><figure class=\"image\"><img style=\"aspect-ratio:1040/600;\" src=\"https://www.senjyuan.jp/wp/wp-content/themes/senjyuan/lib/images/cuisine/cuisine05_pic01.jpg\" alt=\"お食事処 彩華\" width=\"1040\" height=\"600\"></figure>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'do-an/cuisine05-pic01.jpg', 0, NULL, '2026-04-06 03:00:47', '2026-04-06 03:00:47'),
(20, 'Suzumushi no Yu (Suối nước nóng cricket)', '', '<p>Trải nghiệm thư giãn tuyệt đỉnh<br>Tận hưởng thời gian sang trọng<br>Nằm ở phía tây khu suối nước nóng Minakami, suối nước nóng Tanigawa đã chảy liên tục từ thời Edo,<br>và từ lâu đã được người dân vùng có tuyết rơi nhiều này trân trọng.</p><p>Nước suối nóng tại Senjuan là một loại nước suối dịu nhẹ, nhược trương, có tính kiềm yếu. Hãy tận hưởng không khí trong lành giữa dòng suối trong vắt và cây xanh của Tanigawa trong bồn tắm ngoài trời của chúng tôi, hương thơm của cây bách trong bồn tắm trong nhà, và bồn tắm đi bộ nơi bạn có thể thư giãn và trò chuyện.</p><p>Trên hết, bạn có thể tận hưởng một khoảng thời gian sang trọng và thoải mái.</p><p>&nbsp;</p><p>&nbsp;</p><shortcode>[simple-slider key=\"songhoi1\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'suoi-nuoc-nong/c03a0160-968x620.jpg', 0, NULL, '2026-04-06 03:07:01', '2026-04-06 19:52:41'),
(21, 'Nhà tắm công cộng lớn Ichinokura', '', '<p>Phòng xông hơi khô với tường làm bằng than Binchotan, mang lại hiệu quả cách nhiệt vượt trội.</p><p>Bạn có thể lựa chọn nhiệt độ ưa thích, từ 70°C ở tầng dưới đến 90°C ở tầng trên.</p><p>Ngoài ra còn có khu vực thư giãn cạnh cửa sổ, nơi bạn có thể thư giãn và ngắm nhìn khung cảnh xanh tươi bên ngoài.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"songhoi2\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'suoi-nuoc-nong/00.jpg', 0, NULL, '2026-04-06 03:09:54', '2026-04-06 19:53:29'),
(22, 'Nhà tắm ngoài trời Hotaru no Yu', '', '<p>Hãy tận hưởng cảm giác tự do phóng khoáng của bồn tắm ngoài trời nhìn ra thung lũng Tanigawa. Thư giãn trong bồn tắm và cảm nhận làn gió dễ chịu thổi qua thung lũng.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"songhoi3\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'suoi-nuoc-nong/c03a2083-968x620.jpg', 0, NULL, '2026-04-06 03:12:51', '2026-04-06 19:54:12'),
(23, 'Nhà tắm công cộng lớn, Sen no Kura', '', '<p>Chúng tôi cũng có phòng xông hơi sương ở nhiệt độ thấp, rất dịu nhẹ cho da và đặc biệt được khuyên dùng cho phụ nữ.</p><p>&nbsp;</p><p>&nbsp;</p><shortcode>[simple-slider key=\"songhoi4\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'suoi-nuoc-nong/c03a2069-464x297.jpg', 2, NULL, '2026-04-06 03:16:17', '2026-04-06 19:56:36'),
(24, 'bồn tắm đi bộ chỉ dùng vào mùa hè', '', '<p>Bên cạnh phòng spa là bồn tắm đứng với dòng suối chảy phía trước, cho phép bạn thư giãn trong khi tận hưởng không khí trong lành của rừng cây. Nhiệt độ nước dễ chịu từ 38 đến 41 độ C sẽ giúp bạn xua tan mệt mỏi.</p><shortcode>[simple-slider key=\"songhoi4\"][/simple-slider]</shortcode>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'suoi-nuoc-nong/onsen-spa02-pic01.jpg', 0, NULL, '2026-04-06 03:18:40', '2026-04-06 19:57:40'),
(25, 'SPA', '', '<p>Hãy thư giãn cơ thể và thả lỏng hơi thở trong không gian SPA toàn diện đích thực này.<br>Hướng đến sự thư giãn toàn thân.</p><p>Ánh sáng, âm thanh và hương thơm phong phú của thiên nhiên Tanigawa,<br>hồi sinh sự thoải mái của năm giác quan,<br>và nuôi dưỡng sự hài hòa giữa thiên nhiên, thể xác và tâm trí…</p><p>Năng lượng của nước và thực vật hoang dã Tanigawa<br>Cây cối và hoa của núi Tanigawa<br>Các yếu tố của thiên nhiên</p><p>Dựa trên các nguyên tắc Âm Dương và Ngũ Hành, chúng tôi đã kết hợp thiên nhiên Tanigawa với các kỹ thuật cổ truyền Nhật Bản.</p><p>Hãy thả mình vào thiên nhiên, sử dụng các kỹ thuật cổ truyền Nhật Bản, hít thở sâu và trải nghiệm sự bình an nội tâm.</p><p>&nbsp;</p><shortcode>[simple-slider key=\"spa\"][/simple-slider]</shortcode><p>Liệu pháp tự nhiên<br>Các kỹ thuật kéo giãn, xoa bóp và nén trực tiếp làm giảm căng cơ, và một loại gel tự nhiên đặc biệt được làm từ nước suối và thảo dược được sử dụng để cải thiện tuần hoàn máu.</p><p>Liệu trình 60 phút / 19.800 yên (đã bao gồm thuế)</p><p>Liệu trình 90 phút / 29.700 yên (đã bao gồm thuế)</p><p>*Liệu trình sẽ được điều chỉnh phù hợp với tình trạng sức khỏe của bạn dựa trên buổi tư vấn.</p><p>Chương trình buổi tối đặc biệt<br>Liệu pháp ngủ sâu<br>Xoa bóp nhẹ nhàng lưng, đầu, cổ và vùng ngực, thúc đẩy sự thư giãn sâu và giấc ngủ ngon.</p><p>Những liệu pháp tự nhiên nhẹ nhàng xoa dịu tâm trí và cơ thể mệt mỏi của bạn.</p><p>Liệu trình 30 phút / 15.400 yên (đã bao gồm thuế)</p><p>Liệu trình 60 phút / 22.000 yên (đã bao gồm thuế)</p><p>Liệu trình 90 phút / 33.000 yên (đã bao gồm thuế)</p><p>*Liệu trình sẽ được điều chỉnh phù hợp với tình trạng sức khỏe của bạn dựa trên buổi tư vấn.</p><p>Vui lòng liên hệ hoặc hỏi thêm thông tin chi tiết khi đặt chỗ.</p>', 'published', 1, 'Botble\\ACL\\Models\\User', 0, 'suoi-nuoc-nong/intro-main.jpg', 1, NULL, '2026-04-06 03:25:27', '2026-04-06 19:58:34');
INSERT INTO `posts_translations` (`lang_code`, `posts_id`, `name`, `description`, `content`) VALUES
('en_US', 1, 'Each of our 8 double rooms has its own distinct.', 'Discover a world of unique comfort in our collection of 8 double rooms, each boasting its own distinct charm and character. Immerse yourself in a stay that caters to your individual preferences', '<p>At Riorelax, we believe in crafting memories that last a lifetime. Our blog series will unveil the array of experiences we offer, tailored to every kind of traveler. Whether you seek adventure, relaxation, romance, or exploration, our personalized activities and excursions ensure that your stay transcends the ordinary. Join us as we share stories of guests who\'ve embraced the luxury of choice and embarked on journeys that become cherished tales, all within the embrace of our extraordinary hotel.</p><p>Unlock the Gateway to Opulent Tranquility: Introducing Riorelax Embark on a journey to unparalleled luxury and coastal elegance. Nestled along the Adriatic\'s pristine shoreline, Riorelax stands as a beacon of refined indulgence. Join us as we delve into the enchanting world of bespoke experiences, exquisite accommodations, and personalized service that defines our exceptional hotel. From captivating sea-view rooms to tantalizing gastronomic delights, spa sanctuaries, and curated adventures, our blog takes you behind the scenes of a retreat where every moment is a masterpiece. Uncover the essence of opulence, where your desires are our command and the Adriatic becomes your playground. Stay tuned for a symphony of elegance, artistry, and inspiration in our upcoming series.</p><p>By Rosalina Pong</p><p>Viral dreamcatcher keytar typewriter, aest hetic offal umami. Aesthetic polaroid pug pitchfork post-ironic.</p><p>Step into a realm where luxury is not just a word, but a way of life. Riorelax invites you to explore a world where opulence meets comfort in seamless harmony. Our blog series will unveil the heart and soul of our hotel, from the intricacies of our meticulous design to the intuitive service that anticipates your every need. Join us on a virtual tour that captures the essence of sophistication, a prelude to the unforgettable experience that awaits you at our shores.</p><p>&nbsp;</p><p>Prepare to tantalize your taste buds as we delve into the culinary symphony orchestrated by our skilled chefs. From gourmet creations that blend local flavors with international finesse to the art of crafting the perfect cocktail, our blog will be your guide to the exceptional dining journey that awaits. Join us in savoring the stories behind each dish, the dedication that goes into every creation, and the joy of experiencing food as an art form within our culinary haven.</p><p>&nbsp;</p><p>At Riorelax, we believe in crafting memories that last a lifetime. Our blog series will unveil the array of experiences we offer, tailored to every kind of traveler. Whether you seek adventure, relaxation, romance, or exploration, our personalized activities and excursions ensure that your stay transcends the ordinary. Join us as we share stories of guests who\'ve embraced the luxury of choice and embarked on journeys that become cherished tales, all within the embrace of our extraordinary hotel.</p>'),
