INSERT INTO `revisions` (`id`, `revisionable_type`, `revisionable_id`, `user_id`, `key`, `old_value`, `new_value`, `created_at`, `updated_at`) VALUES
(1, 'Botble\\Blog\\Models\\Post', 1, 1, 'name', 'Each of our 8 double rooms has its own distinct.', 'Mỗi phòng đôi trong số 8 phòng của chúng tôi đều có nét đặc trưng riêng.', '2026-03-12 01:13:23', '2026-03-12 01:13:23'),
(2, 'Botble\\Blog\\Models\\Post', 1, 1, 'description', 'Discover a world of unique comfort in our collection of 8 double rooms, each boasting its own distinct charm and character. Immerse yourself in a stay that caters to your individual preferences', 'Khám phá không gian nghỉ dưỡng đầy thoải mái và độc đáo với bộ sưu tập 8 phòng đôi của chúng tôi, mỗi phòng đều mang nét quyến rũ và cá tính riêng biệt. Hãy tận hưởng một kỳ nghỉ được thiết kế để phù hợp với sở thích và nhu cầu riêng của bạn, mang đến trải nghiệm lưu trú thoải mái và đáng nhớ.', '2026-03-12 01:13:23', '2026-03-12 01:13:23'),
(3, 'Botble\\Blog\\Models\\Post', 2, 1, 'name', 'Essential Qualities of Highly Successful Music', 'Những yếu tố cốt lõi của âm nhạc thành công', '2026-03-12 01:14:42', '2026-03-12 01:14:42'),
(4, 'Botble\\Blog\\Models\\Post', 2, 1, 'description', 'Delve into the secrets behind the music that resonates deeply with audiences worldwide. Uncover the essential qualities that elevate music from ordinary to extraordinary, as we explore.', 'Khám phá những bí mật đằng sau các bản nhạc chạm đến trái tim khán giả trên toàn thế giới. Tìm hiểu những yếu tố cốt lõi giúp âm nhạc vươn lên từ bình thường trở nên phi thường, khi chúng ta cùng khám phá những giá trị làm nên sức hút đặc biệt của âm nhạc.', '2026-03-12 01:14:42', '2026-03-12 01:14:42'),
(5, 'Botble\\Blog\\Models\\Post', 3, 1, 'name', '9 Things I Love About Shaving My Head', '9 điều tôi thích khi cạo đầu', '2026-03-12 01:19:46', '2026-03-12 01:19:46'),
(6, 'Botble\\Blog\\Models\\Post', 3, 1, 'description', 'Embark on a personal journey of self-discovery and empowerment as we delve into the unique experience of embracing a bald look. From newfound confidence to a simplified routine, explore the 9 things', 'Hãy bắt đầu hành trình cá nhân khám phá bản thân và sự tự tin khi chúng ta cùng tìm hiểu trải nghiệm độc đáo của việc để đầu trọc. Từ sự tự tin mới mẻ đến thói quen chăm sóc đơn giản hơn, hãy cùng khám phá 9 điều thú vị mà phong cách này mang lại', '2026-03-12 01:19:46', '2026-03-12 01:19:46'),
(7, 'Botble\\Blog\\Models\\Post', 4, 1, 'name', 'Why Teamwork Really Makes The Dream Work', 'Vì sao làm việc nhóm thực sự giúp biến ước mơ thành hiện thực', '2026-03-12 01:20:31', '2026-03-12 01:20:31'),
(8, 'Botble\\Blog\\Models\\Post', 4, 1, 'description', 'Unlock the power of collaboration and synergy in achieving your goals. In this exploration of the importance of teamwork, we delve into real-world examples and insights and how combining diverse skills.', 'Khám phá sức mạnh của sự hợp tác và tinh thần đồng đội trong việc đạt được mục tiêu của bạn. Trong bài viết về tầm quan trọng của làm việc nhóm, chúng ta sẽ tìm hiểu những ví dụ thực tế và những góc nhìn giá trị, cũng như cách kết hợp các kỹ năng đa dạng có thể tạo nên những kết quả vượt trội.', '2026-03-12 01:20:31', '2026-03-12 01:20:31'),
(9, 'Botble\\Blog\\Models\\Post', 6, 1, 'name', 'The litigants on the screen are not actors', 'Những người kiện tụng trên màn hình không phải là diễn viên.', '2026-03-12 01:38:29', '2026-03-12 01:38:29'),
(10, 'Botble\\Blog\\Models\\Post', 6, 1, 'description', 'Take a behind-the-scenes look at the reality of courtroom dramas. Contrary to common assumptions, the litigants you see on the screen are not mere actors, but real people with compelling stories.', 'Hãy cùng khám phá hậu trường của những bộ phim/chương trình về phòng xử án. Trái với suy nghĩ phổ biến của nhiều người, những người tham gia kiện tụng mà bạn thấy trên màn hình không chỉ là diễn viên, mà là những con người thật với những câu chuyện đầy kịch tính và chân thực.', '2026-03-12 01:38:29', '2026-03-12 01:38:29'),
(11, 'Botble\\Blog\\Models\\Post', 5, 1, 'name', 'The World Caters to Average People', 'Thế giới được thiết kế để phục vụ những người bình thường', '2026-03-12 01:39:18', '2026-03-12 01:39:18'),
(12, 'Botble\\Blog\\Models\\Post', 5, 1, 'description', 'Unveil the hidden truths behind success in a world that often values conformity. In a thought-provoking analysis, we examine why societal norms tend to cater to the average and breaking boundaries.', 'Khám phá những sự thật ẩn sau thành công trong một thế giới thường đề cao sự giống nhau và tuân theo chuẩn mực chung. Trong bài phân tích đầy suy ngẫm này, chúng ta sẽ tìm hiểu vì sao các chuẩn mực xã hội thường hướng đến số đông, cũng như cách vượt qua những giới hạn đó để tạo nên sự khác biệt.', '2026-03-12 01:39:18', '2026-03-12 01:39:18'),
