(27, 'Botble\\Blog\\Models\\Post', 7, 1, 'description', '', 'Cloud Pool là hồ bơi vô cực nằm giữa khung cảnh núi rừng hùng vĩ, nơi du khách có thể thư giãn trong làn nước mát và chiêm ngưỡng vẻ đẹp thiên nhiên từ trên cao.', '2026-03-15 20:04:37', '2026-03-15 20:04:37'),
(28, 'Botble\\Blog\\Models\\Post', 7, 1, 'description', 'Cloud Pool là hồ bơi vô cực nằm giữa khung cảnh núi rừng hùng vĩ, nơi du khách có thể thư giãn trong làn nước mát và chiêm ngưỡng vẻ đẹp thiên nhiên từ trên cao.', 'Cloud Pool là hồ bơi vô cực nằm giữa khung cảnh núi rừng và thung lũng xanh mát, nơi du khách có thể hòa mình vào làn nước trong lành, tận hưởng không khí thiên nhiên và chiêm ngưỡng những khoảnh khắc bình yên giữa đất trời.', '2026-03-15 20:05:47', '2026-03-15 20:05:47'),
(29, 'Botble\\Blog\\Models\\Post', 8, 1, 'description', '', 'Orchid Spa là không gian chăm sóc sức khỏe và thư giãn giữa thiên nhiên yên bình, nơi du khách có thể trải nghiệm các liệu trình trị liệu giúp phục hồi năng lượng và cân bằng cơ thể sau những ngày bận rộn.', '2026-03-15 20:07:11', '2026-03-15 20:07:11'),
