INSERT INTO `testimonials` (`id`, `name`, `content`, `image`, `company`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Nguyễn Minh Anh', '<p>Tôi thực sự rất hài lòng với kỳ nghỉ tại đây. Khách sạn sạch sẽ, phòng ốc được chuẩn bị rất chu đáo và nhân viên luôn nhiệt tình hỗ trợ. Vị trí cũng rất thuận tiện để di chuyển và tham quan các địa điểm xung quanh.</p>', 'testimonials/viet-hoangpng.jpg', 'CEO Of Microsoft', 'published', '2025-06-10 10:38:15', '2026-03-12 20:21:03'),
(2, 'Trần Quốc Bảo', '<p>Trải nghiệm lưu trú của tôi rất tuyệt vời. Phòng rộng rãi, tiện nghi đầy đủ và không gian rất yên tĩnh. Nhân viên phục vụ chuyên nghiệp và thân thiện khiến tôi cảm thấy rất thoải mái trong suốt thời gian ở đây.</p>', 'testimonials/anh-chup-man-hinh-2020-04-15-luc-165401.png', 'CEO Of Apple', 'published', '2025-06-10 10:38:15', '2026-03-12 20:21:50'),
(3, 'Phạm Thu Trang', '<p>Một nơi nghỉ dưỡng rất đáng trải nghiệm. Không gian thoải mái, dịch vụ tốt và nhân viên luôn sẵn sàng hỗ trợ khi cần. Tôi đã có một kỳ nghỉ thật thư giãn và dễ chịu tại đây.</p>', 'testimonials/hinh-anh-nguoi-phu-nu-viet-nam-trong-ta-ao-dai-192.webp', 'Pio Founder', 'published', '2025-06-10 10:38:15', '2026-03-12 20:22:36'),
(4, 'Vũ Khánh Linh', '<p>Khách sạn mang lại cảm giác rất thoải mái và tiện nghi. Phòng đẹp, sạch sẽ và được trang bị đầy đủ. Ngoài ra, vị trí cũng rất thuận tiện để đi tham quan và khám phá thành phố.</p>', 'testimonials/free-photo-of-co-gai-tr-m-c-ao-dai-truy-n-th-ng-vi.jpg', 'VP Of Google', 'published', '2025-06-10 10:38:15', '2026-03-12 20:25:53'),
(5, 'Hoàng Ngọc Mai', '<p>Không gian khách sạn rất sang trọng nhưng vẫn tạo cảm giác ấm cúng. Mọi thứ từ phòng nghỉ đến dịch vụ đều được chuẩn bị rất tốt. Tôi thực sự cảm thấy hài lòng với trải nghiệm này.</p>', 'testimonials/3656093-3655919-nguoi-dep-va-xe-may-9796.jpg', 'Founder Of SpaceX', 'published', '2025-06-10 10:38:15', '2026-03-12 20:26:35'),
(6, 'Đỗ Đức Anh', '<p>Phòng rất sạch sẽ, giường ngủ thoải mái và dịch vụ dọn phòng luôn được thực hiện đúng giờ. Nhân viên rất nhiệt tình và luôn sẵn sàng hỗ trợ khi cần thiết.</p>', 'testimonials/chc3a2n-dung-nam-doanh-nhc3a2n-chc3a2u-c3a.jpg', 'Fashion Designer', 'published', '2025-06-10 10:38:15', '2026-03-12 20:27:08');
